function envValue(key) {
  if (key === "META_CLIENT_ID") return process.env.META_CLIENT_ID || process.env.META_APP_ID || "";
  if (key === "META_CLIENT_SECRET") return process.env.META_CLIENT_SECRET || process.env.META_APP_SECRET || "";
  return process.env[key] || "";
}

function validLookingCredential(key, value) {
  if (!value) return false;
  if (key.endsWith("_REDIRECT_URI")) return /^https?:\/\/.+\/api\/(?:oauth\/[^/]+|linkedin|x|meta)\/callback/i.test(value);
  if (key === "SUPABASE_URL") return /^https:\/\/.+\.supabase\.co$/i.test(value);
  if (key.startsWith("ENABLE_LIVE_") || key.endsWith("_LIVE_POSTING_ENABLED") || key === "LINKEDIN_OWNER_ONLY" || key === "USE_SUPABASE_JS_STORE") return ["true", "false"].includes(String(value).toLowerCase());
  if (key === "OAUTH_TOKEN_ENCRYPTION_KEY") return String(value).length >= 24;
  return String(value).trim().length >= 8;
}

function getCredentialReadiness() {
  return credentialSpecs.map((spec) => {
    const value = envValue(spec.key);
    const present = Boolean(value);
    const enabled = String(value).toLowerCase() === "true";
    return {
      key: spec.key,
      label: spec.label,
      category: spec.category,
      description: spec.description,
      severity: spec.severity,
      status: present ? "present" : "missing",
      enabled,
      validLooking: present ? validLookingCredential(spec.key, value) : false,
      nextAction: present ? (validLookingCredential(spec.key, value) ? "No action needed." : `Check ${spec.key}; it does not look complete.`) : spec.nextAction
    };
  });
}

function safeChannelStatus(account = {}) {
  const setup = publicChannelSetup(account.platform);
  const envConnected = envConnectedForChannel(account.platform);
  const envAccountId = accountEnvId(account.platform);
  const connected = Boolean(account.externalAccountId || account.accountId || account.accountName || account.connectedAt || envConnected);
  const tokenExpiresAt = account.tokenExpiresAt ? new Date(account.tokenExpiresAt) : null;
  const expired = connected && tokenExpiresAt && tokenExpiresAt.getTime() <= Date.now();
  const hasStoredToken = Boolean(account.accessTokenEncrypted || account.refreshTokenEncrypted || accountEnvAccessToken(account.platform));
  const canRefresh = Boolean(account.refreshTokenEncrypted);
  let status = account.status || "not_configured";
  if (!setup.configured && !envConnected) status = "setup_required";
  else if (account.lastError || status === "error") status = "error";
  else if (expired && canRefresh) status = "needs_refresh";
  else if (expired || status === "expired") status = "expired";
  else if (connected || status === "connected") status = "connected";
  else status = "ready_to_connect";
  return {
    channel: account.platform,
	    displayName: channelLabels[account.platform] || account.displayName || account.platform,
	    status,
	    connected: status === "connected" || status === "needs_refresh",
	    configured: Boolean(setup.configured || envConnected),
	    missingEnvVars: setup.missingEnv,
	    livePostingEnabled: livePostingEnabledForChannel(account.platform),
	    liveGateEnvVars: livePostingEnvKeys[account.platform] || [],
	    accountName: account.accountName || (envConnected ? `${channelLabels[account.platform] || account.platform} env account` : ""),
    accountId: account.externalAccountId || account.accountId || envAccountId || "",
    tokenExpiresAt: account.tokenExpiresAt || "",
    lastTestedAt: account.lastTestedAt || "",
    lastErrorSummary: account.lastErrorSummary || account.lastError || "",
    hasStoredToken,
    scopes: setup.scopes,
    notes: setup.notes
  };
}

function publicFileUrlFromLocalPath(value = "") {
  const raw = String(value || "").trim();
  if (!raw) return "";
  const clean = raw.replace(/^\/+/, "");
  if (/^(data\/exports\/|data\/assets\/|assets\/)/.test(clean) && !clean.includes("..")) return `/${clean}`;
  const absolute = path.resolve(raw);
  const relative = path.relative(process.cwd(), absolute).replaceAll(path.sep, "/");
  if (relative.startsWith("..") || path.isAbsolute(relative)) return "";
  if (!/^(data\/exports\/|data\/assets\/|assets\/)/.test(relative) || relative.includes("..")) return "";
  return `/${relative}`;
}

function safeImageUrl(value = "", fallbackPath = "") {
  const url = String(value || "");
  if (!url) return publicFileUrlFromLocalPath(fallbackPath);
  if (url.startsWith("data:image/svg+xml") && url.length <= 30000) return url;
  if (url.startsWith("data:")) return publicFileUrlFromLocalPath(fallbackPath);
  if (/^https?:\/\//i.test(url)) return url;
  if (url.startsWith("/")) return url.includes("..") ? "" : url;
  return publicFileUrlFromLocalPath(url) || publicFileUrlFromLocalPath(fallbackPath);
}

function publicAssetBundleUsed(bundle = {}) {
  return {
    aspectRatio: bundle.aspectRatio || "",
    storedImagePath: bundle.storedImagePath || "",
    stylePresetName: bundle.stylePresetName || "",
    imageVariantLabel: bundle.imageVariantLabel || "",
	    finalImage: bundle.finalImage
	      ? {
	          ready: Boolean(bundle.finalImage.ready),
	          url: safeImageUrl(bundle.finalImage.url, bundle.finalImage.localPath),
	          localPath: bundle.finalImage.localPath || "",
            publicImageUrl: bundle.finalImage.publicImageUrl || "",
            storageBucket: bundle.finalImage.storageBucket || "",
            storageObjectPath: bundle.finalImage.storageObjectPath || "",
            uploadedAt: bundle.finalImage.uploadedAt || "",
	          fileSize: Number(bundle.finalImage.fileSize || 0),
	          width: Number(bundle.finalImage.width || 0),
	          height: Number(bundle.finalImage.height || 0),
	          createdAt: bundle.finalImage.createdAt || "",
	          watermarkPosition: bundle.finalImage.watermarkPosition || ""
	        }
	      : undefined
	  };
	}

function publicPostImage(image = {}) {
  const finalPath = image.finalPngPath || image.assetBundleUsed?.finalImage?.localPath || "";
  const finalUrl =
    safeImageUrl(image.finalPngUrl, finalPath) ||
    safeImageUrl(image.finalImageUrl, finalPath) ||
    safeImageUrl(image.assetBundleUsed?.finalImage?.url, image.assetBundleUsed?.finalImage?.localPath);
  const previewUrl = safeImageUrl(image.imageUrl, finalPath) || finalUrl;
  return {
    id: image.id,
    postId: image.postId,
	    imageUrl: previewUrl,
	    finalImageUrl: finalUrl,
	    finalPngUrl: finalUrl,
	    finalPngPath: image.finalPngPath || "",
      localFinalPngPath: image.localFinalPngPath || image.finalPngPath || image.assetBundleUsed?.finalImage?.localPath || "",
      publicImageUrl: image.publicImageUrl || image.assetBundleUsed?.finalImage?.publicImageUrl || "",
      public_image_url: image.public_image_url || image.publicImageUrl || image.assetBundleUsed?.finalImage?.public_image_url || image.assetBundleUsed?.finalImage?.publicImageUrl || "",
      publicImageUploadedAt: image.publicImageUploadedAt || image.assetBundleUsed?.finalImage?.uploadedAt || "",
      public_image_uploaded_at: image.public_image_uploaded_at || image.publicImageUploadedAt || image.assetBundleUsed?.finalImage?.uploadedAt || "",
      supabaseStorageBucket: image.supabaseStorageBucket || image.assetBundleUsed?.finalImage?.storageBucket || "",
      public_image_storage_bucket: image.public_image_storage_bucket || image.supabaseStorageBucket || image.assetBundleUsed?.finalImage?.public_image_storage_bucket || image.assetBundleUsed?.finalImage?.storageBucket || "",
      supabaseStorageObjectPath: image.supabaseStorageObjectPath || image.assetBundleUsed?.finalImage?.storageObjectPath || "",
      public_image_storage_path: image.public_image_storage_path || image.supabaseStorageObjectPath || image.assetBundleUsed?.finalImage?.public_image_storage_path || image.assetBundleUsed?.finalImage?.storageObjectPath || "",
	    finalPngFileSize: Number(image.finalPngFileSize || 0),
	    finalPngGeneratedAt: image.finalPngGeneratedAt || "",
    generationStatus: image.generationStatus,
    imageStatus: image.imageStatus,
    generationMode: image.generationMode,
    generationError: image.generationError,
    visualBucket: image.visualBucket,
    wilmaImageWorkflow: image.wilmaImageWorkflow || null,
    wilmaExpression: image.wilmaExpression || "",
    wilmaPoseReferenceId: image.wilmaPoseReferenceId || "",
    wilmaPoseReferenceName: image.wilmaPoseReferenceName || "",
    wilmaPoseReferenceCount: Number(image.wilmaPoseReferenceCount || 0),
    imagePrompt: image.imagePrompt || "",
    negativePrompt: image.negativePrompt || "",
    promptBuilderOutput: image.promptBuilderOutput || null,
    imageRiskLevel: image.imageRiskLevel,
    imageBrief: image.imageBrief,
    aspectRatio: image.aspectRatio,
    assetBundleKey: image.assetBundleKey,
    usesWilma: Boolean(image.usesWilma),
    usesLogo: Boolean(image.usesLogo),
    versionNumber: image.versionNumber,
    imageVersion: image.imageVersion,
    finalImageReady: Boolean(image.finalImageReady),
    textRenderingMode: image.textRenderingMode || "",
    watermarkPosition: image.watermarkPosition || "",
    styleProfile: image.styleProfile || image.creativeDirection?.styleProfile || "",
    imageVariantLabel: image.imageVariantLabel || image.creativeDirection?.imageVariantLabel || "",
    styleGate: image.styleGate || image.creativeDirection?.styleGate || null,
    assetBundleUsed: publicAssetBundleUsed(image.assetBundleUsed),
    createdAt: image.createdAt
  };
}

function withPublicChannelSetup(state) {
  state = normalizeStateForClient(state, { source: "server-public-setup-input" });
  state = analyzeOperations(state);
  const hostingConfig = storageRuntimeConfig();
  const autonomy = buildAutonomyReport(state);
  const autonomyGovernance = buildAutonomyGovernance(state);
  const livePostingGates = Object.fromEntries(platforms.map((platform) => [platform, liveGateSummary(platform)]));
  const stateWithRuntimeGates = dailyRunEngineState(state, livePostingGates);
  return normalizeStateForClient({
    ...state,
    dailyRun: dailyRunSessionView(stateWithRuntimeGates),
    autonomyActions: autonomy.actions,
    autonomySummary: autonomy.summary,
    autonomyPolicy: autonomy.policy,
    autonomyGovernance: {
      roleMatrix: autonomyGovernance.roleMatrix,
      runbooks: autonomyGovernance.runbooks,
      eventIntelligence: autonomyGovernance.eventIntelligence,
      revenueAwareness: autonomyGovernance.revenueAwareness,
      ownership: autonomyGovernance.ownership,
      safetyRails: autonomyGovernance.safetyRails
    },
    settings: {
      ...(state.settings || {}),
      sourceItems: sourceItemsForState(state)
    },
    postImages: (state.postImages || []).map(publicPostImage),
    runtime: {
      ...(state.runtime || {}),
	      liveLinkedInPostingEnabled: linkedinLivePostingSwitchEnabled(),
	      livePostingGates,
	      openAIConfigured: Boolean(process.env.OPENAI_API_KEY),
      oauthTokenEncryptionConfigured: Boolean(process.env.OAUTH_TOKEN_ENCRYPTION_KEY),
      socialChannelStatuses: {
        linkedin: linkedinSetupState(state).status,
        x: xSetupState(state).status,
        meta: metaSetupState(state).status
      },
      founderCapacityPulse: buildFounderCapacityPulse(state, { warningThreshold:12 }),
      dailyRunSnapshot: buildDailyRunSnapshot(state),
      accessControl: {
        roles: Object.fromEntries(Object.entries(roleDefinitions).map(([key, value]) => [key, { label:value.label, permissions:value.can }])),
        authRequired: storageRuntimeConfig().requestedStorageBackend === "supabase" && !storageRuntimeConfig().localDemoMode,
        localFallbackOpen: storageRuntimeConfig().activeStorageBackend === "json"
      },
      imageModel: process.env.OPENAI_IMAGE_MODEL || "gpt-image-1.5",
      draftModel: openAIDraftEnvStatus().openaiDraftModel,
      visualStylePreset: narrativeInfrastructurePreset,
      credentialReadiness: getCredentialReadiness(),
      supabaseStorage: supabaseStorageStatus(),
      googleWorkspace: googleWorkspaceDiagnostics({
        env: process.env,
        account: (state.socialAccounts || []).find((account) => account.platform === "google_workspace") || {},
        connectorStatus: defaultConnectorStatus(state)
      }),
      productionReadiness: productionReadinessForState(state, { hostingConfig }),
      manualModeActive: platforms.every((platform) => !livePostingEnabledForChannel(platform)),
      hosting: {
        localDemoMode: hostingConfig.localDemoMode,
        storageBackend: hostingConfig.activeStorageBackend,
        requestedStorageBackend: hostingConfig.requestedStorageBackend,
        appBaseUrl: appBaseUrl(),
        supabaseDbConfigured: hostingConfig.supabaseDbConfigured,
        supabaseRecordsTable: hostingConfig.supabaseRecordsTable
      }
    },
    socialAccounts: (state.socialAccounts || []).map((account) => {
      const safe = safeChannelStatus(account);
      return {
        id: account.id,
        platform: account.platform,
        displayName: safe.displayName,
        accountType: account.accountType || "profile",
        setup: {
          configured: safe.configured,
          missingEnv: safe.missingEnvVars,
          scopes: safe.scopes,
          notes: safe.notes
        },
        status: safe.status,
        connected: safe.connected,
        accountName: safe.accountName,
        accountId: safe.accountId,
        tokenExpiresAt: safe.tokenExpiresAt,
        lastTestedAt: safe.lastTestedAt,
        lastTestMessage: account.lastTestMessage || "",
	        lastErrorSummary: safe.lastErrorSummary,
	        hasStoredToken: safe.hasStoredToken,
	        oauthConfigured: safe.configured,
	        livePostingEnabled: safe.livePostingEnabled,
        liveGateEnvVars: safe.liveGateEnvVars
	      };
    })
  }, { source: "server-public-setup-output" });
}

function dailyRunEngineState(state = {}, livePostingGates = Object.fromEntries(platforms.map((platform) => [platform, liveGateSummary(platform)]))) {
  return {
    ...state,
    runtime: {
      ...(state.runtime || {}),
      livePostingGates
    }
  };
}

function productionReadinessCheck(id, label, ok, detail = "", owner = "Operations") {
  return { id, label, ok: Boolean(ok), detail, owner };
}

function productionReadinessForState(state = {}, options = {}) {
  const hostingConfig = options.hostingConfig || storageRuntimeConfig();
  const liveGatesCount = Object.values(Object.fromEntries(platforms.map((platform) => [platform, liveGateSummary(platform)]))).filter((gate) => gate.enabled).length;
  const hostedMode = hostingConfig.requestedStorageBackend === "supabase" && !hostingConfig.localDemoMode;
  const checks = [
    productionReadinessCheck("storage-backend", "Supabase data backend selected", hostingConfig.activeStorageBackend === "supabase", `Active backend: ${hostingConfig.activeStorageBackend}. Requested: ${hostingConfig.requestedStorageBackend}.`),
    productionReadinessCheck("local-fallback", "Local JSON fallback preserved", true, "Local fallback remains available for development and emergency recovery."),
    productionReadinessCheck("app-base-url", "APP_BASE_URL configured", Boolean(appBaseUrl()), appBaseUrl() ? "Hosted callback/export URLs can resolve." : "Set APP_BASE_URL on Render."),
    productionReadinessCheck("owner-token", "Hosted owner token configured", !hostedMode || Boolean(process.env.COMMAND_CENTER_OWNER_TOKEN), hostedMode ? "Required for hosted access." : "Not required in local fallback."),
    productionReadinessCheck("oauth-encryption", "OAuth token encryption configured", Boolean(process.env.OAUTH_TOKEN_ENCRYPTION_KEY), "Required before connecting Google/LinkedIn in hosted mode."),
    productionReadinessCheck("openai", "OpenAI configured", Boolean(process.env.OPENAI_API_KEY), "Required for AI drafts and real image generation."),
    productionReadinessCheck("live-gates", "Live publishing gates remain disabled", liveGatesCount === 0, `${liveGatesCount} live gate(s) enabled.`),
    productionReadinessCheck("growth-inbox", "Growth Inbox available", Array.isArray(state.growthInbox), `${(state.growthInbox || []).filter((item) => !["converted", "ignored"].includes(item.status)).length} open inbox item(s).`),
    productionReadinessCheck("tasks", "Tasks and escalations available", Array.isArray(state.tasks), `${(state.tasks || []).filter((task) => !["done", "dismissed"].includes(String(task.status || "").toLowerCase())).length} open task(s).`),
    productionReadinessCheck("audit-events", "Operating events are captured", Array.isArray(state.events) && Array.isArray(state.activityEvents), `${(state.events || []).length} event(s), ${(state.activityEvents || []).length} activity record(s).`)
  ];
  const blockers = checks.filter((check) => !check.ok);
  return {
    status: blockers.length ? "needs_attention" : "ready",
    hostedMode,
    activeStorageBackend: hostingConfig.activeStorageBackend,
    requestedStorageBackend: hostingConfig.requestedStorageBackend,
    localDemoMode: hostingConfig.localDemoMode,
    liveGatesCount,
    checks,
    blockers,
    generatedAt: new Date().toISOString()
  };
}

async function productionReadinessSnapshot() {
  const state = await store.readState();
  const hostingConfig = storageRuntimeConfig();
  const supabaseDb = await getSupabaseHealth();
  const storageDiagnostics = await diagnoseSupabaseStorage({ testUpload: false });
  const base = productionReadinessForState(state, { hostingConfig });
  const checks = [
    ...base.checks,
    productionReadinessCheck("supabase-db", "Supabase DB connected", Boolean(supabaseDb.connected), supabaseDb.connected ? `Table: ${supabaseDb.table || hostingConfig.supabaseRecordsTable}` : String(supabaseDb.error || "Supabase DB unavailable.").slice(0, 260)),
    productionReadinessCheck("supabase-storage", "Supabase Storage connected", Boolean(storageDiagnostics.bucketReachable), storageDiagnostics.bucketReachable ? `Bucket: ${storageDiagnostics.bucket}; public: ${storageDiagnostics.bucketPublic === true}` : String(storageDiagnostics.error || "Supabase Storage unavailable.").slice(0, 260))
  ];
  const blockers = checks.filter((check) => !check.ok);
  return {
    ...base,
    status: blockers.length ? "needs_attention" : "ready",
    checks,
    blockers,
    supabaseDbConnected: Boolean(supabaseDb.connected),
    supabaseStorageConnected: Boolean(storageDiagnostics.bucketReachable),
    openAIConfigured: Boolean(process.env.OPENAI_API_KEY),
    noSecretsReturned: true,
    generatedAt: new Date().toISOString()
  };
}

function safeChannelsResponse(state) {
  const accountsByPlatform = new Map((state.socialAccounts || []).map((account) => [account.platform, account]));
  return platforms.map((platform) =>
    safeChannelStatus(accountsByPlatform.get(platform) || { id: `channel-${platform}`, platform })
  );
}

function founderPostStatus(value = "") {
  const status = String(value || "").toLowerCase();
  if (status === "posted" || status === "published" || status === "manually_posted") return "Posted";
  if (status === "scheduled") return "Scheduled";
  if (status === "approved" || status === "retry_ready") return "Approved";
  if (status === "failed" || status === "blocked_channel_not_connected") return "Failed";
  return "Draft";
}

function publishStatusMap(post = {}) {
  return { ...(post.per_channel_publish_status || post.perChannelPublishStatus || {}) };
}

function publishExternalIdMap(post = {}) {
  return { ...(post.per_channel_external_post_id || post.perChannelExternalPostId || {}) };
}

function publishFailureMap(post = {}) {
  return { ...(post.per_channel_failure_reason || post.perChannelFailureReason || {}) };
}

function publishAttemptsFor(post = {}) {
  return Array.isArray(post.publish_attempts)
    ? post.publish_attempts
    : Array.isArray(post.publishAttempts)
      ? post.publishAttempts
      : [];
}

function channelAlreadyPublished(post = {}, channel = "") {
  const statuses = publishStatusMap(post);
  const externalIds = publishExternalIdMap(post);
  return statuses[channel] === "posted" || Boolean(externalIds[channel]);
}

function appendPublishAttempt(post = {}, attempt = {}) {
  return [...publishAttemptsFor(post), {
    id: `publish-attempt-${crypto.randomUUID().slice(0, 8)}`,
    postId: post.id || "",
    createdAt: new Date().toISOString(),
    ...attempt
  }].slice(-80);
}

function overallStatusFromChannelStatuses(statuses = {}, targetChannels = []) {
  const channels = targetChannels.filter(Boolean);
  if (channels.length && channels.every((channel) => statuses[channel] === "posted")) return "posted";
  if (channels.some((channel) => statuses[channel] === "failed")) return "failed";
  if (channels.some((channel) => ["scheduled", "blocked"].includes(statuses[channel]))) return "scheduled";
  return "scheduled";
}

function publishReadiness(state, post) {
  if (!post) {
    return { ok: false, status: "blocked", message: "Post not found." };
  }
  if (!["approved", "scheduled", "publishing", "retry_ready"].includes(post.status)) {
    return { ok: false, status: "blocked", message: "Only approved or scheduled posts can enter publishing." };
  }
  if (post.complianceRisk === "high") {
    return { ok: false, status: "blocked", message: "High-risk posts require final human approval before publishing." };
  }
  const targetChannels = Array.isArray(post.targetChannels) && post.targetChannels.length ? post.targetChannels : [post.platform];
  const textOnlyEligible = targetChannels.every((channel) => scheduledPublishingChannels.includes(channel)) && Boolean(post.imageIntentionallyOmitted);
  if (!post.imageFinalized && !textOnlyEligible) {
    return { ok: false, status: "blocked", message: "Finalize the image before publishing." };
  }
  if (!post.finalPreviewConfirmed && !textOnlyEligible) {
    return { ok: false, status: "blocked", message: "Confirm the final preview before publishing." };
  }
  if (!targetChannels.length) {
    return { ok: false, status: "unscheduled", message: "Choose at least one target channel." };
  }
  const channelDetails = channelReadinessDetails(state, post, { requireLiveGate:false });
  for (const channel of targetChannels) {
    const dryRun = channelDetails.dryRuns[channel];
    if (dryRun?.status === "blocked") {
      const status = dryRun.configured === false
        ? "setup_required"
        : dryRun.connected === false
          ? "blocked_channel_not_connected"
          : "blocked";
      return {
        ok: false,
        status,
        message: dryRun.message,
        channelReadiness: channelDetails.dryRuns
      };
    }
  }
  if (!post.scheduledFor) {
    return { ok: false, status: "unscheduled", message: "Add a scheduled time before publishing." };
  }
  return {
    ok: true,
    status: "ready",
    message: "Ready for live publisher adapter. No auto-posting has run.",
    channelReadiness: channelDetails.dryRuns
  };
}

async function updatePublishingCheck(postId) {
  const state = await store.readState();
  const post = state.posts.find((item) => item.id === postId);
  const readiness = publishReadiness(state, post);
	  const patch = {
	    publishingStatus: readiness.status,
	    lastPublishAttemptAt: new Date().toISOString(),
	    publishErrorSummary: readiness.ok ? "" : readiness.message,
	    channelReadiness: readiness.channelReadiness || {},
	    channelDryRuns: readiness.channelReadiness || {}
	  };
  const nextState = await store.updatePost(postId, patch);
  return { readiness, state: nextState };
}

async function recordPublishEvent({ post, channel, eventType, statusBefore, statusAfter, message, errorCode = "" }) {
  return store.addPublishEvent({
    id: crypto.randomUUID(),
    postId: post?.id,
    channel: channel || post?.platform || "unknown",
    eventType,
    statusBefore: statusBefore || post?.status || "",
    statusAfter,
    message,
    errorCode,
    createdAt: new Date().toISOString()
  });
}

function scheduledDateIsDue(value) {
  if (!value) return false;
  const date = new Date(value);
  return Number.isFinite(date.getTime()) && date.getTime() <= Date.now();
}

function composePublishText(post, channel = post.platform) {
  const adaptation = post.channelAdaptations?.[channel];
  if (adaptation?.text) return adaptation.text;
  return [post.hook, "", post.body, "", post.cta, "", (post.hashtags || []).join(" ")]
    .join("\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

function normalizePlatformName(value = "") {
  const text = String(value || "").trim().toLowerCase();
  if (["twitter", "twitter/x", "twitter-x", "x/twitter", "x-twitter", "x"].includes(text)) return "x";
  if (text.includes("linkedin")) return "linkedin";
  if (text.includes("facebook")) return "facebook";
  if (text.includes("instagram")) return "instagram";
  if (text.includes("thread")) return "threads";
  return platforms.includes(text) ? text : "";
}

function splitList(value = "") {
  return String(value || "")
    .split(/[,|]/)
    .map((item) => item.trim())
    .filter(Boolean);
}

function parseIdeaBlock(block = {}) {
  const get = (name) => {
    const pattern = new RegExp(`^${name}\\s*:\\s*(.+)$`, "im");
    return String(block || "").match(pattern)?.[1]?.trim() || "";
  };
  const title = get("Title");
  const rawIdea = get("Idea") || get("Raw idea") || get("Description");
  if (!title && !rawIdea) return null;
  const platformsValue = get("Platforms") || get("Platform");
  const parsedPlatforms = splitList(platformsValue).map(normalizePlatformName).filter(Boolean);
  return {
    id: `idea-${crypto.randomUUID()}`,
    title: title || rawIdea.slice(0, 80),
    rawIdea,
    bucket: get("Bucket") || get("Content bucket") || "LegalEase Growth",
    audience: get("Audience") || "partners",
    platforms: parsedPlatforms.length ? parsedPlatforms : ["linkedin"],
    campaign: get("Campaign"),
    cta: get("CTA") || get("Call to action") || "Learn more",
    creativeDirection: get("Creative") || get("Creative direction") || "Clean editorial LegalEase graphic.",
    usesWilma: String(get("Wilma") || "optional").toLowerCase().includes("yes") ? "yes" : String(get("Wilma") || "").toLowerCase().includes("no") ? "no" : "optional",
    complianceRisk: String(get("Risk") || "low").toLowerCase().includes("high") ? "high" : String(get("Risk") || "").toLowerCase().includes("medium") ? "medium" : "low",
    priority: String(get("Priority") || "medium").toLowerCase().includes("high") ? "high" : String(get("Priority") || "").toLowerCase().includes("low") ? "low" : "medium",
    status: "ready_to_generate",
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
    nextBestAction: "Generate draft"
  };
}

function parseCsvIdeas(text = "") {
  const lines = String(text || "").split(/\r?\n/).map((line) => line.trim()).filter(Boolean);
  if (lines.length < 2 || !lines[0].includes(",")) return [];
  const headers = lines[0].split(",").map((header) => header.trim().toLowerCase());
  return lines.slice(1).map((line) => {
    const values = line.split(",").map((value) => value.trim());
    const row = Object.fromEntries(headers.map((header, index) => [header, values[index] || ""]));
    return {
      id: `idea-${crypto.randomUUID()}`,
      title: row.title || row.idea || "Untitled idea",
      rawIdea: row.idea || row.rawidea || row.description || row.title || "",
      bucket: row.bucket || "LegalEase Growth",
      audience: row.audience || "partners",
      platforms: splitList(row.platforms || row.platform || "linkedin").map(normalizePlatformName).filter(Boolean),
      campaign: row.campaign || "",
      cta: row.cta || "Learn more",
      creativeDirection: row.creative || row.creativedirection || "Clean editorial LegalEase graphic.",
      usesWilma: row.wilma || "optional",
      complianceRisk: row.risk || "low",
      priority: row.priority || "medium",
      status: "ready_to_generate",
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      nextBestAction: "Generate draft"
    };
  }).filter((item) => item.title || item.rawIdea);
}

function parseContentBankIdeas(input = "") {
  const text = String(input || "").trim();
  if (!text) throw new Error("Paste at least one content idea.");
  if (text.startsWith("[") || text.startsWith("{")) {
    const raw = JSON.parse(text);
    const rows = Array.isArray(raw) ? raw : [raw];
    return rows.map((item) => ({
      id: item.id || `idea-${crypto.randomUUID()}`,
      title: item.title || item.rawIdea || "Untitled idea",
      rawIdea: item.rawIdea || item.idea || item.description || "",
      bucket: item.bucket || item.contentBucket || "LegalEase Growth",
      audience: item.audience || "partners",
      platforms: Array.isArray(item.platforms) ? item.platforms.map(normalizePlatformName).filter(Boolean) : splitList(item.platforms || item.platform || "linkedin").map(normalizePlatformName).filter(Boolean),
      campaign: item.campaign || "",
      cta: item.cta || "Learn more",
      creativeDirection: item.creativeDirection || item.creative || "Clean editorial LegalEase graphic.",
      usesWilma: item.usesWilma || item.wilma || "optional",
      complianceRisk: item.complianceRisk || item.risk || "low",
      priority: item.priority || "medium",
      status: item.status || "ready_to_generate",
      createdAt: item.createdAt || new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      nextBestAction: item.nextBestAction || "Generate draft"
    }));
  }
  const csvIdeas = parseCsvIdeas(text);
  if (csvIdeas.length) return csvIdeas;
  const blocks = text.split(/\n\s*\n(?=Title\s*:)/i);
  const ideas = blocks.map(parseIdeaBlock).filter(Boolean);
  if (!ideas.length) throw new Error("Could not parse ideas. Use Title:, Idea:, Bucket:, Platforms:, CTA:, Wilma:, Risk:, Creative:.");
  return ideas;
}

function platformHookForIdea(idea = {}, platform = "linkedin") {
  if (platform === "x") return `${idea.title}: ${String(idea.rawIdea || "").split(".")[0] || "make the next step clearer"}.`;
  if (platform === "instagram") return idea.title;
  return idea.title;
}

function localComplianceRewriteForIdea(idea = {}) {
  if (idea.complianceRisk !== "high") return "";
  return [
    idea.rawIdea || idea.title || "This topic needs careful review.",
    "This draft must stay general, avoid legal advice, avoid eligibility promises, and avoid any guarantee about filing, court approval, cleanup, employment, housing, or other outcomes.",
    "Roger should review before approval."
  ].join("\n\n");
}

function draftPostFromIdea(idea = {}, platform = "linkedin") {
  const safePlatform = normalizePlatformName(platform) || "linkedin";
  const now = new Date().toISOString();
  const body = safePlatform === "x"
    ? String(idea.rawIdea || idea.title || "").slice(0, 180)
    : idea.rawIdea || `Explain: ${idea.title}`;
  const draft = {
    id: `post-${slugify(idea.title)}-${safePlatform}-${crypto.randomUUID().slice(0, 8)}`,
    title: idea.title,
    platform: safePlatform,
    status: idea.complianceRisk === "high" ? "needs_review" : "needs_review",
    contentType: "content_bank_draft",
    sourceType: "content_bank",
    contentBankIdeaId: idea.id,
    campaign: idea.campaign || "",
    scheduledFor: "",
    hook: platformHookForIdea(idea, safePlatform),
    body,
    cta: idea.cta || "Learn more",
    hashtags: ["#LegalEase", ...(idea.bucket ? [`#${slugify(idea.bucket).replace(/-/g, "")}`] : [])],
    complianceRisk: idea.complianceRisk || "low",
    complianceNotes: idea.complianceRisk === "high"
      ? "High-risk idea. Human compliance review required before approval."
      : "Educational content only. No legal advice or guaranteed outcomes.",
    complianceRewrite: localComplianceRewriteForIdea(idea),
    createdAt: now,
    updatedAt: now,
    speaker: idea.usesWilma === "yes" ? "wilma" : "legalease",
    audience: idea.audience || "partners",
    contentBucket: idea.bucket || "LegalEase Growth",
    targetChannels: [safePlatform],
    copyReviewed: false,
    copyReviewedAt: "",
    overlayConfirmed: false,
    imageFinalized: false,
    finalPreviewConfirmed: false,
    manualPostingKitReady: false,
    publishingStatus: "approval_required",
    publishErrorSummary: "",
    creativeBrief: idea.creativeDirection || "Clean editorial LegalEase graphic.",
    imageRiskLevel: idea.complianceRisk || "low",
    wilmaImageWorkflow: {
      state: "Needs Copy Review",
      visualBucket: idea.bucket || "LegalEase Growth",
      wilmaExpression: idea.usesWilma === "yes" ? "Helpful" : "",
      wilmaPoseReferenceId: idea.usesWilma === "yes" ? "pose-03" : "",
      wilmaPoseReferenceName: idea.usesWilma === "yes" ? "Helpful guide" : "",
      platformFormatSize: wilmaPlatformFormatSize(safePlatform),
      overlayText: idea.title,
      imagePrompt: idea.creativeDirection || "",
      negativePrompt: "No readable text, fake logos, legal guarantees, court victory imagery, mugshots, jail bars, or handcuffs.",
      brandSafeRules: ["No legal guarantees", "No fake partner logos", "No readable fake text"],
      overlayRules: ["Readable on mobile", "No outcome promises"]
    },
    recommendedPostingWindow: safePlatform === "linkedin" ? "Tue-Thu morning" : "This week",
    approvalStatus: "needs_review",
    nextBestAction: "Review copy"
  };
  // Guidelines gate report stamped at creation so the Review Desk shows hard fails
  // immediately; enforcement happens at approve/schedule.
  draft.guidelinesGate = socialGuidelinesGate(draft);
  return draft;
}

function contentDraftPrompt(idea = {}, platform = "linkedin") {
  const platformLabel = platformLabels[platform] || platform;
  return `Create one approval-ready LegalEase social draft.

Context:
- Title: ${idea.title || ""}
- Raw idea: ${idea.rawIdea || ""}
- Bucket: ${idea.bucket || "LegalEase Growth"}
- Audience: ${idea.audience || "partners"}
- Platform: ${platformLabel}
- Campaign: ${idea.campaign || "none"}
- CTA: ${idea.cta || "Learn more"}
- Creative direction: ${idea.creativeDirection || "Clean LegalEase editorial creative."}
- Wilma usage: ${idea.usesWilma || "optional"}
- Compliance risk: ${idea.complianceRisk || "low"}

Rules:
- Plain English, calm, useful, not hype.
- No legal advice.
- No eligibility guarantees.
- No outcome guarantees.
- No fake partner/government claims.
- No claims that a court will approve anything.
- If compliance risk is high, rewrite the draft to be safer and set complianceRewrite.
- Keep Twitter / X under 260 characters if platform is Twitter / X.
- Do not include final image text. Creative brief can describe art direction only.`;
}

function aiDraftResponseSchema() {
  return {
    type: "json_schema",
    name: "legalese_social_draft",
    strict: true,
    schema: {
      type: "object",
      additionalProperties: false,
      properties: {
        hook: { type: "string" },
        body: { type: "string" },
        cta: { type: "string" },
        hashtags: { type: "array", items: { type: "string" } },
        creativeBrief: { type: "string" },
        complianceNotes: { type: "string" },
        complianceRewrite: { type: "string" },
        recommendedPostingWindow: { type: "string" }
      },
      required: ["hook", "body", "cta", "hashtags", "creativeBrief", "complianceNotes", "complianceRewrite", "recommendedPostingWindow"]
    }
  };
}

function extractOpenAIText(payload = {}) {
  if (payload.output_text) return String(payload.output_text);
  for (const item of payload.output || []) {
    for (const content of item.content || []) {
      if (content.text) return String(content.text);
    }
  }
  return "";
}

function normalizeAIHashtags(values = []) {
  return (Array.isArray(values) ? values : [])
    .map((value) => String(value || "").trim())
    .filter(Boolean)
    .map((value) => value.startsWith("#") ? value : `#${value.replace(/^#+/, "")}`)
    .slice(0, 6);
}

function applyAIDraftToPost(post = {}, ai = {}, meta = {}) {
  const highRisk = post.complianceRisk === "high";
  const saferBody = highRisk && ai.complianceRewrite ? ai.complianceRewrite : ai.body;
  const next = {
    ...post,
    hook: String(ai.hook || post.hook || post.title).trim(),
    body: String(saferBody || post.body || "").trim(),
    cta: String(ai.cta || post.cta || "Learn more").trim(),
    hashtags: normalizeAIHashtags(ai.hashtags).length ? normalizeAIHashtags(ai.hashtags) : post.hashtags,
    creativeBrief: String(ai.creativeBrief || post.creativeBrief || "").trim(),
    complianceNotes: String(ai.complianceNotes || post.complianceNotes || "").trim(),
    complianceRewrite: String(ai.complianceRewrite || "").trim(),
    originalAIDraftBody: highRisk && ai.body ? String(ai.body).trim() : "",
    recommendedPostingWindow: String(ai.recommendedPostingWindow || post.recommendedPostingWindow || "This week").trim(),
    generationMode: "ai_draft",
    aiDraftStatus: "generated",
    aiDraftModel: meta.model,
    aiDraftGeneratedAt: meta.generatedAt,
    aiDraftPromptVersion: "legalese-content-bank-ai-draft-v1",
    approvalStatus: "needs_review",
    status: "needs_review",
    nextBestAction: highRisk ? "Review compliance rewrite" : "Review AI draft"
  };
  // Re-stamp the guidelines gate after AI copy lands on the post.
  next.guidelinesGate = socialGuidelinesGate(next);
  return next;
}

async function draftPostFromIdeaWithAI(idea = {}, platform = "linkedin") {
  const localPost = draftPostFromIdea(idea, platform);
  const apiKey = process.env.OPENAI_API_KEY;
  const env = openAIDraftEnvStatus();
  if (!apiKey) throw new Error("OPENAI_API_KEY is missing. Local fallback used.");
  let response;
  try {
    response = await fetch("https://api.openai.com/v1/responses", {
      method: "POST",
      headers: {
        authorization: `Bearer ${apiKey}`,
        "content-type": "application/json"
      },
      body: JSON.stringify({
        model: env.openaiDraftModel,
        instructions: "You are LegalEase's careful social content drafter. Produce safe, approval-ready drafts only. Never claim legal outcomes or eligibility. Return structured JSON only.",
        input: [{ role: "user", content: [{ type: "input_text", text: contentDraftPrompt(idea, normalizePlatformName(platform) || "linkedin") }] }],
        text: { format: aiDraftResponseSchema(), verbosity: "low" },
        max_output_tokens: 1200
      })
    });
  } catch (error) {
    throw new Error(`OpenAI draft request failed. ${safeShortError(error.message)}`);
  }
  const payload = await response.json().catch(() => ({}));
  if (!response.ok) {
    const message = payload?.error?.message || response.statusText || "OpenAI draft request failed.";
    throw new Error(`OpenAI draft request failed. ${safeShortError(message)}`);
  }
  const text = extractOpenAIText(payload);
  if (!text) throw new Error("OpenAI draft response was empty. Local fallback used.");
  let parsed;
  try {
    parsed = JSON.parse(text);
  } catch (error) {
    throw new Error("OpenAI draft response was not valid JSON. Local fallback used.");
  }
  return applyAIDraftToPost(localPost, parsed, { model: env.openaiDraftModel, generatedAt: new Date().toISOString() });
}

// Minimal Claude (Anthropic) client. Key + transport only, mirroring the OpenAI
// wiring above. Server-side only; the key is never sent to the browser.
async function callAnthropic({ system = "", prompt = "", maxTokens = 1024 } = {}) {
  const apiKey = process.env.ANTHROPIC_API_KEY;
  if (!apiKey) throw new Error("ANTHROPIC_API_KEY is missing.");
  const env = anthropicEnvStatus();
  let response;
  try {
    response = await fetch("https://api.anthropic.com/v1/messages", {
      method: "POST",
      headers: {
        "x-api-key": apiKey,
        "anthropic-version": "2023-06-01",
        "content-type": "application/json"
      },
      body: JSON.stringify({
        model: env.anthropicModel,
        max_tokens: maxTokens,
        ...(system ? { system } : {}),
        messages: [{ role: "user", content: prompt }]
      })
    });
  } catch (error) {
    throw new Error(`Anthropic request failed. ${safeShortError(error.message)}`);
  }
  const payload = await response.json().catch(() => ({}));
  if (!response.ok) {
    const message = payload?.error?.message || response.statusText || "Anthropic request failed.";
    throw new Error(`Anthropic request failed. ${safeShortError(message)}`);
  }
  const text = (payload.content || [])
    .filter((block) => block?.type === "text")
    .map((block) => block.text)
    .join("")
    .trim();
  return { text, model: env.anthropicModel };
}

async function importContentBankIdeas(payload = {}) {
  return serializeStateMutation(async () => {
    const state = await store.readState();
    const imported = parseContentBankIdeas(payload.text || payload.input || JSON.stringify(payload.ideas || []));
    const existing = state.contentBank || [];
    const existingKeys = new Set(existing.map((item) => `${String(item.title).toLowerCase()}|${String(item.rawIdea).toLowerCase()}`));
    const deduped = imported.filter((item) => !existingKeys.has(`${String(item.title).toLowerCase()}|${String(item.rawIdea).toLowerCase()}`));
    const nextState = analyzeOperations({
      ...state,
      contentBank: [...existing, ...deduped],
      generationBatches: state.generationBatches || []
    });
    await writeChangedCollections(state, nextState);
    return { state: nextState, imported: deduped.length, total: nextState.contentBank.length, ideas: deduped };
  });
}

async function generateContentBankDrafts(payload = {}) {
  const state = await store.readState();
  const selectedIds = Array.isArray(payload.ids) ? new Set(payload.ids) : null;
  const limit = Number(payload.limit || 30);
  const requestedMode = payload.mode === "ai" ? "ai" : "local";
  const candidates = (state.contentBank || [])
    .filter((idea) => !selectedIds || selectedIds.has(idea.id))
    .filter((idea) => ["idea", "ready_to_generate", "generated"].includes(idea.status || "idea"))
    .slice(0, limit);
  if (!candidates.length) throw new Error("No Content Bank ideas are ready to generate.");
  const posts = [];
  const fallbackEvents = [];
  const now = new Date().toISOString();
  for (const idea of candidates) {
    for (const platform of (idea.platforms || ["linkedin"]).map(normalizePlatformName).filter(Boolean)) {
      if (requestedMode === "ai") {
        try {
          posts.push(await draftPostFromIdeaWithAI(idea, platform));
        } catch (error) {
          const fallbackPost = {
            ...draftPostFromIdea(idea, platform),
            generationMode: "local_fallback_after_ai_failure",
            aiDraftStatus: "fallback",
            aiDraftError: safeShortError(error.message),
            nextBestAction: idea.complianceRisk === "high" ? "Review local fallback and compliance risk" : "Review local fallback draft"
          };
          fallbackEvents.push({ ideaId: idea.id, platform, error: fallbackPost.aiDraftError });
          posts.push(fallbackPost);
        }
      } else {
        posts.push({ ...draftPostFromIdea(idea, platform), generationMode: "local_demo" });
      }
    }
  }
  const generatedIdeaIds = new Set(candidates.map((idea) => idea.id));
  const nextState = analyzeOperations({
    ...state,
    posts: [...(state.posts || []), ...posts],
    contentBank: (state.contentBank || []).map((idea) =>
      generatedIdeaIds.has(idea.id)
        ? { ...idea, status: "generated", updatedAt: now, nextBestAction: "Review generated drafts" }
        : idea
    ),
    generationBatches: [
      {
        id: `batch-${crypto.randomUUID()}`,
        source: "content_bank",
        ideaIds: [...generatedIdeaIds],
        postIds: posts.map((post) => post.id),
        createdAt: now,
        status: "generated",
        mode: requestedMode,
        aiFallbackCount: fallbackEvents.length,
        aiFallbackEvents: fallbackEvents.slice(0, 20),
        nextBestAction: "Review drafts in Approval Queue"
      },
      ...(state.generationBatches || [])
    ]
  });
  // Scoped but NOT serialized: the AI drafting loop above holds network calls, and the
  // mutation lock must never wait on a model round-trip. The diff-scoped write removes the
  // full-state clobber; the read happened before the AI calls, matching prior behavior.
  await writeChangedCollections(state, nextState);
  return { state: nextState, generated: posts.length, posts, mode: requestedMode, fallbackCount: fallbackEvents.length, fallbackEvents };
}

async function sendContentBankIdeasToQueue(payload = {}) {
  return serializeStateMutation(async () => {
    const state = await store.readState();
    const selectedIds = new Set(Array.isArray(payload.ids) ? payload.ids : []);
    if (!selectedIds.size) throw new Error("Select at least one idea.");
    const posts = (state.contentBank || [])
      .filter((idea) => selectedIds.has(idea.id))
      .map((idea) => draftPostFromIdea(idea, (idea.platforms || ["linkedin"])[0]));
    const now = new Date().toISOString();
    const nextState = analyzeOperations({
      ...state,
      posts: [...(state.posts || []), ...posts],
      contentBank: (state.contentBank || []).map((idea) =>
        selectedIds.has(idea.id) ? { ...idea, status: "queued", updatedAt: now, nextBestAction: "Review draft in Queue" } : idea
      )
    });
    await writeChangedCollections(state, nextState);
    return { state: nextState, queued: posts.length, posts };
  });
}

async function archiveContentBankIdeas(payload = {}) {
  return serializeStateMutation(async () => {
    const state = await store.readState();
    const selectedIds = new Set(Array.isArray(payload.ids) ? payload.ids : []);
    if (!selectedIds.size) throw new Error("Select at least one idea.");
    const now = new Date().toISOString();
    const nextState = analyzeOperations({
      ...state,
      contentBank: (state.contentBank || []).map((idea) =>
        selectedIds.has(idea.id)
          ? { ...idea, status: "archived", updatedAt: now, nextBestAction: "Archived" }
          : idea
      )
    });
    await writeChangedCollections(state, nextState);
    return { state: nextState, archived: selectedIds.size };
  });
}

function growthInboxTriagePrompt(item = {}) {
  return `Classify this LegalEase company signal for internal operations only.

Return JSON only with:
- sourceType: one of meeting_notes, partner_update, investor_note, customer_support_issue, content_idea, campaign_idea, pilot_update, revenue_pipeline_update, compliance_concern
- priority: low, normal, medium, high
- riskLevel: low, medium, high
- summary: one concise sentence
- suggestedAction: one concrete next action
- suggestedDestination: one of task, content_idea, partner_update, campaign_update, support_issue, evidence_pack_note, pilot_update

Safety:
- Draft triage only.
- Do not write legal advice.
- Do not promise eligibility or court outcomes.
- High-risk legal/compliance/customer issues require human review.

Raw signal:
${item.rawText || ""}`;
}

function growthInboxTriageSchema() {
  return {
    type: "json_schema",
    name: "legalese_growth_inbox_triage",
    strict: true,
    schema: {
      type: "object",
      additionalProperties: false,
      properties: {
        sourceType: { type: "string", enum: ["meeting_notes", "partner_update", "investor_note", "customer_support_issue", "content_idea", "campaign_idea", "pilot_update", "revenue_pipeline_update", "compliance_concern"] },
        priority: { type: "string", enum: ["low", "normal", "medium", "high"] },
        riskLevel: { type: "string", enum: ["low", "medium", "high"] },
        summary: { type: "string" },
        suggestedAction: { type: "string" },
        suggestedDestination: { type: "string", enum: ["task", "content_idea", "partner_update", "campaign_update", "support_issue", "evidence_pack_note", "pilot_update"] }
      },
      required: ["sourceType", "priority", "riskLevel", "summary", "suggestedAction", "suggestedDestination"]
    }
  };
}

async function aiTriageGrowthInboxItem(item = {}) {
  const apiKey = process.env.OPENAI_API_KEY;
  const env = openAIDraftEnvStatus();
  if (!apiKey) throw new Error("OPENAI_API_KEY is missing. Rule-assisted triage used.");
  let response;
  try {
    response = await fetch("https://api.openai.com/v1/responses", {
      method: "POST",
      headers: {
        authorization: `Bearer ${apiKey}`,
        "content-type": "application/json"
      },
      body: JSON.stringify({
        model: env.openaiDraftModel,
        instructions: "You are LegalEase's internal operations triage assistant. Classify raw company signals into safe draft operational work. Never send, publish, or provide legal advice. Return JSON only.",
        input: [{ role: "user", content: [{ type: "input_text", text: growthInboxTriagePrompt(item) }] }],
        text: { format: growthInboxTriageSchema(), verbosity: "low" },
        max_output_tokens: 700
      })
    });
  } catch (error) {
    throw new Error(`OpenAI triage request failed. ${safeShortError(error.message)}`);
  }
  const payload = await response.json().catch(() => ({}));
  if (!response.ok) {
    const message = payload?.error?.message || response.statusText || "OpenAI triage request failed.";
    throw new Error(`OpenAI triage request failed. ${safeShortError(message)}`);
  }
  const text = extractOpenAIText(payload);
  if (!text) throw new Error("OpenAI triage response was empty. Rule-assisted triage used.");
  try {
    return JSON.parse(text);
  } catch {
    throw new Error("OpenAI triage response was not valid JSON. Rule-assisted triage used.");
  }
}

function upsertConvertedGrowthRecord(state = {}, convertedRecord = null) {
  if (!convertedRecord?.collection || !convertedRecord?.record) return state;
  const collection = convertedRecord.collection;
  const record = convertedRecord.record;
  const current = Array.isArray(state[collection]) ? state[collection] : [];
  const relatedName = String(record.organizationName || record.campaignName || "").toLowerCase();
  if (collection === "partners" && relatedName) {
    const existing = current.find((item) => String(item.organizationName || "").toLowerCase() === relatedName);
    if (existing) {
      return {
        ...state,
        partners: current.map((item) => item.id === existing.id ? {
          ...item,
          nextAction: record.nextAction || item.nextAction,
          notes: [item.notes, record.notes].filter(Boolean).join("\n\n"),
          lastTouchDate: record.lastTouchDate || item.lastTouchDate,
          updatedAt: record.updatedAt
        } : item)
      };
    }
  }
  if (collection === "campaigns" && relatedName) {
    const existing = current.find((item) => String(item.campaignName || "").toLowerCase() === relatedName);
    if (existing) {
      return {
        ...state,
        campaigns: current.map((item) => item.id === existing.id ? {
          ...item,
          nextAction: record.nextAction || item.nextAction,
          notes: [item.notes, record.notes].filter(Boolean).join("\n\n"),
          updatedAt: record.updatedAt
        } : item)
      };
    }
  }
  return { ...state, [collection]: [record, ...current.filter((item) => item.id !== record.id)] };
}

function appendGrowthInboxEvent(state = {}, event = null) {
  if (!event) return state;
  return {
    ...state,
    events: [event, ...(state.events || [])].slice(0, 1000),
    activityEvents: [
      {
        id: event.id.replace(/^event-/, "activity-"),
        eventType: event.eventType,
        title: event.title,
        relatedObjectType: event.objectType,
        relatedObjectId: event.objectId,
        createdAt: event.createdAt
      },
      ...(state.activityEvents || [])
    ].slice(0, 500)
  };
}

function taskEvent(eventType = "task_updated", task = {}, metadata = {}) {
  const now = metadata.now || new Date().toISOString();
  return {
    id: `event-${eventType}-${crypto.randomUUID().slice(0, 8)}`,
    eventType,
    title: task.title || "Task",
    source: "tasks",
    objectType: "task",
    objectId: task.id || "",
    partnerId: task.partnerId || "",
    campaignId: task.campaignId || "",
    riskLevel: task.riskLevel || "low",
    proofValue: task.sourceType === "report" || task.sourceType === "data_room" ? "medium" : "low",
    revenueImpact: task.sourceType === "revenue" ? "medium" : "low",
    nextAction: task.nextAction || "",
    metadata,
    createdAt: now,
    timestamp: now
  };
}

function appendTaskEvent(state = {}, event = null) {
  if (!event) return state;
  return {
    ...state,
    events: [event, ...(state.events || [])].slice(0, 1000),
    activityEvents: [
      {
        id: event.id.replace(/^event-/, "activity-"),
        eventType: event.eventType,
        title: event.title,
        relatedObjectType: event.objectType,
        relatedObjectId: event.objectId,
        createdAt: event.createdAt
      },
      ...(state.activityEvents || [])
    ].slice(0, 500)
  };
}

async function rebuildTasksState() {
  return serializeStateMutation(async () => {
    const state = await store.readState();
    const analyzed = analyzeOperations(state);
    const automaticTasks = deriveAutomaticTasks(analyzed);
    const merged = mergeAutomaticTasks(analyzed, automaticTasks);
    const event = taskEvent("tasks_rebuilt", { id: "automatic", title: `${automaticTasks.length} automatic task(s) evaluated`, sourceType: "tasks" }, { automaticCount: automaticTasks.length });
    const nextState = analyzeOperations(appendTaskEvent(merged, event));
    await writeChangedCollections(state, nextState);
    return { state: nextState, created: Math.max(0, (nextState.tasks || []).length - (state.tasks || []).length), automaticCount: automaticTasks.length, message: "Tasks rebuilt." };
  });
}

async function updateTaskRecord(id = "", action = "in_progress", patch = {}) {
  return serializeStateMutation(async () => {
    const state = await store.readState();
    const existing = (state.tasks || []).find((task) => task.id === id);
    if (!existing) throw new Error("Task not found.");
    const internalActions = new Set(["in_progress", "waiting", "blocked", "block", "done", "reopen", "archive", "add_note", "update_priority", "update_due_date", "snooze", "assign", "dismiss"]);
    if (internalActions.has(action)) {
      const result = updateTaskInState(state, id, action, patch || {}, { actor: "owner_token" });
      const nextState = analyzeOperations(result.state);
      await writeChangedCollections(state, nextState);
      const messages = {
        in_progress: "Task marked in progress.",
        waiting: "Task marked waiting.",
        blocked: "Task marked blocked.",
        block: "Task marked blocked.",
        done: "Task marked done.",
        reopen: "Task reopened.",
        archive: "Task archived.",
        add_note: "Task note added.",
        update_priority: "Task priority updated.",
        update_due_date: "Task due date updated.",
        snooze: "Task snoozed.",
        assign: "Task assigned.",
        dismiss: "Task archived."
      };
      return { state: nextState, task: result.task, message: messages[action] || "Task updated." };
    }
    const updated = updateTask(existing, action, patch || {});
    let next = {
      ...state,
      tasks: (state.tasks || []).map((task) => task.id === id ? updated : task)
    };
    if (action === "convert-report-note") {
      const note = {
        id: `evidence-note-task-${id}`,
        title: updated.title,
        summary: updated.description || updated.nextAction || "",
        sourceType: "task",
        sourceId: id,
        riskLevel: updated.riskLevel || "low",
        status: "draft",
        nextBestAction: "Review for Weekly Evidence Pack",
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString()
      };
      next.evidencePackNotes = [note, ...(next.evidencePackNotes || []).filter((item) => item.id !== note.id)];
    }
    if (action === "convert-content-idea") {
      const idea = {
        id: `idea-task-${id}`,
        title: updated.title,
        rawIdea: updated.description || updated.nextAction || updated.title,
        bucket: "LegalEase Growth",
        audience: updated.sourceType === "partner" ? "partners" : "general",
        platforms: ["linkedin"],
        campaign: updated.campaignId || "",
        cta: "Learn more",
        creativeDirection: "Clean LegalEase operational story. No legal promises.",
        usesWilma: "optional",
        complianceRisk: updated.riskLevel === "high" ? "high" : "low",
        priority: updated.priority || "medium",
        status: "idea",
        nextBestAction: "Generate draft when ready",
        sourceId: id,
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString()
      };
      next.contentBank = [idea, ...(next.contentBank || []).filter((item) => item.id !== idea.id)];
    }
    const event = taskEvent(`task_${action.replaceAll("-", "_")}`, updated, { action });
    next = analyzeOperations(appendTaskEvent(next, event));
    await writeChangedCollections(state, next);
    return { state: next, task: updated, message: action === "done" ? "Task marked done." : action === "dismiss" ? "Task dismissed." : "Task updated." };
  });
}

// Le-E chat v2. Three deliberate properties, all fixing prod failures of the old endpoint:
// (1) The response is the chat delta only, never a full-state echo (the old 7.6 MB body blew
//     the client's 8s abort on prod data). (2) All writes are SCOPED to the collections this
//     handler actually changes. (3) The retired leeActionProposals lane migrates one-way into
//     the I4 automationSuggestions flow, and the abandoned knowledge index is drained so it
//     stops bloating /api/state. Le-E itself never applies anything: suggestions land
//     "pending" and only the existing approve endpoint changes records.
async function runLeeChat(payload = {}, actor = {}) {
  return serializeStateMutation(async () => {
    const state = await store.readState();
    const now = new Date().toISOString();
    const visibleState = stripOwnerOnlyCollections(state, actor);
    const migration = migrateLegacyLeeProposals(state, { now });
    const result = await runLeeAssistant(visibleState, payload || {}, {
      now,
      callModel: buildLeeModelCaller(process.env)
    });
    const newSuggestions = [...result.suggestions, ...migration.suggestions];
    const patch = {
      leeThreads: [result.thread, ...(state.leeThreads || []).filter((thread) => thread.id !== result.thread.id)].slice(0, 100),
      leeMessages: [result.userMessage, result.assistantMessage, ...(state.leeMessages || [])].slice(0, 1000),
      leeRuns: [result.run, ...(state.leeRuns || [])].slice(0, 300),
      leeMemory: { ...(state.leeMemory || {}), lastThreadId: result.thread.id, lastPrompt: String(payload?.message || "").slice(0, 240), updatedAt: now }
    };
    if (newSuggestions.length) {
      patch.automationSuggestions = [...newSuggestions, ...(state.automationSuggestions || [])].slice(0, 200);
    }
    if (migration.changed) patch.leeActionProposals = migration.state.leeActionProposals;
    if ((state.leeKnowledgeChunks || []).length) patch.leeKnowledgeChunks = [];
    if ((state.leeKnowledgeSources || []).length) patch.leeKnowledgeSources = [];
    await store.writeCollections(patch);
    return {
      thread: result.thread,
      messages: [result.userMessage, result.assistantMessage],
      suggestions: result.suggestions,
      migratedLegacyProposals: migration.migratedCount,
      message: result.suggestions.length
        ? `Le-E answered and queued ${result.suggestions.length} suggestion(s) for your approval.`
        : "Le-E answered."
    };
  });
}

async function createGrowthInboxItem(payload = {}) {
  return serializeStateMutation(async () => {
    const state = await store.readState();
    const item = normalizeGrowthInboxItem(payload || {});
    const duplicate = (state.growthInbox || []).find((entry) => {
      if (entry.fingerprint && entry.fingerprint === item.fingerprint) return true;
      return growthInboxFingerprint(entry.rawText || "") === item.fingerprint;
    });
    if (duplicate && !["ignored", "converted"].includes(String(duplicate.status || "").toLowerCase())) {
      const event = growthInboxEvent("growth_inbox_duplicate_blocked", duplicate, { attemptedId: item.id, fingerprint: item.fingerprint }, new Date().toISOString());
      const nextState = analyzeOperations(appendGrowthInboxEvent(state, event));
      await writeChangedCollections(state, nextState);
      return { state: nextState, item: duplicate, duplicate: true, message: "Duplicate signal already exists in Growth Inbox." };
    }
    const event = growthInboxEvent("growth_inbox_item_created", item, { sourceType: item.sourceType });
    const nextState = analyzeOperations(appendGrowthInboxEvent({
      ...state,
      growthInbox: [item, ...(state.growthInbox || [])]
    }, event));
    await writeChangedCollections(state, nextState);
    return { state: nextState, item, message: "Growth Inbox item added." };
  });
}

async function triageNewGrowthInboxItems() {
  return serializeStateMutation(async () => {
    const state = await store.readState();
    const now = new Date().toISOString();
    let count = 0;
    const items = (state.growthInbox || []).map((item) => {
      if (String(item.status || "new").toLowerCase() !== "new") return item;
      count += 1;
      return triageGrowthInboxItem(item, {
        aiTriage: {
          mode: "rule_assisted_batch",
          generatedAt: now
        }
      }, { now });
    });
    const event = growthInboxEvent("growth_inbox_batch_triaged", { id: "batch", summary: `${count} Growth Inbox item(s) triaged`, riskLevel: count ? "medium" : "low" }, { count }, now);
    const nextState = analyzeOperations(appendGrowthInboxEvent({ ...state, growthInbox: items }, event));
    await writeChangedCollections(state, nextState);
    return { state: nextState, count, message: count ? `${count} Growth Inbox item(s) triaged.` : "No new Growth Inbox items to triage." };
  });
}

async function triageGrowthInboxRecord(id = "", options = {}) {
  return serializeStateMutation(async () => {
    const state = await store.readState();
    const item = (state.growthInbox || []).find((entry) => entry.id === id);
    if (!item) throw new Error("Growth Inbox item not found.");
    let aiPatch = {};
    let aiError = "";
    if (options.useAI !== false && process.env.OPENAI_API_KEY) {
      try {
        aiPatch = await aiTriageGrowthInboxItem(item);
      } catch (error) {
        aiError = safeShortError(error.message);
      }
    }
    const triaged = triageGrowthInboxItem(item, {
      ...aiPatch,
      aiTriage: {
        mode: Object.keys(aiPatch).length ? "openai_draft" : "rule_assisted",
        model: Object.keys(aiPatch).length ? openAIDraftEnvStatus().openaiDraftModel : "",
        error: aiError,
        generatedAt: new Date().toISOString()
      }
    });
    const event = growthInboxEvent("growth_inbox_item_triaged", triaged, { triageMode: triaged.aiTriage?.mode || "rule_assisted", aiError });
    const nextState = analyzeOperations(appendGrowthInboxEvent({
      ...state,
      growthInbox: (state.growthInbox || []).map((entry) => entry.id === id ? triaged : entry)
    }, event));
    await writeChangedCollections(state, nextState);
    return { state: nextState, item: triaged, aiError, message: aiError ? "Triaged with rule-assisted fallback." : "Growth Inbox item triaged." };
  });
}

async function convertGrowthInboxRecord(id = "", destination = "task", options = {}) {
  return serializeStateMutation(async () => {
    const state = await store.readState();
    const item = (state.growthInbox || []).find((entry) => entry.id === id);
    if (!item) throw new Error("Growth Inbox item not found.");
    const result = convertGrowthInboxItem(item, destination, options || {});
    let next = {
      ...state,
      growthInbox: (state.growthInbox || []).map((entry) => entry.id === id ? result.item : entry)
    };
    next = upsertConvertedGrowthRecord(next, result.convertedRecord);
    next = analyzeOperations(appendGrowthInboxEvent(next, result.event));
    await writeChangedCollections(state, next);
    return { state: next, item: result.item, convertedRecord: result.convertedRecord, message: result.convertedRecord ? `Converted to ${result.convertedRecord.collection}.` : "Growth Inbox item ignored." };
  });
}

async function rebuildPriorityState() {
  return serializeStateMutation(async () => {
    const state = await store.readState();
    const nextState = analyzeOperations(state);
    await writeChangedCollections(state, nextState);
    return { state: nextState, message: "COO priorities rebuilt." };
  });
}

async function updateApprovalItem(id = "", action = "", patch = {}) {
  return serializeStateMutation(async () => {
    const state = await store.readState();
    const approval = (state.approvalQueue || analyzeOperations(state).approvalQueue || []).find((item) => item.id === id);
    if (!approval) throw new Error("Approval item not found.");
    let next = { ...state };
    if (approval.type === "post") {
      const currentPost = (state.posts || []).find((post) => post.id === approval.sourceId) || {};
      if (action === "approve") {
        // Guidelines hard-fail gate (§2 voice, §3 dignity): a violating post can be edited
        // or culled, but it can never be approved.
        const guidelinesGate = socialGuidelinesGate(currentPost);
        if (!guidelinesGate.passed) {
          throw new Error(`Guidelines hard fail - cannot approve "${currentPost.title || approval.sourceId}": ${guidelinesGate.hardFails.map((item) => item.detail).join(" | ")}`);
        }
      }
      const previousApprovalState = {
        status: currentPost.status || "",
        approvalStatus: currentPost.approvalStatus || "",
        copyReviewed: Boolean(currentPost.copyReviewed),
        publishErrorSummary: currentPost.publishErrorSummary || "",
        updatedAt: currentPost.updatedAt || ""
      };
      const statusPatch = action === "approve"
        ? { status: "approved", copyReviewed: true, copyReviewedAt: new Date().toISOString(), approvalStatus: "approved" }
        : action === "block"
          ? { status: "blocked_channel_not_connected", publishErrorSummary: patch.reason || "Blocked by operator.", approvalStatus: "blocked" }
        : action === "send-to-queue"
            ? { status: "needs_review", approvalStatus: "needs_review", nextBestAction: "Review in Queue" }
            : { ...patch, approvalStatus: "edited" };
      next.posts = (state.posts || []).map((post) => post.id === approval.sourceId ? {
        ...post,
        ...statusPatch,
        previousApprovalState,
        approvalHistory: [
          { action, previousStatus: previousApprovalState.status, at: new Date().toISOString() },
          ...(post.approvalHistory || [])
        ].slice(0, 20),
        updatedAt: new Date().toISOString()
      } : post);
    }
    next = analyzeOperations(next);
    await writeChangedCollections(state, next);
    return { state: next, message: action === "approve" ? "Approved." : action === "block" ? "Blocked." : "Updated." };
  });
}

async function updateApprovalItems(ids = [], action = "", patch = {}) {
  return serializeStateMutation(async () => {
    const state = await store.readState();
    const analyzed = analyzeOperations(state);
    const selectedIds = new Set(Array.isArray(ids) ? ids : []);
    if (!selectedIds.size) throw new Error("Select at least one approval item.");
    const approvals = (analyzed.approvalQueue || []).filter((item) => selectedIds.has(item.id));
    if (!approvals.length) throw new Error("No matching approval items found.");
    const now = new Date().toISOString();
    const postPatches = new Map();
    const reportPatches = new Map();
    const guidelinesBlocked = [];
    for (const approval of approvals) {
      if (approval.type === "post") {
        const currentPost = (state.posts || []).find((post) => post.id === approval.sourceId) || {};
        if (action === "approve") {
          // Guidelines hard-fail gate (§2 voice, §3 dignity): failing posts are skipped,
          // the rest of the batch still approves, and the blocks are reported back.
          const guidelinesGate = socialGuidelinesGate(currentPost);
          if (!guidelinesGate.passed) {
            guidelinesBlocked.push(`"${currentPost.title || approval.sourceId}": ${guidelinesGate.hardFails.map((item) => item.detail).join(" | ")}`);
            continue;
          }
        }
        const previousApprovalState = {
          status: currentPost.status || "",
          approvalStatus: currentPost.approvalStatus || "",
          copyReviewed: Boolean(currentPost.copyReviewed),
          publishErrorSummary: currentPost.publishErrorSummary || "",
          updatedAt: currentPost.updatedAt || ""
        };
        const statusPatch = action === "approve"
          ? { status: "approved", copyReviewed: true, copyReviewedAt: now, approvalStatus: "approved", nextBestAction: "Check publish setup" }
          : action === "block"
            ? { status: "blocked_channel_not_connected", publishErrorSummary: patch.reason || "Blocked by operator.", approvalStatus: "blocked", nextBestAction: "Fix blocker" }
            : action === "send-to-queue"
              ? { status: "needs_review", approvalStatus: "needs_review", nextBestAction: "Review in Queue" }
              : action === "archive"
            ? { status: "archived", approvalStatus: "archived", nextBestAction: "Archived" }
            : {};
        postPatches.set(approval.sourceId, { ...statusPatch, previousApprovalState, updatedAt: now });
      }
      if (approval.type === "report") {
        const statusPatch = action === "approve"
          ? { status: "approved", approvedAt: now }
          : action === "archive"
            ? { status: "archived", archivedAt: now }
            : action === "block"
              ? { status: "blocked", blockedReason: patch.reason || "Blocked by operator." }
              : { status: "needs_review" };
        reportPatches.set(approval.sourceId, statusPatch);
      }
    }
    const next = analyzeOperations({
      ...state,
      posts: (state.posts || []).map((post) => postPatches.has(post.id) ? {
        ...post,
        ...postPatches.get(post.id),
        approvalHistory: [
          { action, previousStatus: post.status || "", at: now },
          ...(post.approvalHistory || [])
        ].slice(0, 20)
      } : post),
      reports: (state.reports || []).map((report) => reportPatches.has(report.id) ? { ...report, ...reportPatches.get(report.id) } : report),
      activityEvents: [
        {
          id: `activity-approval-batch-${crypto.randomUUID().slice(0, 8)}`,
          eventType: "Approval batch updated",
          title: `${approvals.length - guidelinesBlocked.length} approval item(s) ${action.replaceAll("-", " ")}${guidelinesBlocked.length ? `, ${guidelinesBlocked.length} blocked by guidelines` : ""}`,
          relatedObjectType: "approval_queue",
          relatedObjectId: "batch",
          createdAt: now
        },
        ...(state.activityEvents || [])
      ].slice(0, 500)
    });
    await writeChangedCollections(state, next);
    const updatedCount = approvals.length - guidelinesBlocked.length;
    const message = guidelinesBlocked.length
      ? `${updatedCount} approval item(s) updated. ${guidelinesBlocked.length} blocked by guidelines hard fails: ${guidelinesBlocked.join(" || ")}`
      : `${approvals.length} approval item(s) updated.`;
    return { state: next, updated: updatedCount, guidelinesBlocked, message };
  });
}

function ideaFromPost(post = {}) {
  return {
    id: post.contentBankIdeaId || `idea-from-${post.id}`,
    title: post.title || post.hook || "Untitled draft",
    rawIdea: post.body || post.hook || "",
    bucket: post.contentBucket || "LegalEase Growth",
    audience: post.audience || "partners",
    platforms: [post.platform || "linkedin"],
    campaign: post.campaign || "",
    cta: post.cta || "Learn more",
    creativeDirection: post.creativeBrief || post.imageBrief || "Clean LegalEase editorial creative.",
    usesWilma: post.speaker === "wilma" ? "yes" : "optional",
    complianceRisk: post.complianceRisk || "low",
    priority: post.priority || "medium"
  };
}

async function regenerateAIDraftForPost(postId = "") {
  return serializeStateMutation(async () => {
    const state = await store.readState();
    const post = (state.posts || []).find((item) => item.id === postId);
    if (!post) throw new Error("Post not found.");
    if (String(post.status || "").toLowerCase() !== "approved" || !post.finalPreviewConfirmed) {
      throw new Error("A post must be approved and its final preview confirmed before public asset promotion.");
    }
    const idea = (state.contentBank || []).find((item) => item.id === post.contentBankIdeaId) || ideaFromPost(post);
    let nextPost;
    try {
      nextPost = await draftPostFromIdeaWithAI(idea, post.platform || "linkedin");
    } catch (error) {
      nextPost = {
        ...draftPostFromIdea(idea, post.platform || "linkedin"),
        generationMode: "local_fallback_after_ai_failure",
        aiDraftStatus: "fallback",
        aiDraftError: safeShortError(error.message),
        nextBestAction: idea.complianceRisk === "high" ? "Review local fallback and compliance risk" : "Review local fallback draft"
      };
    }
    const updatedPost = {
      ...post,
      hook: nextPost.hook,
      body: nextPost.body,
      cta: nextPost.cta,
      hashtags: nextPost.hashtags,
      creativeBrief: nextPost.creativeBrief,
      complianceNotes: nextPost.complianceNotes,
      complianceRewrite: nextPost.complianceRewrite || "",
      originalAIDraftBody: nextPost.originalAIDraftBody || "",
      recommendedPostingWindow: nextPost.recommendedPostingWindow,
      generationMode: nextPost.generationMode,
      aiDraftStatus: nextPost.aiDraftStatus,
      aiDraftModel: nextPost.aiDraftModel || "",
      aiDraftGeneratedAt: nextPost.aiDraftGeneratedAt || new Date().toISOString(),
      aiDraftPromptVersion: nextPost.aiDraftPromptVersion || "legalese-content-bank-ai-draft-v1",
      aiDraftError: nextPost.aiDraftError || "",
      copyReviewed: false,
      approvalStatus: "needs_review",
      status: "needs_review",
      nextBestAction: nextPost.nextBestAction || "Review AI draft",
      updatedAt: new Date().toISOString()
    };
    const nextState = analyzeOperations({
      ...state,
      posts: (state.posts || []).map((item) => item.id === post.id ? updatedPost : item),
      activityEvents: [
        {
          id: `activity-ai-draft-${crypto.randomUUID().slice(0, 8)}`,
          eventType: updatedPost.aiDraftStatus === "fallback" ? "AI draft fallback used" : "AI draft regenerated",
          title: updatedPost.title,
          relatedObjectType: "post",
          relatedObjectId: updatedPost.id,
          createdAt: updatedPost.updatedAt
        },
        ...(state.activityEvents || [])
      ].slice(0, 500)
    });
    await writeChangedCollections(state, nextState);
    return {
      state: nextState,
      post: updatedPost,
      fallback: updatedPost.aiDraftStatus === "fallback",
      message: updatedPost.aiDraftStatus === "fallback" ? "AI failed; local fallback draft created." : "AI draft regenerated."
    };
  });
}

function overlayTextForPostServer(post) {
  if (post.overlayMode === "none") {
    return { mode: "none", kicker: "", headline: "", support: "" };
  }
  const supportLine = String(post.cta || post.body || "")
    .replace(/\n/g, ". ")
    .split(".")
    .filter(Boolean)[0] || "Make second chances easier to understand.";
  return {
    mode: "text",
    kicker: post.overlayKicker || post.contentBucket || post.contentFormat || "LegalEase",
    headline: post.overlayHeadline || post.wilmaImageWorkflow?.overlayText || post.hook || post.title,
    support: post.overlaySupport || supportLine
  };
}

function imageForPostFromState(state, postId) {
  return (state.postImages || [])
    .filter((image) => image.postId === postId)
    .sort((a, b) => (b.versionNumber || 0) - (a.versionNumber || 0))[0] || null;
}

function sourceImageForFinalFromState(state, postId) {
  const images = (state.postImages || [])
    .filter((image) => image.postId === postId)
    .sort((a, b) => (b.versionNumber || 0) - (a.versionNumber || 0));
  return images.find((image) =>
    image.generationStatus === "generated" &&
    image.imageUrl &&
    image.generationMode !== "final_composited_image" &&
    image.imageStatus !== "final_composited" &&
    !image.finalImageReady
  ) || images[0] || null;
}

function finalImageIsReady(image) {
  return Boolean(
    image &&
      image.generationStatus === "generated" &&
      (image.finalImageReady ||
        image.textRenderingMode === "baked_overlay" ||
        image.textRenderingMode === "no_text_overlay" ||
        image.assetBundleUsed?.finalImage?.ready)
  );
}

function finalPngAbsolutePathForPost(post = {}, image = {}) {
  const candidates = [
    post.localFinalPngPath,
    post.finalPngPath,
    post.finalExportKit?.localFinalPngPath,
    post.finalExportKit?.finalPngPath,
    image.localFinalPngPath,
    image.finalPngPath,
    image.assetBundleUsed?.finalImage?.localPath
  ].filter(Boolean);
  const root = path.resolve(process.cwd(), "data/exports/final-pngs");
  for (const candidate of candidates) {
    const raw = String(candidate || "").trim();
    const absolute = path.isAbsolute(raw)
      ? path.resolve(raw)
      : path.resolve(process.cwd(), raw.replace(/^\/+/, ""));
    const relative = path.relative(root, absolute);
    if (!relative || relative.startsWith("..") || path.isAbsolute(relative)) continue;
    if (!/\.(png)$/i.test(absolute)) continue;
    if (existsSync(absolute)) return absolute;
  }
  return "";
}

function storageObjectPathForFinalPng(localPath = "", postId = "post") {
  const safeName = safeDownloadFilename(path.basename(localPath || "final.png"));
  return `social-posts/${safePackageSegment(postId || "post")}/${safeName}`;
}

async function uploadPostFinalPngToStorage(postId = "") {
  return serializeStateMutation(async () => {
    const state = await store.readState();
    const post = (state.posts || []).find((item) => item.id === postId);
    if (!post) throw new Error("Post not found.");
    const image = imageForPostFromState(state, postId);
    if (!finalImageIsReady(image)) throw new Error("Create Final PNG before uploading a public image.");
    const localPath = finalPngAbsolutePathForPost(post, image);
    if (!localPath) throw new Error("Final PNG file is missing under data/exports/final-pngs/.");
    const storage = supabaseStorageStatus();
    if (!storage.configured) throw new Error(storage.message);
    const body = await readFile(localPath);
    const objectPath = storageObjectPathForFinalPng(localPath, postId);
    await supabaseStorageFetch(`object/${encodeURIComponent(storage.bucket)}/${objectPath}`, {
      method: "PUT",
      body,
      contentType: "image/png",
      upsert: true
    });
    const now = new Date().toISOString();
    const publicImageUrl = supabaseStorageObjectPublicUrl(objectPath);
    if (!validatePublicSocialImageUrl(publicImageUrl)) {
      throw new Error("Public image URL must be HTTPS and externally reachable before Meta publishing can use it.");
    }
    const updatedImage = {
      ...image,
      localFinalPngPath: localPath,
      publicImageUrl,
      public_image_url: publicImageUrl,
      final_image_path: localPath,
      public_image_status: "uploaded",
      public_image_error: "",
      publicImageUploadedAt: now,
      public_image_uploaded_at: now,
      supabaseStorageBucket: storage.bucket,
      public_image_storage_bucket: storage.bucket,
      supabaseStorageObjectPath: objectPath,
      public_image_storage_path: objectPath,
      assetBundleUsed: {
        ...(image.assetBundleUsed || {}),
        finalImage: {
          ...(image.assetBundleUsed?.finalImage || {}),
          ready: true,
          localPath,
          publicImageUrl,
          public_image_url: publicImageUrl,
          storageBucket: storage.bucket,
          public_image_storage_bucket: storage.bucket,
          storageObjectPath: objectPath,
          public_image_storage_path: objectPath,
          uploadedAt: now
        }
      },
      updatedAt: now
    };
    const updatedPost = {
      ...post,
      localFinalPngPath: localPath,
      publicImageUrl,
      public_image_url: publicImageUrl,
      final_image_path: localPath,
      public_image_status: "uploaded",
      public_image_error: "",
      publicImageUploadedAt: now,
      public_image_uploaded_at: now,
      supabaseStorageBucket: storage.bucket,
      public_image_storage_bucket: storage.bucket,
      supabaseStorageObjectPath: objectPath,
      public_image_storage_path: objectPath,
      finalExportKit: {
        ...(post.finalExportKit || {}),
        localFinalPngPath: localPath,
        publicImageUrl,
        public_image_url: publicImageUrl,
        publicImageUploadedAt: now,
        public_image_uploaded_at: now,
        storageBucket: storage.bucket,
        public_image_storage_bucket: storage.bucket,
        storageObjectPath: objectPath,
        public_image_storage_path: objectPath
      },
      updatedAt: now
    };
    const nextState = analyzeOperations({
      ...state,
      posts: (state.posts || []).map((item) => item.id === postId ? updatedPost : item),
      postImages: (state.postImages || []).map((item) => item.id === image.id ? updatedImage : item),
      activityEvents: [{
        id: `activity-public-image-${crypto.randomUUID().slice(0, 8)}`,
        eventType: "Public image uploaded",
        title: post.title || post.id,
        relatedObjectType: "post",
        relatedObjectId: post.id,
        createdAt: now
      }, ...(state.activityEvents || [])].slice(0, 500)
    });
    await writeChangedCollections(state, nextState);
    return {
      state: nextState,
      post: updatedPost,
      image: updatedImage,
      publicImageUrl,
      localFinalPngPath: localPath,
      message: "Public image uploaded."
    };
  });
}

async function batchUploadPublicImages(ids = []) {
  const targets = Array.from(new Set((ids || []).map((id) => String(id || "").trim()).filter(Boolean)));
  if (!targets.length) throw new Error("Select at least one post with a final PNG.");
  const results = [];
  let latestState = null;
  for (const id of targets) {
    try {
      const result = await uploadPostFinalPngToStorage(id);
      latestState = result.state;
      results.push({ postId: id, ok: true, publicImageUrl: result.publicImageUrl });
    } catch (error) {
      results.push({ postId: id, ok: false, error: safeSupabaseError(error) });
    }
  }
  latestState ||= await store.readState();
  const uploaded = results.filter((item) => item.ok).length;
  const failed = results.length - uploaded;
  return {
    state: latestState,
    results,
    uploaded,
    failed,
    message: failed
      ? `${uploaded} uploaded, ${failed} blocked.`
      : `${uploaded} public image${uploaded === 1 ? "" : "s"} uploaded.`
  };
}

function wilmaPoseAssets(state = {}) {
  const mapped = poseMappingsForState(state).map((mapping) => {
    const asset = localAssetById(state, mapping.linkedAssetId);
    return {
      id: mapping.id,
      name: mapping.label,
      slug: slugify(mapping.label),
      assetType: "wilma_reference",
      fileUrl: asset?.filePath || "",
      mimeType: "image/png",
      fileSize: asset?.fileSize || 0,
      width: 0,
      height: 0,
      approved: true,
      isDefault: mapping.poseRefNumber === 1,
      tags: ["wilma", "pose-library", "local-pose-mapping", mapping.expressionCategory],
      version: 1,
      localAssetId: asset?.id || "",
      fallbackPlaceholder: mapping.fallbackPlaceholder
    };
  });
  const legacy = (state.brandAssets || []).filter((asset) => (asset.tags || []).includes("pose-library"));
  const seen = new Set(mapped.map((asset) => asset.id));
  return [...mapped, ...legacy.filter((asset) => !seen.has(asset.id))];
}

function wilmaPoseReferenceCount(state = {}) {
  return wilmaPoseAssets(state).length;
}

function wilmaPoseAssetById(state = {}, id = "") {
  // No catch-all: an unknown pose id must surface as missing at the caller, never silently
  // become pose 1 (the old `|| poses[0]` swapped in the primary stance for any typo'd or
  // legacy id, e.g. intake's "pose-03" vs the library's "wilma-pose-03").
  const poses = wilmaPoseAssets(state);
  return poses.find((asset) => asset.id === id) || null;
}

function words(value = "") {
  return String(value || "").trim().split(/\s+/).filter(Boolean);
}

function wilmaOverlaySafetyReport(value = "") {
  const text = String(value || "").trim();
  const normalized = text.toLowerCase();
  const wordCount = words(text).length;
  const guaranteePattern = /\b(guarantee|guaranteed|will\s+(clear|erase|remove|fix|qualify|win|approve)|100%|assured|promise|promised)\b/i;
  const eligibilityPattern = /\b(you\s+(are|re|'re)\s+eligible|everyone\s+qualifies|automatically\s+qualif(?:y|ies)|always\s+eligible|definitely\s+eligible|qualify\s+for\s+expungement)\b/i;
  return {
    overlayText: text,
    wordCount,
    overlayLengthOk: wordCount > 0 && wordCount <= 8,
    empty: !text,
    hasLegalGuaranteeLanguage: guaranteePattern.test(text),
    hasEligibilityPromiseLanguage: eligibilityPattern.test(text),
    bannedVisualElementsOk: wilmaBrandSafeRules.length > 0,
    mobileReadable: wordCount > 0 && wordCount <= 8,
    normalized
  };
}

function wilmaWorkflowBlockers({ post = {}, image = null, workflow = {}, requireFinal = false } = {}) {
  const overlayText = workflow.overlayText || shortOverlayHeadline(post);
  const safety = wilmaOverlaySafetyReport(overlayText);
  const blockers = [];
  if (!post.copyReviewed) blockers.push("Copy still needs review.");
  if (!workflow.imagePrompt && !post.imagePrompt && !image?.imagePrompt) blockers.push("Image prompt still needs to be generated.");
  if (!image || image.generationStatus !== "generated") blockers.push("Image has not been marked generated.");
  if (!post.overlayConfirmed) blockers.push("Overlay has not been confirmed.");
  if (requireFinal && safety.empty) blockers.push("Overlay text is empty.");
  if (requireFinal && !finalImageIsReady(image)) blockers.push("Final PNG has not been marked ready.");
  if (!workflow.platformFormatSize) blockers.push("Platform size has not been confirmed.");
  if (!composePublishText(post)) blockers.push("Manual posting copy is not ready.");
  return { blockers, safety };
}

function shortOverlayHeadline(post) {
  const overlay = overlayTextForPostServer(post);
  if (overlay.mode === "none") return "";
  const headlineWords = words(overlay.headline || post.hook || post.title);
  return headlineWords.slice(0, 8).join(" ");
}

function wilmaPlatformFormatSize(platform = "linkedin") {
  const ratio = narrativeInfrastructurePreset.recommendedAspectRatios[platform] || "1:1";
  if (ratio === "4:5") return "4:5 vertical PNG, 1080 x 1350 preview target";
  return "1:1 square PNG, 1200 x 1200 preview target";
}

function slugify(value = "") {
  return String(value || "")
    .toLowerCase()
    .replace(/&/g, " and ")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 72) || "item";
}

function localDateSlug(value = "") {
  const date = value ? new Date(value) : new Date();
  if (Number.isFinite(date.getTime())) return date.toISOString().slice(0, 10);
  return new Date().toISOString().slice(0, 10);
}

function exportFormatForPost(post = {}, overrideId = "") {
  const targetChannels = (post.targetChannels?.length ? post.targetChannels : [post.platform]).filter(Boolean);
  const platform = targetChannels[0] || post.platform || "linkedin";
  if (overrideId) {
    const exact = finalExportPlatformFormats.find((format) => format.id === overrideId);
    if (exact) return exact;
  }
  if (platform === "instagram") return finalExportPlatformFormats.find((format) => format.id === "instagram-square");
  if (platform === "linkedin") return finalExportPlatformFormats.find((format) => format.id === "linkedin-square");
  if (platform === "x") return finalExportPlatformFormats.find((format) => format.id === "x-twitter-landscape");
  return finalExportPlatformFormats.find((format) => format.id === "linkedin-square");
}

function altTextForExport(post = {}, workflow = {}) {
  const bucket = workflow.visualBucket || post.wilmaVisualBucket || post.contentBucket || "LegalEase social graphic";
  const expression = workflow.wilmaExpression || post.wilmaExpression || "helpful";
  const overlay = workflow.overlayText || shortOverlayHeadline(post);
  return [
    `LegalEase social graphic for ${bucket}.`,
    `Wilma appears in a ${String(expression).toLowerCase()} pose.`,
    overlay ? `Overlay text reads: ${overlay}.` : "",
    "Educational content only; not legal advice."
  ].filter(Boolean).join(" ");
}

function buildFinalExportKit(post = {}, image = null, workflow = {}) {
  const format = exportFormatForPost(post, post.finalExportKit?.platformFormatId || workflow.platformFormatId);
  const bucket = workflow.visualBucket || post.wilmaVisualBucket || image?.visualBucket || post.contentBucket || "LegalEase POV";
  const date = localDateSlug();
  const filename = `legalease-${slugify(bucket)}-${slugify(format.id)}-${date}-${slugify(post.id || "post")}.png`;
  const caption = composePublishText(post);
  const hashtags = (post.hashtags || []).join(" ");
  const altText = post.finalExportKit?.altText || altTextForExport(post, workflow);
  const postingNotes = post.finalExportKit?.postingNotes || post.operatorNotes || "Manual posting only. Confirm final visual and caption before uploading.";
  const finalReady = Boolean(finalImageIsReady(image) && post.imageFinalized);
  const finalImageUrl = finalImageIsReady(image) ? image?.imageUrl || "" : "";
  const finalMeta = image?.assetBundleUsed?.finalImage || {};
  const localPath = finalMeta.localPath || image?.finalPngPath || "";
  const fileSize = Number(finalMeta.fileSize || image?.finalPngFileSize || 0);
  const generatedAt = finalMeta.createdAt || image?.finalPngGeneratedAt || "";
  return {
    status: finalReady ? "ready" : "blocked",
    platformFormatId: format.id,
    platformFormatLabel: format.label,
    platform: format.platform,
    width: format.width,
    height: format.height,
    dimensions: `${format.width}x${format.height}`,
    contentBucket: bucket,
    wilmaExpression: workflow.wilmaExpression || post.wilmaExpression || image?.wilmaExpression || "",
    wilmaPoseReference: workflow.wilmaPoseReferenceName || image?.wilmaPoseReferenceName || post.wilmaPoseReferenceId || "",
    wilmaPoseReferenceId: workflow.wilmaPoseReferenceId || image?.wilmaPoseReferenceId || post.wilmaPoseReferenceId || "",
    overlayText: workflow.overlayText || shortOverlayHeadline(post),
    caption,
    hashtags,
    altText,
    postingNotes,
    exportFilename: filename,
    imageUrl: image?.imageUrl || "",
    finalImageUrl,
    finalPngUrl: finalImageUrl,
    finalPngPath: localPath,
    finalPngFileSize: fileSize,
    finalPngGeneratedAt: generatedAt,
    downloadUrl: finalImageUrl ? `/api/posts/${encodeURIComponent(post.id || "post")}/final-png` : "",
    finalPngReady: finalReady,
    livePostingDisabled: true,
    operatorMustPostManually: true,
    manualPostingKitReady: Boolean(post.finalExportKit?.manualPostingKitReady),
    updatedAt: new Date().toISOString()
  };
}

function safeDownloadFilename(value = "legalease-final.png") {
  const clean = String(value || "legalease-final.png")
    .replace(/[/\\?%*:|"<>]/g, "-")
    .replace(/\s+/g, "-")
    .replace(/-+/g, "-")
    .replace(/^-+|-+$/g, "");
  return clean.toLowerCase().endsWith(".png") ? clean : `${clean || "legalease-final"}.png`;
}

function finalPngExportRelativePath(filename = "") {
  return `data/exports/final-pngs/${safeDownloadFilename(filename)}`;
}

function safePackageSegment(value = "post") {
  return slugify(value).replace(/[^a-z0-9-]/g, "").slice(0, 90) || "post";
}

function postingPackageRelativeDir(postId = "", dateSlug = localDateSlug()) {
  return `data/exports/posting-kits/${safePackageSegment(postId)}-${dateSlug}`;
}

function postingPackageZipFilename(postId = "post") {
  return `${safePackageSegment(postId)}-posting-kit.zip`;
}

function safeExportFilePath(relativePath = "", allowedPrefix = "data/exports/final-pngs/") {
  const clean = String(relativePath || "").replace(/^\/+/, "");
  const normalized = path.posix.normalize(clean).replace(/^\/+/, "");
  if (!normalized.startsWith(allowedPrefix) || normalized.includes("../")) return "";
  const fullPath = path.resolve(process.cwd(), normalized);
  const allowedRoot = path.resolve(process.cwd(), allowedPrefix);
  if (!fullPath.startsWith(allowedRoot)) return "";
  return fullPath;
}

function safePostingPackagePath(relativePath = "") {
  const clean = String(relativePath || "").replace(/^\/+/, "");
  const normalized = path.posix.normalize(clean).replace(/^\/+/, "");
  if (!normalized.startsWith("data/exports/posting-kits/") || normalized.includes("../")) return "";
  const fullPath = path.resolve(process.cwd(), normalized);
  const allowedRoot = path.resolve(process.cwd(), "data/exports/posting-kits");
  if (!fullPath.startsWith(allowedRoot)) return "";
  return fullPath;
}

const crcTable = Array.from({ length: 256 }, (_, index) => {
  let value = index;
  for (let bit = 0; bit < 8; bit += 1) {
    value = value & 1 ? 0xedb88320 ^ (value >>> 1) : value >>> 1;
  }
  return value >>> 0;
});

function crc32(buffer) {
  let crc = 0xffffffff;
  for (const byte of buffer) {
    crc = crcTable[(crc ^ byte) & 0xff] ^ (crc >>> 8);
  }
  return (crc ^ 0xffffffff) >>> 0;
}

function dosDateTime(date = new Date()) {
  const year = Math.max(1980, date.getFullYear());
  const dosTime = (date.getHours() << 11) | (date.getMinutes() << 5) | Math.floor(date.getSeconds() / 2);
  const dosDate = ((year - 1980) << 9) | ((date.getMonth() + 1) << 5) | date.getDate();
  return { dosDate, dosTime };
}

function zipBuffers(entries = []) {
  const now = dosDateTime();
  const locals = [];
  const central = [];
  let offset = 0;

  for (const entry of entries) {
    const name = String(entry.name || "").replace(/^\/+/, "");
    if (!name || name.includes("..") || name.includes("/") || name.includes("\\")) {
      throw new Error("Unsafe zip entry name.");
    }
    const nameBuffer = Buffer.from(name);
    const body = Buffer.isBuffer(entry.data) ? entry.data : Buffer.from(String(entry.data || ""), "utf8");
    const checksum = crc32(body);
    const localHeader = Buffer.alloc(30);
    localHeader.writeUInt32LE(0x04034b50, 0);
    localHeader.writeUInt16LE(20, 4);
    localHeader.writeUInt16LE(0, 6);
    localHeader.writeUInt16LE(0, 8);
    localHeader.writeUInt16LE(now.dosTime, 10);
    localHeader.writeUInt16LE(now.dosDate, 12);
    localHeader.writeUInt32LE(checksum, 14);
    localHeader.writeUInt32LE(body.length, 18);
    localHeader.writeUInt32LE(body.length, 22);
    localHeader.writeUInt16LE(nameBuffer.length, 26);
    localHeader.writeUInt16LE(0, 28);
    locals.push(localHeader, nameBuffer, body);

    const centralHeader = Buffer.alloc(46);
    centralHeader.writeUInt32LE(0x02014b50, 0);
    centralHeader.writeUInt16LE(20, 4);
    centralHeader.writeUInt16LE(20, 6);
    centralHeader.writeUInt16LE(0, 8);
    centralHeader.writeUInt16LE(0, 10);
    centralHeader.writeUInt16LE(now.dosTime, 12);
    centralHeader.writeUInt16LE(now.dosDate, 14);
    centralHeader.writeUInt32LE(checksum, 16);
    centralHeader.writeUInt32LE(body.length, 20);
    centralHeader.writeUInt32LE(body.length, 24);
    centralHeader.writeUInt16LE(nameBuffer.length, 28);
    centralHeader.writeUInt16LE(0, 30);
    centralHeader.writeUInt16LE(0, 32);
    centralHeader.writeUInt16LE(0, 34);
    centralHeader.writeUInt16LE(0, 36);
    centralHeader.writeUInt32LE(0, 38);
    centralHeader.writeUInt32LE(offset, 42);
    central.push(centralHeader, nameBuffer);
    offset += localHeader.length + nameBuffer.length + body.length;
  }

  const centralSize = central.reduce((sum, part) => sum + part.length, 0);
  const end = Buffer.alloc(22);
  end.writeUInt32LE(0x06054b50, 0);
  end.writeUInt16LE(0, 4);
  end.writeUInt16LE(0, 6);
  end.writeUInt16LE(entries.length, 8);
  end.writeUInt16LE(entries.length, 10);
  end.writeUInt32LE(centralSize, 12);
  end.writeUInt32LE(offset, 16);
  end.writeUInt16LE(0, 20);
  return Buffer.concat([...locals, ...central, end]);
}

const postingPackageZipFiles = ["final.png", "caption.txt", "hashtags.txt", "alt-text.txt", "posting-notes.txt", "metadata.json"];

async function writePostingPackageZip(packageRelativePath = "", postId = "post") {
  const packagePath = safePostingPackagePath(packageRelativePath);
  if (!packagePath) throw new Error("Posting package path is unsafe.");
  const entries = [];
  for (const filename of postingPackageZipFiles) {
    const filePath = path.join(packagePath, filename);
    if (!(await pathExists(filePath))) throw new Error(`Posting package is incomplete: ${filename} is missing.`);
    entries.push({ name: filename, data: await readFile(filePath) });
  }
  const zipFilename = postingPackageZipFilename(postId);
  const zipPath = path.join(packagePath, zipFilename);
  const zipBuffer = zipBuffers(entries);
  await writeFile(zipPath, zipBuffer);
  const zipRelativePath = `${packageRelativePath.replace(/\/+$/, "")}/${zipFilename}`;
  return {
    zipFilename,
    zipPath,
    zipRelativePath,
    zipDownloadUrl: `/api/posts/${encodeURIComponent(postId)}/posting-package-zip`,
    zipFileSize: zipBuffer.length,
    zippedAt: new Date().toISOString()
  };
}

async function ensurePostingPackageZip(postId = "") {
  const state = await store.readState();
  const post = state.posts.find((item) => item.id === postId);
  if (!post) throw new Error("Post not found.");
  const pkg = post.postingPackage || {};
  const relativePath = pkg.relativePath || String(post.postingPackagePath || "").replace(process.cwd() + "/", "");
  if (!relativePath) throw new Error("Export a posting package before downloading the zip.");
  const zipRecord = await writePostingPackageZip(relativePath, post.id);
  const nextPackage = {
    ...pkg,
    ...zipRecord,
    generated: true,
    relativePath,
    fileList: pkg.fileList || post.postingPackageFileList || postingPackageZipFiles
  };
  const nextState = await store.updatePost(post.id, {
    postingPackageZipGenerated: true,
    postingPackageZipPath: zipRecord.zipPath,
    postingPackageZipDownloadUrl: zipRecord.zipDownloadUrl,
    postingPackageZipFileSize: zipRecord.zipFileSize,
    postingPackageZipGeneratedAt: zipRecord.zippedAt,
    postingPackage: nextPackage,
    finalExportKit: {
      ...(post.finalExportKit || {}),
      postingPackage: nextPackage,
      postingPackageZipGenerated: true
    }
  });
  return { state: nextState, post, packageZip: zipRecord };
}

function defaultWilmaVisualBucket(post = {}) {
  const text = [post.contentFormat, post.contentBucket, post.title, post.hook].join(" ").toLowerCase();
  if (/ask|question|wilma/.test(text)) return "Ask Wilma";
  if (/translate|translation|plain english|explain/.test(text)) return "Wilma Translation";
  if (/myth|misconception|check/.test(text)) return "Wilma Myth Check";
  if (/implementation|operator|workflow|system/.test(text)) return "The Implementation Layer";
  if (/record|clearance|work|job|workforce|employment/.test(text)) return "Record Clearance & Work";
  return "LegalEase POV";
}

function defaultWilmaExpression(post = {}) {
  const text = [post.contentFormat, post.contentBucket, post.title, post.hook, post.body].join(" ").toLowerCase();
  if (/myth|misconception|wrong|not true/.test(text)) return "Myth-checking";
  if (/work|record|clearance|employment/.test(text)) return "Determined";
  if (/how|explain|translate|plain english/.test(text)) return "Explaining";
  if (/win|celebrate|progress|done|ready/.test(text)) return "Celebratory";
  if (/hard|confusing|stress|fear|uncertain/.test(text)) return "Empathetic";
  if (/trust|safe|review|human/.test(text)) return "Reassuring";
  return post.speaker === "wilma" ? "Helpful" : "Serious but warm";
}

function buildWilmaImageWorkflow(state = {}, post = {}, overrides = {}) {
  const visualBucket = wilmaVisualBuckets.includes(overrides.visualBucket)
    ? overrides.visualBucket
    : (wilmaVisualBuckets.includes(post.wilmaVisualBucket) ? post.wilmaVisualBucket : defaultWilmaVisualBucket(post));
  const wilmaExpression = wilmaExpressions.includes(overrides.wilmaExpression || overrides.expression)
    ? (overrides.wilmaExpression || overrides.expression)
    : (wilmaExpressions.includes(post.wilmaExpression) ? post.wilmaExpression : defaultWilmaExpression(post));
  const fallbackPoseId = wilmaExpressionPoseMap[wilmaExpression] || "wilma-pose-02";
  const explicitPoseId = String(overrides.wilmaPoseReferenceId || overrides.poseReferenceId || post.wilmaPoseReferenceId || "");
  const requestedPoseId = explicitPoseId || fallbackPoseId;
  // No silent substitution: an explicitly requested pose that isn't in the library stays
  // missing — the expression fallback only fills in when nothing was requested, and a
  // missing pose is named as missing rather than quietly becoming another pose.
  const pose = wilmaPoseAssetById(state, requestedPoseId) || (explicitPoseId ? null : wilmaPoseAssetById(state, fallbackPoseId));
  const poseReferenceId = pose?.id || requestedPoseId;
  const poseReferenceName = pose
    ? pose.name
    : `${requestedPoseId} — POSE MISSING: not in the pose library, no substitute used`;
  const linkedPoseAsset = localAssetById(state, overrides.wilmaAssetId || post.wilmaImageWorkflow?.wilmaAssetId || pose?.localAssetId || "") || linkedAssetForPose(state, poseReferenceId);
  const backgroundAsset = localAssetById(state, overrides.backgroundAssetId || post.wilmaImageWorkflow?.backgroundAssetId || "");
  const brandMarkAsset = localAssetById(state, overrides.brandMarkAssetId || post.wilmaImageWorkflow?.brandMarkAssetId || "");
  const overlayText = overrides.overlayText || shortOverlayHeadline(post) || "Make the next step clearer";
  const targetChannels = (post.targetChannels?.length ? post.targetChannels : [post.platform]).filter(Boolean);
  const platform = targetChannels[0] || post.platform || "linkedin";
  const formatSize = wilmaPlatformFormatSize(platform);
  const postTopic = post.hook || post.title || "LegalEase social post";
  const audience = audienceLabels[post.audience] || post.audience || "People trying to understand record clearance and second-chance pathways";
  const backgroundStyle = visualBucket === "LegalEase POV"
    ? "Clean branded editorial background with subtle civic texture and space for mobile-readable overlay text."
    : "Warm branded social background with Wilma as the guide, clear negative space, and no panic imagery.";
  const colorPalette = "LegalEase legal blue, horizon orange, paper white, civic black, and infrastructure gray.";
  const lighting = "Soft studio lighting, polished but humane, with high contrast for mobile readability.";
  const composition = visualBucket === "The Implementation Layer"
    ? "Wilma or LegalEase branded visual anchored right, simple workflow cues left, overlay in safe area."
    : "Wilma centered or three-quarter view, expressive but calm, overlay text placed in a clear safe area.";
  const negativePrompt = wilmaBrandSafeRules.join("; ");
  const complianceNote = "Educational social graphic only. Avoid specific legal advice, outcome guarantees, eligibility promises, or implied attorney-client relationship.";
  const promptBuilderOutput = {
    platform,
    postTopic,
    audience,
    visualBucket,
    wilmaExpression,
    wilmaPoseReference: `${poseReferenceName} (${poseReferenceId})`,
    backgroundStyle,
    colorPalette,
    lighting,
    composition,
    overlayText,
    negativePrompt,
    complianceNote
  };
  const imagePrompt = [
    `Create a LegalEase social graphic for ${platformLabels[platform] || platform}.`,
    `Post topic: ${postTopic}`,
    `Audience: ${audience}.`,
    `Visual bucket: ${visualBucket}.`,
    `Wilma expression: ${wilmaExpression}.`,
    pose
      ? `Use Wilma pose reference ${poseReferenceName} (${poseReferenceId}) from the approved pose library.`
      : `Pose reference unavailable — ${poseReferenceName}. Do not invent or substitute a different pose; keep Wilma in a neutral stance matching the expression above.`,
    `Background style: ${backgroundStyle}`,
    `Palette: ${colorPalette}`,
    `Lighting: ${lighting}`,
    `Composition: ${composition}`,
    `Overlay text: "${overlayText}".`,
    `Compliance note: ${complianceNote}`
  ].join("\n");
  return {
    state: "Image Prompt Ready",
    visualBucket,
    wilmaExpression,
    wilmaPoseReferenceId: poseReferenceId,
    wilmaPoseReferenceName: poseReferenceName,
    wilmaPoseReferenceCount: wilmaPoseReferenceCount(state),
    wilmaAssetId: linkedPoseAsset?.id || "",
    wilmaAssetLabel: linkedPoseAsset?.label || "",
    backgroundAssetId: backgroundAsset?.id || "",
    backgroundAssetLabel: backgroundAsset?.label || "",
    brandMarkAssetId: brandMarkAsset?.id || "",
    brandMarkAssetLabel: brandMarkAsset?.label || "",
    platformFormatSize: formatSize,
    overlayText,
    imagePrompt,
    negativePrompt,
    promptBuilderOutput,
    safetyReview: wilmaOverlaySafetyReport(overlayText),
    brandSafeRules: wilmaBrandSafeRules,
    overlayRules: wilmaOverlayRules,
    exportChecklist: {
      copyReviewed: Boolean(post.copyReviewed),
      imageSelectedOrGenerated: false,
      overlayConfirmed: Boolean(post.overlayConfirmed),
      finalPngGenerated: false,
      watermarkOrBrandMarkAppliedIfSelected: true,
      platformSizeConfirmed: Boolean(formatSize),
      manualPostingCopyReady: Boolean(composePublishText(post))
    },
    updatedAt: new Date().toISOString()
  };
}

