let store;
try {
  store = createStore(initialState);
  assertProductionReadiness(process.env, { activeStorageBackend: store.kind });
} catch (error) {
  console.error(safeStartupError(error));
  process.exit(error?.exitCode || 78);
}
const sessionService = createSessionService({ store, env: process.env });
const auditService = createAuditService({ store });
let stateMutationQueue = Promise.resolve();

function serializeStateMutation(operation) {
  const next = stateMutationQueue.then(operation, operation);
  stateMutationQueue = next.catch(() => {});
  return next;
}

// Scoped-write conversion helper (Slice 4 tier 2). Every mutation in this codebase transforms
// state immutably (spread copies), so a collection changed exactly when its top-level reference
// changed. Writing only those keys turns a full-state write into a scoped one with zero
// hand-maintained key lists. ONLY safe for immutable transforms: an in-place mutation keeps the
// reference and would be silently dropped, so call sites are converted only after verifying the
// transform is spread-style. Falls back to a full-state write if nothing diffs but the objects
// differ (belt for an unnoticed in-place mutation upstream).
async function writeChangedCollections(before = {}, after = {}) {
  if (typeof store.writeChanges === "function") {
    await store.writeChanges(before, after);
    return after;
  }
  const patch = {};
  for (const key of Object.keys(after)) {
    if (after[key] !== before[key]) patch[key] = after[key];
  }
  if (Object.keys(patch).length === 0) {
    if (after !== before) await store.writeState(after);
    return after;
  }
  await store.writeCollections(patch);
  return after;
}

async function readJson(request) {
  return readBoundedJson(request, { limit: REQUEST_LIMITS.json });
}

async function readJsonWithRawBody(request) {
  const rawBody = await readBoundedBody(request, { limit: REQUEST_LIMITS.webhook });
  let payload;
  try { payload = rawBody.length ? JSON.parse(rawBody.toString("utf8")) : {}; }
  catch { const error = new Error("Request body must be valid JSON."); error.status = 400; throw error; }
  return { payload, rawBody };
}

async function readBuffer(request) {
  return readBoundedBody(request, { limit: REQUEST_LIMITS.image });
}

async function runAutonomyCycle({ executeAutomatic = true } = {}) {
  return serializeStateMutation(async () => {
    const current = await store.readState();
    const operated = analyzeOperations(current);
    const result = runAutonomyCycleOnState(operated, { executeAutomatic });
    const nextState = analyzeOperations(result.state);
    await writeChangedCollections(current, nextState);
    return { ...result, state: nextState };
  });
}

async function updateAutonomyAction(id = "", action = "", patch = {}) {
  return serializeStateMutation(async () => {
    const state = await store.readState();
    const report = buildAutonomyReport(analyzeOperations(state));
    const target = report.actions.find((item) => item.id === id);
    if (!target) throw new Error("Autonomy action not found.");
    if (target.decisionClass === "forbidden" && action !== "ignore") {
      throw new Error("Forbidden autonomy actions cannot be approved or executed.");
    }
    const now = new Date().toISOString();
    const status = action === "approve" ? "approved" : action === "ignore" ? "ignored" : action === "block" ? "blocked" : "pending";
    const updated = {
      ...target,
      ...patch,
      status,
      reviewedAt: ["approve", "ignore", "block"].includes(action) ? now : target.reviewedAt || "",
      updatedAt: now
    };
    const nextActions = [updated, ...report.actions.filter((item) => item.id !== id)].slice(0, 120);
    const audit = {
      id: "soc2-audit-autonomy-" + crypto.randomUUID().slice(0, 10),
      timestamp: now,
      actor: "local_operator",
      action: "autonomy action " + action,
      resourceType: "autonomy_action",
      resourceId: id,
      controlArea: target.category === "compliance" || target.category === "legal" ? "AI Governance" : "Evidence Collection",
      beforeValue: target,
      afterValue: updated,
      ip: "local",
      userAgent: "preview-server"
    };
    const activity = {
      id: "activity-autonomy-" + crypto.randomUUID().slice(0, 8),
      eventType: "Autonomy decision",
      title: `${updated.title} ${status}`,
      relatedObjectType: "autonomy_action",
      relatedObjectId: id,
      createdAt: now
    };
    const nextState = {
      ...state,
      autonomyActions: nextActions,
      soc2AuditLogs: [audit, ...(state.soc2AuditLogs || [])],
      activityEvents: [activity, ...(state.activityEvents || [])].slice(0, 500)
    };
    await writeChangedCollections(state, nextState);
    return { state: nextState, item: updated, message: `Autonomy action ${status}.` };
  });
}

function parseMultipartForm(buffer, contentType = "") {
  const boundaryMatch = contentType.match(/boundary=(?:"([^"]+)"|([^;]+))/i);
  if (!boundaryMatch) throw new Error("Upload boundary missing.");
  const boundary = `--${boundaryMatch[1] || boundaryMatch[2]}`;
  const raw = buffer.toString("binary");
  const fields = {};
  const files = {};
  for (const part of raw.split(boundary)) {
    if (!part || part === "--\r\n" || part === "--") continue;
    const trimmed = part.replace(/^\r\n/, "").replace(/\r\n--$/, "");
    const headerEnd = trimmed.indexOf("\r\n\r\n");
    if (headerEnd === -1) continue;
    const rawHeaders = trimmed.slice(0, headerEnd);
    const body = trimmed.slice(headerEnd + 4).replace(/\r\n$/, "");
    const disposition = rawHeaders.match(/content-disposition:\s*form-data;\s*name="([^"]+)"(?:;\s*filename="([^"]*)")?/i);
    if (!disposition) continue;
    const name = disposition[1];
    const filename = disposition[2];
    const mimeType = rawHeaders.match(/content-type:\s*([^\r\n]+)/i)?.[1]?.trim() || "application/octet-stream";
    if (filename) {
      files[name] = {
        filename,
        mimeType,
        buffer: Buffer.from(body, "binary")
      };
    } else {
      fields[name] = Buffer.from(body, "binary").toString("utf8");
    }
  }
  return { fields, files };
}

function sanitizeOutboundText(value = "") {
  return String(value || "")
    .replace(/SUPABASE_SERVICE_ROLE_KEY/g, "Supabase server credential")
    .replace(/OPENAI_API_KEY/g, "OpenAI server key")
    .replace(/LINKEDIN_CLIENT_SECRET/g, "LinkedIn client secret")
    .replace(/GOOGLE_CLIENT_SECRET/g, "Google client secret")
    .replace(/X_CLIENT_SECRET/g, "X client secret")
    .replace(/DATABASE_URL/g, "database connection string")
    .replace(/COMMAND_CENTER_OWNER_TOKEN/g, "owner access token")
    .replace(/OWNER_TOKEN/g, "owner access token")
    .replace(/OAUTH_TOKEN_ENCRYPTION_KEY/g, "OAuth token encryption setting")
    .replace(/STRIPE_SECRET_KEY/g, "Stripe server key")
    .replace(/service_role/gi, "server role")
    .replace(/\bsk-[A-Za-z0-9_-]{8,}/g, "[redacted-secret]")
    .replace(/\bwhsec_[A-Za-z0-9_-]{8,}/g, "[redacted-webhook-secret]")
    .replace(/Bearer\s+[A-Za-z0-9._~+/-]{16,}/gi, "Bearer [redacted]");
}

function sendJson(response, payload, status = 200) {
  response.writeHead(status, {
    "content-type": "application/json",
    "cache-control": "no-store, max-age=0"
  });
  response.end(sanitizeOutboundText(JSON.stringify(payload)));
}

