function creativePlanForImage(post, context, versionNumber) {
  const seed = crypto
    .createHash("sha256")
    .update(`${post.id}:${versionNumber}:${Date.now()}:${Math.random()}`)
    .digest("hex")
    .slice(0, 12);
  const lane = imageLanes[context.visualLane] || selectVisualLane(post, context);
  const treatment = artisticTreatments[context.artisticTreatment] || selectArtisticTreatment(post, lane, context);
  const visualMetaphor = context.visualMetaphor || visualMetaphorForPost(post, context, lane, treatment);
  const artDirection = artDirectionForTreatment(post, context, lane, treatment);
  const compositionDirection = [
    `Composition system: ${context.compositionSystem || treatment.compositionSystem}.`,
    compositionForLane(post, context, lane),
    "Use one focal point. Use intentional asymmetry. Avoid over-decoration and any composition with no clear focal point."
  ].join(" ");
  const textureDirection = textureDirectionForTreatment(treatment);
  const negativeRulesUsed = legalEaseNegativePrompt(context);
  const prompt = buildLegalEaseImagePromptV3({
    post,
    context,
    lane,
    treatment,
    visualMetaphor,
    artDirection,
    compositionDirection,
    textureDirection,
    negativeRules: negativeRulesUsed
  });
  return {
    seed,
    promptVersion: imagePromptVersion,
    stylePresetId: "legalease_premium_social_creative",
    styleProfile: "Premium LegalEase Social Creative",
    visualLane: lane.id,
    visualLaneLabel: lane.label,
    visualLaneReason: context.visualLaneReason || lane.reason,
    artisticTreatment: treatment.id,
    artisticTreatmentLabel: treatment.label,
    artisticTreatmentReason: context.artisticTreatmentReason || treatment.reason,
    compositionSystem: context.compositionSystem || treatment.compositionSystem,
    textureSystem: context.textureSystem || treatment.textureSystem,
    visualMetaphor,
    overlayZone: context.overlayZone,
    wilmaTreatment: context.wilmaTreatment || "none",
    productBrand: context.productBrand || productBrandForPost(post),
    imageAudience: context.imageAudience || audienceForImage(post),
    imageVariant: lane.id,
    imageVariantLabel: lane.label,
    imageVariantReason: context.visualLaneReason || lane.reason,
    negativePrompt: negativeRulesUsed,
    negativeRulesUsed,
    directionKey: lane.id,
    directionLabel: lane.label,
    representationVariant: lane.id === "human_impact" ? representationVariants[parseInt(seed.slice(8, 10), 16) % representationVariants.length] : "",
    composition: compositionDirection,
    creativeDirectionText: artDirection,
    artDirection,
    textureDirection,
    prompt
  };
  const direction = directionForContext(context, seed);
  const bucketSystem = bucketVisualSystems[context.contentBucket] || bucketVisualSystems["Trust & Guidance"];
  const variant = selectImageVariant(post, context);
  const representationVariant = representationVariants[parseInt(seed.slice(8, 10), 16) % representationVariants.length];
  const compositionOptions = context.usesWilma
    ? [
        "The approved Wilma asset will sit inside a calm lower-right guide panel, surrounded by luminous pathways, blank glass panels, and warm orange signal geometry.",
        "Reserve a clean guide-window area for app-composited Wilma while the background becomes a semi-abstract techno map of clarity, access, and next steps.",
        "Use layered signal fields and cultural geometry around the Wilma panel; she supports the idea without the model drawing any character."
      ]
    : [
        "Use an asymmetrical abstract composition with one dominant conceptual form, luminous route lines, orbital nodes, cultural geometry, and deep negative space.",
        "Use a techno-systems composition with blank glass panels, pathway light, threshold forms, and signal movement from barrier to access.",
        "Use a split symbolic layout where human reality and system logic are translated into abstract light, frame geometry, and data constellation patterns."
      ];
  const composition = compositionOptions[parseInt(seed.slice(2, 4), 16) % compositionOptions.length];
  const styleProfile = narrativeInfrastructurePreset.displayName;
  const styleBlock =
    `Style profile: ${styleProfile}. Visual style id: ${narrativeInfrastructurePreset.visualStyleId}. Brand images must feel like semi-abstract modern techno concept art with Afro-futurist inspiration, not generic social graphics. The target style combines conceptual visual metaphor, human dignity, luminous pathway systems, orbital data constellations, cultural geometry, square-frame structures, deep navy atmosphere, warm orange signal energy, and polished future-facing civic technology.`;
  const defaultPromptTemplate =
    `Create a ${context.aspectRatio} social image in the "${styleProfile}" style. This should look like high-end semi-abstract concept art for a civic technology brand: modern, luminous, symbolic, Afro-futurist-inspired, grounded, and emotionally intelligent. It should not look like a startup infographic, civic-tech template, Canva card, law-firm ad, or generic social media graphic. Do not render any visible brand name or wordmark.`;
  const layoutRules =
    "Layout rules: create strong negative space for app-rendered overlay text, plus a calm low-detail corner for an optional watermark. Keep an 8-12% safe margin around subjects, faces, hands, frame corners, route nodes, and overlay zones. Do not crop faces, hands, key geometry, or pathway endpoints off the canvas. Do not render the actual headline, support line, letters, words, numbers, or captions inside the generated image. Use layered abstract panels, square/corner frame motifs, luminous route lines, nodes, portals, data constellations, woven circuit patterns, deep atmospheric gradients, and polished dimensional light.";
  const metadataRule =
    "Text-safe metadata rule: do not render readable metadata, labels, letters, or numbers in the image. Suggest information architecture with blank plates, luminous nodes, empty capsules, abstract bars, and non-letter texture only. Exact overlay text will be added later by the app.";
  const bucketBlock =
    `Bucket visual lane: ${context.contentBucket}. Look: ${bucketSystem.look}. Use: ${bucketSystem.use}. Avoid: ${bucketSystem.avoid}. Style reference concept: ${bucketSystem.reference}`;
  const styleReferenceRule = (context.referenceAssets || []).some((asset) => asset.assetType === "example_output")
    ? "An approved style reference exists in the brand library, but the new direction should be more abstract, modern, techno, and Afro-futurist-inspired. Do not copy the reference person, race, gender, headline, or layout."
    : "";
  const representationBlock =
    `Representation rule: when people appear, show diverse, dignified human representation across race, ethnicity, gender, adult age, body type, and socioeconomic context over time. For this image specifically: ${representationVariant} People should feel capable, grounded, real, and respected. Do not tokenize, stereotype, imply criminality through appearance or setting, use pity imagery, or suggest a real person's legal status/testimonial unless explicitly provided and approved. Do not default to Black women or any single demographic repeatedly. Vary human subjects across generations.`;
  const signalLanguage =
    "Signal language direction: conceptualize access, confusion, records, second chances, workforce mobility, and process through light pathways, threshold portals, blank document planes, orbital nodes, protective frames, and signal movement. Do not render actual words.";
  const palette =
    `LegalEase DESIGN.md palette only: Legal Blue ${designSystem.colors.legalBlue}, Horizon Orange ${designSystem.colors.horizonOrange}, Skyline Blue ${designSystem.colors.skylineBlue}, Paper White ${designSystem.colors.paperWhite}, Civic Black ${designSystem.colors.civicBlack}, Infrastructure Gray ${designSystem.colors.infrastructureGray}, Lighter Legal Blue ${designSystem.colors.legalBlueLight}, Lighter Horizon Orange ${designSystem.colors.horizonOrangeLight}, Soft Light ${designSystem.colors.softLight}, white ${designSystem.colors.white}. Legal Blue should dominate. Paper White, Soft Light, white, Infrastructure Gray, and Skyline Blue create breathing space. Horizon Orange is a signal for active pathways, checkpoints, warnings, CTAs, and intervention points; do not use orange as a giant blanket background.`;
  const textRule =
    "TEXT-SAFE MODE: do not render readable text, letters, words, numbers, captions, slogans, pseudo-words, fake metadata, or tiny UI copy inside the generated image. Do not attempt to spell LegalEase, post hooks, support lines, system labels, or metadata. Leave clean blank areas and simple label plates for the app to overlay exact DM Sans and DM Mono typography afterward. This prevents typos and blurred text.";
  const wilmaRule = context.usesWilma
    ? "Wilma production rule: do not draw, render, generate, reinterpret, or include Wilma in the generated raster image. The app will composite the approved canonical Wilma PNG after background generation. Leave a clean lower-right or right-side framed guide-panel area for the approved Wilma asset. Do not create any assistant character, mascot, avatar, cartoon person, headset character, or Wilma-like substitute."
    : "Do not include Wilma unless explicitly requested. Do not use generic AI avatars or legal cliché props.";
  const safetyRule =
    context.imageRiskLevel === "high"
      ? "High-risk topic. Avoid court victory imagery, before/after transformation, eligibility promises, disappearing records, gavels, scales of justice, jail bars, handcuffs, mugshots, courthouse silhouettes, generic legal icons, fake legal documents with case details, or anything implying guaranteed outcomes. Also avoid generic flat vector people, Canva infographic style, isometric tech scenes, random dashboards, glowing AI nodes, generic robots, stock-photo overlay clichés, tokenized diversity collage, stereotype shorthand, pity imagery, and implying any shown person has a criminal record without approved context."
      : "Avoid generic flat vector people, Canva infographic style, isometric tech scenes, random dashboards, glowing AI nodes, generic robots, generic legal-tech stock visuals, courthouse silhouettes, gavels, scales of justice, jail bars, mugshots, handcuffs, giant logo badges, cheap collage energy, tokenized diversity collage, stereotype shorthand, and pity imagery.";
  const logoRule = context.usesLogo
    ? "Logo lock: do not render, recreate, redraw, reinterpret, retype, approximate, or generate any LegalEase logo, wordmark, initials, badge, fake mark, brand symbol, or logo-like device inside the image. The app may overlay the official approved LegalEase watermark after generation. Leave corners clean for optional watermark placement. Do not use generic marks, fake logos, gavels, scales, courthouse icons, or legal-themed badges."
    : "Do not include a LegalEase logo or any substitute mark.";
  const brandTextBan =
    "ABSOLUTE TYPOGRAPHY RULE: the generated raster image must contain zero readable text. Do not render the word LegalEase, LEGAL, EASE, LE, logo text, partial letters, cropped lettering, fake typography, pseudo-words, numbers, metadata, labels, captions, or UI text. All typography will be added later by the app as editable overlay text or watermark. If a design area needs text, make it a blank rectangle, blank tag, abstract line, or illegible non-letter texture.";
  const negativePrompt = legalEaseNegativePrompt(context);
  const promptBuild = buildLegalEaseImagePrompt({
    context,
    variant,
    direction,
    composition,
    negativePrompt,
    blocks: [
      defaultPromptTemplate,
      styleBlock,
      bucketBlock,
      styleReferenceRule,
      representationBlock,
      `Creative direction: ${direction.direction}`,
      `Composition: ${composition}`,
      layoutRules,
      metadataRule,
      signalLanguage,
      `Post message: ${post.hook}`,
      `Content bucket: ${context.contentBucket}. Visual bucket: ${context.visualBucket}. Speaker: ${speakerLabels[post.speaker] || "LegalEase"}. Audience: ${audienceLabels[post.audience] || "general"}.`,
      palette,
      logoRule,
      brandTextBan,
      wilmaRule,
      textRule,
      safetyRule,
      `Final art direction: semi-abstract modern techno Afro-futurist-inspired concept art with conceptual clarity, human dignity, balanced negative space, polished lighting, deep navy atmosphere, orange signal energy, pale blue glow, and no visible brand text.`
    ]
  });
  return {
    seed,
    stylePresetId: promptBuild.metadata.stylePresetId,
    styleProfile,
    imageVariant: variant.id,
    imageVariantLabel: variant.label,
    imageVariantReason: variant.reason,
    negativePrompt: promptBuild.negativePrompt,
    directionKey: direction.key,
    directionLabel: direction.label,
    representationVariant,
    composition,
    prompt: promptBuild.finalPrompt
  };
}

function imageSizeForAspectRatio(aspectRatio) {
  if (aspectRatio === "16:9") return "1536x1024";
  if (aspectRatio === "4:5" || aspectRatio === "9:16") return "1024x1536";
  return "1024x1024";
}

function isBrandMarkReferenceAsset(asset = {}) {
  const type = String(asset.assetType || "").toLowerCase();
  const text = [asset.name, asset.fileUrl, asset.filePath, ...(asset.tags || [])]
    .filter(Boolean)
    .join(" ")
    .toLowerCase();
  return (
    type === "wilma_reference" ||
    type.includes("logo") ||
    type.includes("wordmark") ||
    /\blogo\b|wordmark|brand[ -]?mark|\bwilma\b/.test(text)
  );
}

async function generateOpenAICreativeImage(prompt, aspectRatio, referenceAssets = []) {
  // Social media guidelines hard rule: Wilma, logos, and wordmarks are never sent to the
  // image model as generation references. They composite from the asset library only.
  referenceAssets = referenceAssets.filter((asset) => !isBrandMarkReferenceAsset(asset));
  const apiKey = process.env.OPENAI_API_KEY;
  if (!apiKey) {
    const details = openAIErrorDetails({ message: "OPENAI_API_KEY is missing.", route: "openai_image_generation" });
    logOpenAIImageFailure(details);
    return { imageUrl: null, error: details.safeMessage, errorDetails: details };
  }
  const env = openAIImageEnvStatus();
  let response;
  try {
    if (referenceAssets.length) {
      const form = new FormData();
      form.append("model", env.openaiImageModel);
      form.append("prompt", prompt);
      form.append("size", imageSizeForAspectRatio(aspectRatio));
      form.append("quality", env.openaiImageQuality);
      form.append("n", "1");
      for (const [index, referenceAsset] of referenceAssets.entries()) {
        const referenceUrl = assetFileUrl(referenceAsset);
        if (!referenceUrl) {
          const missing = referenceAsset?.assetType === "wilma_reference"
            ? "Wilma generation blocked: canonical reference asset missing."
            : "Logo generation blocked: approved LegalEase logo asset missing.";
          return { imageUrl: null, error: missing };
        }
        const imageBlob = new Blob([readFileSync(referenceUrl)], { type: referenceAsset.mimeType || "image/png" });
        const filename = referenceAsset.fileUrl?.split("/").pop() || `brand-reference-${index + 1}.png`;
        form.append(referenceAssets.length === 1 ? "image" : "image[]", imageBlob, filename);
      }
      response = await fetch("https://api.openai.com/v1/images/edits", {
        method: "POST",
        headers: { authorization: `Bearer ${apiKey}` },
        body: form
      });
    } else {
      response = await fetch("https://api.openai.com/v1/images/generations", {
        method: "POST",
        headers: {
          authorization: `Bearer ${apiKey}`,
          "content-type": "application/json"
        },
        body: JSON.stringify({
          model: env.openaiImageModel,
          prompt,
          size: imageSizeForAspectRatio(aspectRatio),
          quality: env.openaiImageQuality,
          n: 1
        })
      });
    }
  } catch (error) {
    const details = openAIErrorDetails({ message: error.message || "Image generation request failed.", route: "openai_image_generation" });
    logOpenAIImageFailure(details, error);
    return { imageUrl: null, error: details.safeMessage, errorDetails: details };
  }
  const payload = await response.json().catch(() => ({}));
  if (!response.ok) {
    const rawMessage = payload?.error?.message || response.statusText || "Image generation failed.";
    const details = openAIErrorDetails({ status: response.status, payload, message: rawMessage, route: "openai_image_generation" });
    logOpenAIImageFailure(details);
    const rateLimit = imageRateLimitDetails(rawMessage);
    if (rateLimit.rateLimited) {
      return {
        imageUrl: null,
        error: details.safeMessage,
        errorDetails: details,
        rateLimited: true,
        retryAfterSeconds: rateLimit.retryAfterSeconds
      };
    }
    return { imageUrl: null, error: details.safeMessage, errorDetails: details };
  }
  const item = payload.data?.[0];
  if (item?.b64_json) return { imageUrl: `data:image/png;base64,${item.b64_json}`, error: null };
  if (item?.url) return { imageUrl: item.url, error: null };
  const details = openAIErrorDetails({ message: "Image generation returned no image.", route: "openai_image_generation" });
  logOpenAIImageFailure(details);
  return { imageUrl: null, error: details.safeMessage, errorDetails: details };
}

function safeShortError(value) {
  return String(value || "Image generation failed.").replace(/sk-[A-Za-z0-9_-]+/g, "[redacted]").slice(0, 180);
}

function imageRateLimitDetails(value) {
  const raw = String(value || "");
  const secondsMatch = raw.match(/try again in\s+(\d+)\s*s/i);
  const retryAfterSeconds = secondsMatch ? Number(secondsMatch[1]) : 15;
  const rateLimited = /rate limit|too many requests|limit reached/i.test(raw);
  return {
    rateLimited,
    retryAfterSeconds,
    message: rateLimited
      ? `OpenAI image generation is cooling down. Try again in ${retryAfterSeconds}s.`
      : safeShortError(raw)
  };
}

function redactSecretText(value = "") {
  return String(value || "")
    .replace(/Bearer\s+[A-Za-z0-9._-]+/g, "Bearer [redacted]")
    .replace(/sk-[A-Za-z0-9_-]+/g, "[redacted]")
    .replace(/OPENAI_API_KEY=[^\s]+/g, "OPENAI_API_KEY=[redacted]")
    .slice(0, 900);
}

function classifyOpenAIImageError({ status = 0, payload = {}, message = "" } = {}) {
  const error = payload?.error || {};
  const raw = redactSecretText(error.message || message || "Image generation failed.");
  const type = String(error.type || "").toLowerCase();
  const code = String(error.code || "").toLowerCase();
  const combined = `${raw} ${type} ${code}`.toLowerCase();
  if (!process.env.OPENAI_API_KEY) {
    return { errorCode: "OPENAI_API_KEY_MISSING", safeMessage: "OPENAI_API_KEY is missing." };
  }
  if (status === 401 || /invalid api key|incorrect api key|authentication|unauthorized/.test(combined)) {
    return { errorCode: "OPENAI_AUTHENTICATION_FAILED", safeMessage: "OpenAI authentication failed. Check OPENAI_API_KEY in .env.local." };
  }
  if (/model|does not exist|not found|not have access|unsupported|not available/.test(combined)) {
    return {
      errorCode: "OPENAI_MODEL_UNAVAILABLE",
      safeMessage: "OpenAI model not available for this account. Your account may not have access to gpt-image-1.5. Try OPENAI_IMAGE_MODEL=gpt-image-1."
    };
  }
  if (/billing|organization verification|verify your organization|usage limit|hard limit|quota|insufficient_quota/.test(combined)) {
    return { errorCode: "OPENAI_BILLING_OR_ORG_VERIFICATION", safeMessage: "OpenAI billing or organization verification issue. Check your OpenAI project billing and organization verification." };
  }
  if (/rate limit|too many requests|limit reached/.test(combined) || status === 429) {
    return { errorCode: "OPENAI_RATE_LIMIT_REACHED", safeMessage: imageRateLimitDetails(raw).message };
  }
  if (status >= 500) {
    return { errorCode: "OPENAI_SERVER_ERROR", safeMessage: "OpenAI server error. Try again shortly." };
  }
  if (status >= 400) {
    return { errorCode: "OPENAI_REQUEST_REJECTED", safeMessage: "OpenAI request rejected. Check the model, prompt, size, and project access." };
  }
  return { errorCode: "OPENAI_IMAGE_GENERATION_FAILED", safeMessage: "Image generation failed. Check server logs." };
}

function openAIErrorDetails({ status = 0, payload = {}, message = "", route = "image_generation" } = {}) {
  const env = openAIImageEnvStatus();
  const classified = classifyOpenAIImageError({ status, payload, message });
  const error = payload?.error || {};
  return {
    ok: false,
    errorCode: classified.errorCode,
    safeMessage: classified.safeMessage,
    model: env.openaiImageModel,
    quality: env.openaiImageQuality,
    apiKeyPresent: env.openaiKeyPresent,
    fallbackEnabled: env.allowLocalImageFallback,
    openAIStatus: status || null,
    openAIType: error.type || "",
    openAICode: error.code || "",
    openAIMessage: redactSecretText(error.message || message || ""),
    route,
    timestamp: new Date().toISOString()
  };
}

function logOpenAIImageFailure(details = {}, error = null) {
  console.error("OpenAI image generation failed", {
    timestamp: details.timestamp || new Date().toISOString(),
    route: details.route || "image_generation",
    model: details.model || openAIImageEnvStatus().openaiImageModel,
    quality: details.quality || openAIImageEnvStatus().openaiImageQuality,
    apiKeyPresent: Boolean(details.apiKeyPresent),
    fallbackEnabled: Boolean(details.fallbackEnabled),
    status: details.openAIStatus || null,
    code: details.openAICode || "",
    type: details.openAIType || "",
    message: redactSecretText(details.openAIMessage || details.safeMessage || "")
  });
  if (error?.stack) console.error(redactSecretText(error.stack));
}

function narrativeInfrastructureStyleGate({ prompt, generationMode, usesWilma }) {
  const text = String(prompt || "").toLowerCase();
  const required = [
    { label: "text-free instruction", test: /text-free|no readable text|zero readable text/.test(text) },
    { label: "art-directed quality bar", test: /art-directed|human graphic designer|designed artifact|editorial spread|museum wall graphic/.test(text) },
    { label: "LegalEase brand context", test: /legalease|legal-tech|civic-tech/.test(text) },
    { label: "no fake logos/text", test: /no .*logos|no .*wordmarks|no letters|no numbers/.test(text) },
    { label: "visual metaphor", test: /creative thesis|visual metaphor|metaphor/.test(text) },
    { label: "material direction", test: /material and texture|texture\/material|paper|matte|vellum|ink/.test(text) }
  ];
  const missing = required.filter((item) => !item.test).map((item) => item.label);
  const banned = [];
  const generated = /^openai_(image|background)/.test(String(generationMode || ""));
  const passed = generated && missing.length === 0 && banned.length === 0;
  return {
    passed,
    label: passed ? "Premium prompt locked" : "Needs regeneration",
    missing,
    banned,
    message: passed
      ? "Premium LegalEase prompt requirements are present."
      : "Needs regeneration: strengthen premium text-free prompt requirements before approval."
  };
}

function validateGeneratedImageStyle({ prompt, generationMode, context, creativePlan, openAIResult }) {
  const gate = narrativeInfrastructureStyleGate({
    prompt,
    generationMode,
    usesWilma: context.usesWilma
  });
  const warnings = [];
  const lowerPrompt = String(prompt || "").toLowerCase();
  if (context.usesWilma && !context.wilmaReferenceAssetIds.length) {
    warnings.push("Wilma asset missing; OpenAI will generate a text-free background only.");
  }
  if (/include (the )?(legalease )?(logo|wordmark)|place (the )?(legalease )?(logo|wordmark)|draw (the )?(legalease )?(logo|wordmark)/.test(lowerPrompt)) {
    warnings.push("Prompt appears to request a generated logo or wordmark.");
  }
  if (!creativePlan?.promptVersion || creativePlan.promptVersion !== imagePromptVersion) {
    warnings.push("Image prompt v2 metadata missing.");
  }
  if (!openAIResult?.imageUrl) {
    warnings.push("Final generated image missing; use upload or regenerate before launch.");
  }
  const blockingWarnings = warnings.filter((warning) =>
    /fake logo/i.test(warning)
  );
  const passed = gate.passed && Boolean(openAIResult?.imageUrl) && blockingWarnings.length === 0;
  return {
    ...gate,
    passed,
    label: passed ? "Premium prompt locked" : "Needs regeneration",
    warnings,
    message: passed
      ? "Premium LegalEase prompt requirements are present."
      : `Needs regeneration: ${warnings[0] || gate.message}`
  };
}

// GUIDELINES_GATE_BLOCK_START — voice (§2) and dignity (§3) hard fails per
// docs/legalease-social-media-guidelines.md. HARD FAIL semantics: a violation blocks the
// post from advancing past review (approve/schedule); it never deletes or hides a draft.
// Every function in this block is pure (no store/env access) so tests can vm-load it.
function guidelinesNormalizeCopy(value = "") {
  // Curly apostrophes normalize to ASCII so negation lookbehinds ("can't guarantee")
  // match real copy, which routinely ships with typographic quotes.
  return String(value || "").replace(/[‘’]/g, "'").replace(/\s+/g, " ").trim();
}

// Every copy surface the guidelines cover: "any copy, any caption, any overlay" —
// title, hook, body, CTA, hashtags, overlay fields, and per-channel adaptations.
function guidelinesCopySurfaces(post = {}) {
  const surfaces = [
    ["title", post.title],
    ["hook", post.hook],
    ["body", post.body],
    ["cta", post.cta],
    ["hashtags", (post.hashtags || []).join(" ")],
    ["overlayText", post.overlayText || post.overlay_text],
    ["overlayHeadline", post.overlayHeadline],
    ["overlaySupport", post.overlaySupport],
    ["wilmaImageWorkflow.overlayText", post.wilmaImageWorkflow?.overlayText]
  ];
  for (const [channel, adaptation] of Object.entries(post.channelAdaptations || {})) {
    if (!adaptation || typeof adaptation !== "object") continue;
    for (const key of ["hook", "body", "cta"]) {
      if (adaptation[key]) surfaces.push([`channelAdaptations.${channel}.${key}`, adaptation[key]]);
    }
  }
  return surfaces
    .map(([field, text]) => [field, guidelinesNormalizeCopy(text)])
    .filter(([, text]) => Boolean(text));
}

const GUIDELINES_AI_PHRASE_PATTERNS = [
  { pattern: /excited to announce/i, label: '"excited to announce"' },
  { pattern: /thrilled to share/i, label: '"thrilled to share"' },
  { pattern: /\bgame.chang/i, label: '"game-changer"' },
  { pattern: /\brevolutioni[sz]/i, label: '"revolutionize"' },
  { pattern: /\bunlock/i, label: '"unlock"' },
  { pattern: /\bempower/i, label: '"empower"' },
  { pattern: /\bdelv(e|es|ed|ing)\b/i, label: '"delve"' },
  { pattern: /\blandscapes?\b/i, label: '"landscape"' },
  // "journey" is banned as metaphor. A mechanical check cannot read intent, so every use
  // fails; a literal use gets rewritten or Roger overrides by editing the copy.
  { pattern: /\bjourneys?\b/i, label: '"journey" (banned as metaphor)' },
  { pattern: /we('| a)re just getting started/i, label: '"we\'re just getting started"' }
];

const GUIDELINES_OUTCOME_PROMISE_PATTERNS = [
  // "guarantee" is allowed only in explicit negations ("no guarantees", "we cannot guarantee").
  { pattern: /(?<!no )(?<!not )(?<!cannot )(?<!can't )(?<!never )guarantee[ds]?\b/i, label: "guarantee language" },
  { pattern: /\bwill (clear|erase|wipe|expunge|seal)\b/i, label: "promised record outcome" },
  { pattern: /\brecord will (disappear|be (cleared|erased|sealed|gone))\b/i, label: "promised record outcome" },
  { pattern: /\byou (qualify|are eligible|'re eligible)\b/i, label: "eligibility promise" },
  { pattern: /\binstant approval\b/i, label: "instant approval promise" },
  { pattern: /\bthe court will approve\b/i, label: "court outcome promise" },
  { pattern: /\bthis will get you (a job|housing|hired)\b/i, label: "employment/housing outcome promise" }
];

// UPL sensitivity: statute citations or specific-situation directives require Lawrence
// Blackmon's sign-off (post.lawrenceSignoffAt) BEFORE the post can advance to Roger's queue.
const GUIDELINES_UPL_PATTERNS = [
  { pattern: /§/, label: "statute citation (§)" },
  { pattern: /\bILCS\b/, label: "statute citation (ILCS)" },
  { pattern: /\bU\.?S\.?C\.?\s*§?\s*\d/, label: "statute citation (USC)" },
  { pattern: /\bstatutes?\b/i, label: "statute reference" },
  { pattern: /\bpenal code\b/i, label: "penal code reference" },
  { pattern: /\byou (should|must|need to) (file|petition|plead)\b/i, label: "specific-situation legal directive" }
];

const GUIDELINES_DIGNITY_LANGUAGE_PATTERNS = [
  { pattern: /\bex[- ]?cons?\b/i, label: '"ex-con" — use "people with records"' },
  { pattern: /\bex[- ]?offenders?\b/i, label: '"ex-offender" — use "people with records"' },
  { pattern: /\bfelons?\b/i, label: '"felon" — use "someone with a felony record"' },
  { pattern: /\boffenders?\b/i, label: '"offender" — use person-first language' },
  { pattern: /\bconvicts\b|\ba convict\b/i, label: '"convict" (as a noun) — use person-first language' },
  { pattern: /\bcriminals\b/i, label: '"criminals" — use person-first language' },
  { pattern: /\ba criminal\b(?! (records?|history|background|charges?|case|conviction|justice|law|defense))/i, label: '"a criminal" as a label for a person' }
];

const GUIDELINES_BEFORE_AFTER_PATTERNS = [
  { pattern: /\bbefore (and|&) after\b/i, label: '"before and after" framing of a customer\'s past' },
  { pattern: /\bbefore\/after\b/i, label: '"before/after" framing of a customer\'s past' }
];

// §3 imagery bans (checked in copy AND image prompts) + §6 stock-photo clichés (prompts).
const GUIDELINES_BANNED_IMAGERY_PATTERNS = [
  { pattern: /handcuffs?/i, label: "handcuffs" },
  { pattern: /jail (bars?|cells?)/i, label: "jail bars/cell" },
  { pattern: /prison (bars?|cells?)/i, label: "prison bars/cell" },
  { pattern: /behind bars/i, label: "behind-bars imagery" },
  { pattern: /mug ?shots?/i, label: "mugshot" },
  { pattern: /crime scenes?/i, label: "crime-scene imagery" },
  { pattern: /courtroom drama/i, label: "courtroom-drama imagery" },
  { pattern: /police tape/i, label: "police tape" },
  { pattern: /barbed wire/i, label: "barbed wire" },
  { pattern: /orange jumpsuits?/i, label: "orange jumpsuit" }
];

const GUIDELINES_STOCK_CLICHE_PATTERNS = [
  { pattern: /gavels?/i, label: "gavel" },
  { pattern: /scales? of justice/i, label: "scales of justice" },
  { pattern: /handshakes?|shaking hands/i, label: "handshake-in-suits cliché" },
  { pattern: /diverse team/i, label: "generic diverse-team imagery" },
  { pattern: /stock photo/i, label: "stock photo" }
];

// Fabricated-number rule (§2): every number must trace to a verified source. Mechanically:
// any numeric token outside the whitelist requires post.verifiedNumberSources (a non-empty
// array naming the Command Center source or Roger-approved document for the numbers).
// Whitelisted: the documented $50 flat fee, plain years, and 24/7.
function guidelinesUntracedNumbers(text = "") {
  const stripped = String(text || "")
    .replace(/https?:\/\/\S+/gi, " ")
    .replace(/[#@][\w-]+/g, " ");
  const tokens = stripped.match(/\$?\d[\d,.:%/]*/g) || [];
  return tokens
    .map((token) => token.replace(/[.,:]+$/, ""))
    .filter((token) => !/^\$50$/.test(token) && !/^(19|20)\d{2}$/.test(token) && !/^24\/7$/.test(token));
}

function guidelinesImagePromptFindings(promptText = "") {
  // Prompts legitimately NAME banned imagery inside negations ("Avoid: ... no handcuffs,
  // no mugshots"). Only positively-requested imagery is a violation, so segments that
  // carry a negation cue are excluded before scanning.
  const positiveSegments = String(promptText || "")
    .split(/[.;\n]/)
    .map((segment) => guidelinesNormalizeCopy(segment))
    .filter(Boolean)
    .filter((segment) => !/\b(no|not|never|avoid|without|don'?t|do not|prevent[s]?|banned|exclude[sd]?)\b/i.test(segment));
  if (!positiveSegments.length) return [];
  const text = positiveSegments.join(". ");
  const findings = [];
  for (const { pattern, label } of GUIDELINES_BANNED_IMAGERY_PATTERNS) {
    if (pattern.test(text)) findings.push({ rule: "dignity_imagery", detail: `Image prompt asks for banned imagery: ${label} (guidelines §3).` });
  }
  for (const { pattern, label } of GUIDELINES_STOCK_CLICHE_PATTERNS) {
    if (pattern.test(text)) findings.push({ rule: "stock_cliche", detail: `Image prompt asks for a stock-photo cliché: ${label} (guidelines §6).` });
  }
  return findings;
}

function socialGuidelinesGate(post = {}) {
  const hardFails = [];
  const surfaces = guidelinesCopySurfaces(post);
  let uplHits = [];
  let untracedNumbers = [];
  for (const [field, text] of surfaces) {
    if (/—/.test(text)) {
      hardFails.push({ rule: "voice_em_dash", field, detail: `Em-dash in ${field} (guidelines §2: no em-dashes anywhere).` });
    }
    for (const { pattern, label } of GUIDELINES_AI_PHRASE_PATTERNS) {
      if (pattern.test(text)) hardFails.push({ rule: "voice_ai_phrase", field, detail: `AI-sounding construction ${label} in ${field} (guidelines §2).` });
    }
    for (const { pattern, label } of GUIDELINES_OUTCOME_PROMISE_PATTERNS) {
      if (pattern.test(text)) hardFails.push({ rule: "voice_outcome_promise", field, detail: `Outcome promise (${label}) in ${field} (guidelines §2: scope, never escalate).` });
    }
    for (const { pattern, label } of GUIDELINES_DIGNITY_LANGUAGE_PATTERNS) {
      if (pattern.test(text)) hardFails.push({ rule: "dignity_language", field, detail: `Person-first language violation in ${field}: ${label} (guidelines §3).` });
    }
    for (const { pattern, label } of GUIDELINES_BEFORE_AFTER_PATTERNS) {
      if (pattern.test(text)) hardFails.push({ rule: "dignity_framing", field, detail: `${label} in ${field} (guidelines §3).` });
    }
    for (const { pattern, label } of GUIDELINES_BANNED_IMAGERY_PATTERNS) {
      if (pattern.test(text)) hardFails.push({ rule: "dignity_imagery", field, detail: `Banned imagery reference in ${field}: ${label} (guidelines §3).` });
    }
    uplHits = uplHits.concat(
      GUIDELINES_UPL_PATTERNS.filter(({ pattern }) => pattern.test(text)).map(({ label }) => `${label} in ${field}`)
    );
    untracedNumbers = untracedNumbers.concat(guidelinesUntracedNumbers(text).map((token) => `"${token}" in ${field}`));
  }
  if (uplHits.length && !(post.lawrenceSignoffAt || post.lawrenceSignoff === true)) {
    hardFails.push({
      rule: "voice_upl_signoff",
      field: "post",
      detail: `UPL-sensitive content (${[...new Set(uplHits)].join("; ")}) requires Lawrence Blackmon's sign-off before it advances (guidelines §2). Record it as lawrenceSignoffAt on the post.`
    });
  }
  const numbersTraced = Array.isArray(post.verifiedNumberSources) && post.verifiedNumberSources.length > 0;
  if (untracedNumbers.length && !numbersTraced) {
    hardFails.push({
      rule: "voice_untraced_number",
      field: "post",
      detail: `Numbers without a verified source: ${[...new Set(untracedNumbers)].join("; ")} (guidelines §2). Add verifiedNumberSources tracing every number, or remove them.`
    });
  }
  return {
    passed: hardFails.length === 0,
    hardFails,
    ruleSource: "docs/legalease-social-media-guidelines.md §2-§3",
    checkedAt: new Date().toISOString()
  };
}
// GUIDELINES_GATE_BLOCK_END

// RENDER_QA_BLOCK_START — render QA per docs/legalease-social-media-guidelines.md §6.
// Every function in this block is pure (no store/env access) so tests can vm-load it.
function collapseWhitespaceForQa(value = "") {
  return String(value || "").replace(/\s+/g, " ").trim();
}

const RENDER_QA_STOCK_FALLBACK_COPY = [
  "Make second chances easier to understand.",
  "LegalEase"
];

// The copy pool is everything Roger approved on the post. Overlay text is legitimate only
// if it comes out of this pool character for character (case-insensitive: the compositor
// upcases headlines deliberately).
function approvedCopyPoolForPost(post = {}) {
  return [
    post.overlayText, post.overlay_text, post.overlayKicker, post.overlayHeadline, post.overlaySupport,
    post.wilmaImageWorkflow?.overlayText,
    post.headline, post.hook, post.caption, post.body, post.title, post.cta,
    post.contentBucket, post.contentFormat,
    ...RENDER_QA_STOCK_FALLBACK_COPY
  ].filter(Boolean).map(collapseWhitespaceForQa);
}

function overlaySegmentMatchesApprovedCopy(segment, pool) {
  const text = collapseWhitespaceForQa(segment).replace(/\.\.\.$/, "").trim();
  if (!text) return true;
  const lower = text.toLowerCase();
  return pool.some((entry) => entry.toLowerCase().includes(lower));
}

const OVERLAY_CORRUPTION_PATTERNS = [
  { pattern: /�/, label: "unicode replacement character (broken encoding)" },
  { pattern: /\$\{/, label: "unrendered template placeholder" },
  { pattern: /\\[nrtsdwb]/, label: "literal backslash escape leaked into copy" },
  { pattern: /\b(undefined|NaN|\[object Object\])\b/, label: "serialized runtime value in copy" },
  // eslint-disable-next-line no-control-regex
  { pattern: /[\u0000-\u0008\u000B\u000C\u000E-\u001F]/, label: "control character" }
];

function overlayCorruptionFindings(segment = "") {
  const text = String(segment || "");
  return OVERLAY_CORRUPTION_PATTERNS
    .filter((item) => item.pattern.test(text))
    .map((item) => item.label);
}

// Spelling gate: overlay copy is composited verbatim from approved captions, so spelling
// correctness is inherited from approval. What this catches is render corruption — words
// that no longer appear in the approved copy (the regex-escape outage class that shipped
// captions with every "s" eaten) and letter-mangled tokens.
function overlaySpellingFindings(segment, pool) {
  const text = collapseWhitespaceForQa(segment).replace(/\.\.\.$/, "");
  if (!text) return [];
  const poolText = ` ${pool.join(" ").toLowerCase()} `;
  const findings = [];
  for (const rawWord of text.split(" ")) {
    const word = rawWord.replace(/^[^a-zA-Z0-9$.']+|[^a-zA-Z0-9$.']+$/g, "");
    if (!word || !/[a-zA-Z]/.test(word)) continue;
    const lower = word.toLowerCase();
    if (!poolText.includes(lower)) {
      findings.push(`"${word}" does not appear in the approved copy`);
      continue;
    }
    if (word.length >= 4 && !/[aeiouyAEIOUY]/.test(word)) {
      findings.push(`"${word}" looks letter-mangled (no vowels)`);
    }
  }
  return findings;
}

function renderQaForGeneratedImage({
  post = {},
  context = {},
  promptUsed = "",
  generationMode = "",
  openAIResult = {},
  quoteCard = null,
  referenceAssetsSent = []
} = {}) {
  const hardFails = [];
  const pool = approvedCopyPoolForPost(post);
  const overlay = { mode: "text", kicker: "", headline: "", support: "" };
  const overlaySource = quoteCard?.textRendered || null;
  if (overlaySource) {
    overlay.kicker = overlaySource.kicker || "";
    overlay.headline = overlaySource.headline || "";
    overlay.support = overlaySource.support || "";
  } else {
    const serverOverlay = overlayTextForPostServer(post);
    overlay.mode = serverOverlay.mode;
    overlay.kicker = serverOverlay.kicker || "";
    overlay.headline = serverOverlay.headline || "";
    overlay.support = serverOverlay.support || "";
  }
  if (overlay.mode !== "none") {
    for (const [part, segment] of [["kicker", overlay.kicker], ["headline", overlay.headline], ["support", overlay.support]]) {
      if (!overlaySegmentMatchesApprovedCopy(segment, pool)) {
        hardFails.push({
          rule: "overlay_verbatim",
          detail: `Overlay ${part} does not match the approved caption character for character: "${collapseWhitespaceForQa(segment).slice(0, 120)}"`
        });
      }
      for (const label of overlayCorruptionFindings(segment)) {
        hardFails.push({ rule: "overlay_corruption", detail: `Overlay ${part}: ${label}` });
      }
      for (const finding of overlaySpellingFindings(segment, pool)) {
        hardFails.push({ rule: "spelling", detail: `Overlay ${part}: ${finding}` });
      }
    }
    // §6 QA item 4 (legible at thumbnail size), mechanical proxy: past these lengths the
    // composited type is unreadable at platform thumbnail size regardless of styling.
    const headlineLength = collapseWhitespaceForQa(overlay.headline).length;
    if (headlineLength > 90) {
      hardFails.push({ rule: "legibility", detail: `Overlay headline is ${headlineLength} characters; it cannot stay legible at thumbnail size (max 90). Shorten the overlay.` });
    }
    const supportLength = collapseWhitespaceForQa(overlay.support).length;
    if (supportLength > 220) {
      hardFails.push({ rule: "legibility", detail: `Overlay support line is ${supportLength} characters; it cannot stay legible at thumbnail size (max 220). Shorten the overlay.` });
    }
  }
  const promptText = String(promptUsed || "").toLowerCase();
  const isGeneratedMode = /^openai_(image|background)/.test(String(generationMode || ""));
  if (isGeneratedMode) {
    if (!/text-free|no readable text|zero readable text/.test(promptText)) {
      hardFails.push({ rule: "asset_integrity", detail: "Generation prompt is missing the text-free lock." });
    }
    if (!/no logos|no .*logos|zero .*logos|do not render.*logo|no wordmarks/.test(promptText)) {
      hardFails.push({ rule: "asset_integrity", detail: "Generation prompt is missing the no-logo/no-wordmark lock." });
    }
    if (context.usesWilma && !/do not draw wilma/.test(promptText)) {
      hardFails.push({ rule: "asset_integrity", detail: "Wilma post generated without the do-not-draw-Wilma prompt lock." });
    }
    // Dignity imagery + stock clichés (§3/§6) are pre-blocked before generation; this
    // re-check keeps the QA verdict honest if a render slipped through another path.
    for (const finding of guidelinesImagePromptFindings(promptUsed)) {
      hardFails.push(finding);
    }
    // §6 QA item 5 (colors within the brand palette), mechanical proxy: generated
    // backgrounds must carry the palette lock in the prompt. (Quote cards are palette-
    // correct by construction; pixel-level verification of AI output is not attempted.)
    if (!/deep navy|legalease palette|brand palette/.test(promptText)) {
      hardFails.push({ rule: "palette", detail: "Generation prompt is missing the brand-palette lock (restrained LegalEase palette). Colors cannot be trusted to stay in palette." });
    }
  }
  const brandMarksSent = (referenceAssetsSent || []).filter((asset) => isBrandMarkReferenceAsset(asset));
  if (brandMarksSent.length) {
    hardFails.push({
      rule: "asset_integrity",
      detail: `Brand-mark assets were sent to the image model as generation references: ${brandMarksSent.map((asset) => asset.name || asset.assetType).join(", ")}`
    });
  }
  if (context.usesWilma && openAIResult.imageUrl && isGeneratedMode && !openAIResult.compositedWilma) {
    hardFails.push({
      rule: "asset_integrity",
      detail: "Wilma post rendered without compositing the canonical Wilma asset. Guidelines: if the real asset cannot be composited, the image does not ship."
    });
  }
  if (String(context.visualBucket || "") === "Quote card" && openAIResult.imageUrl && isGeneratedMode) {
    hardFails.push({
      rule: "asset_integrity",
      detail: "Quote cards must be typographic composites (typography + palette + real logo), never AI-generated images."
    });
  }
  if (String(generationMode || "").startsWith("typographic_quote_card") && quoteCard && !quoteCard.logoIncluded) {
    hardFails.push({ rule: "asset_integrity", detail: "Quote card rendered without the real logo asset file." });
  }
  return {
    passed: hardFails.length === 0,
    hardFails,
    ruleSource: "docs/legalease-social-media-guidelines.md §6",
    checkedAt: new Date().toISOString()
  };
}
// RENDER_QA_BLOCK_END

function stricterPosterPrompt(prompt) {
  return `${prompt}

STRICT REGENERATION INSTRUCTION:
Make this less like generic AI prompt art and more like an art-directed designed artifact: one metaphor, one focal point, one material system, restrained palette, editorial lighting, and intentional negative space.

TEXT-SAFE REQUIREMENT:
Do not render actual readable text, letters, words, numbers, logo text, metadata, slogans, captions, or pseudo-words. Leave clean blank areas and label plates for exact app-rendered typography. Reject any generated text, fake logo, blurred letters, misspelled words, or pseudo UI copy.

Reject any generic flat illustration, centered person-plus-icons composition, weak typography, fake logo, fake Wilma, random legal symbols, generic UI icons, glossy gradients, glowing tech mist, fake dashboards, random floating icons, or Canva-style layout.`;
}

function wilmaBackgroundOnlyPrompt(prompt) {
  return `${prompt}

WILMA COMPOSITION PIPELINE:
Generate only the poster background and environment. Do not draw Wilma. Do not draw any mascot, assistant, avatar, headset character, robot, or substitute guide. The approved Wilma PNG will be composited by the app after generation.

ABSOLUTE BACKGROUND TEXT BAN:
The generated background must contain zero readable text and zero text-like markings. Do not create signs, labels, badges, stickers, banners, captions, metadata plates with words, UI labels, fake words, pseudo-letters, numbers, or letter-shaped marks. If a route checkpoint or tag is needed, use an empty shape with no glyphs inside it.

SAFE COMPOSITION:
Leave the right/lower-right area low-detail and calm for the app-composited Wilma guide panel. Keep all important human faces, route lines, and frame edges away from the lower-right panel area.`;
}

function generationModeForResult(openAIResult, context, wilmaBlocked) {
  if (openAIResult.imageUrl) {
    if (context.usesWilma && openAIResult.compositedWilma) return "openai_background_with_canonical_wilma_composite";
    if (context.usesWilma) return "openai_background_generation_for_wilma";
    return "openai_image_generation";
  }
  if (context.usesWilma && !wilmaBlocked) return "wilma_composited_preview";
  return "creative_prompt_preview";
}

async function saveUploadedPostImage(request) {
  const buffer = await readBuffer(request);
  if (buffer.length > 12 * 1024 * 1024) throw new Error("Image upload is too large. Keep it under 12MB.");
  const { fields, files } = parseMultipartForm(buffer, request.headers["content-type"] || "");
  const postId = fields.postId;
  const file = files.image;
  if (!postId) throw new Error("Post id is required.");
  if (!file?.buffer?.length) throw new Error("Choose an image to upload.");
  if (!/^image\/(png|jpe?g|webp|gif)$/i.test(file.mimeType)) {
    throw new Error("Upload a PNG, JPG, WebP, or GIF image.");
  }
  const detectedType = imageTypeFromSignature(file.buffer);
  const declaredType = file.mimeType.split("/")[1].toLowerCase().replace("jpg", "jpeg");
  if (!detectedType || detectedType !== declaredType) throw new Error("Uploaded image content does not match its declared type.");
  const state = await store.readState();
  const post = state.posts.find((item) => item.id === postId);
  if (!post) throw new Error("Post not found.");
  const previous = (state.postImages || []).filter((image) => image.postId === postId);
  const versionNumber = previous.length + 1;
  const extension = detectedType.replace("jpeg", "jpg");
  const safeName = `${crypto.randomUUID()}.${extension}`;
  const storedDraft = await persistPrivateDraftAsset(safeName, file.buffer, file.mimeType);
  const image = {
    id: crypto.randomUUID(),
    postId,
    imageUrl: "",
    privateAssetPath: storedDraft.privateAssetPath,
    imagePrompt: "",
    promptSummary: "Human-uploaded image. This visual overrides generated image output for the queue item.",
    assetBundleUsed: {
      uploadPath: storedDraft.privateAssetPath,
      storageBucket: storedDraft.storageBucket || "",
      storageObjectPath: storedDraft.storageObjectPath || "",
      uploadedBy: "human",
      watermark: {
        position: "none",
        mode: "none",
        logoAssetId: "23232323-2323-4232-8232-232323232323"
      }
    },
    rulesBundleUsed: {
      rules: [],
      note: "Manual upload. Brand/compliance review still applies."
    },
    usesWilma: false,
    usesLogo: false,
    logoAssetId: "",
    logoTypeUsed: "",
    logoColorMode: "",
    logoFidelityLocked: false,
    brandGuidelineVersionUsed: designSystem.version,
    wilmaReferenceAssetIds: [],
    wilmaFidelityMode: "",
    wilmaIdentityLocked: false,
    wilmaReferenceMode: "",
    logoReferenceMode: "",
    watermarkPosition: "none",
    watermarkMode: "none",
    watermarkLogoAssetId: "23232323-2323-4232-8232-232323232323",
    versionNumber,
    imageVersion: versionNumber,
    generationStatus: "generated",
    imageStatus: "uploaded",
    visualBucket: post.visualBucket || "Human-uploaded image",
    imageRiskLevel: post.imageRiskLevel || post.complianceRisk || "medium",
    imageBrief: "Human-uploaded image for this post.",
    aspectRatio: "uploaded",
    assetBundleKey: "human_upload",
    templateKey: "none_manual_upload",
    generationMode: "human_uploaded_image",
    styleProfile: "Manual upload",
    styleGate: {
      passed: true,
      label: "Human uploaded",
      missing: [],
      banned: [],
      message: "Manual image upload. Review visually before approval."
    },
    styleQualityLabel: "Human uploaded",
    creativeDirection: {
      styleProfile: "Manual upload",
      directionLabel: "Human-uploaded image",
      composition: "Manual visual override"
    },
    generationError: null,
    createdAt: new Date().toISOString()
  };
  await store.updatePost(postId, {
    imageFinalized: false,
    finalPreviewConfirmed: false,
    finalPreviewConfirmedAt: ""
  });
  const nextState = await store.savePostImage(image);
  return { state: nextState, image, message: "Image uploaded." };
}

function designTemplateForPost(post, context) {
  const format = String(post.contentFormat || "").toLowerCase();
  if (context.usesWilma && /myth/.test(format)) return "wilma_myth_check";
  if (context.usesWilma) return "wilma_explainer_card";
  if (context.visualBucket === "Quote card") return "legalease_quote_card";
  if (post.contentBucket === "Human Cost" || context.visualBucket === "People-centered editorial graphic") return "human_cost_editorial";
  return "legalease_implementation_graphic";
}

