// Count only new-model revenue: charges created on or after this date (00:00 UTC).
// Legacy charges before the cutoff are excluded so the box reflects new revenue
// only, not the old baseline. Change this one line to move the cutoff.
const STRIPE_REVENUE_CUTOFF_ISO = "2026-06-25";

// Live Stripe revenue, computed server-side only. The secret key is read here in
// Node scope and is NEVER serialized into any client payload — only the computed
// dollar amount and a status flag reach the browser. Returns gross captured
// revenue (sum of amount_captured across paid, succeeded charges) for charges on
// or after STRIPE_REVENUE_CUTOFF_ISO.
// On ANY failure — missing key, non-live key, auth rejection, network/timeout —
// it returns available:false so the Revenue box renders a clear unavailable
// state. It never returns a cached, stale, estimated, or fabricated number, and
// a test-mode key can never surface as live revenue.
async function fetchStripeRevenueSnapshot() {
  const base = { source: "stripe_live", fetchedAt: new Date().toISOString() };
  const key = process.env.STRIPE_SECRET_KEY || "";
  if (!key) {
    return { ...base, available: false, configured: false, error: "Stripe is not connected yet." };
  }
  if (!(key.startsWith("sk_live_") || key.startsWith("rk_live_"))) {
    // Honesty guard: a test-mode (or restricted test) key must never read as live.
    return { ...base, available: false, configured: true, error: "Stripe key is not in live mode. Live revenue requires a live key." };
  }
  const cutoffUnix = Math.floor(Date.parse(STRIPE_REVENUE_CUTOFF_ISO + "T00:00:00Z") / 1000);
  const sinceLabel = new Date(cutoffUnix * 1000).toLocaleDateString("en-US", { month: "short", day: "numeric", timeZone: "UTC" });
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), 8000);
  try {
    let totalMinorUnits = 0;
    let currency = "";
    let after = "";
    let pages = 0;
    // Display-only per-day aggregation of the same charges that make up the total,
    // so the Money card can draw an honest daily chart. No extra API calls.
    const dailyMinorUnits = {};
    while (true) {
      // created[gte] makes Stripe return only on/after-cutoff charges; the local
      // check below is a defensive double-guard so legacy charges can never count.
      const query = "charges?limit=100&created%5Bgte%5D=" + cutoffUnix + (after ? "&starting_after=" + encodeURIComponent(after) : "");
      const res = await fetch("https://api.stripe.com/v1/" + query, {
        headers: { authorization: "Bearer " + key },
        signal: controller.signal
      });
      const data = await res.json().catch(() => null);
      if (!res.ok) {
        const safe = res.status === 401 ? "Stripe rejected the API key." : "Stripe request failed (status " + res.status + ").";
        return { ...base, available: false, configured: true, error: safe };
      }
      pages += 1;
      for (const charge of (data && data.data) || []) {
        if (charge && charge.livemode === false) {
          // Defensive: a live key returning test-mode data should never count.
          return { ...base, available: false, configured: true, error: "Stripe returned test-mode data for a live key." };
        }
        if (charge && charge.paid && charge.status === "succeeded" && Number(charge.created) >= cutoffUnix) {
          const minor = Number(charge.amount_captured ?? charge.amount ?? 0);
          totalMinorUnits += minor;
          if (!currency) currency = charge.currency || "";
          const day = new Date(Number(charge.created) * 1000).toISOString().slice(0, 10);
          dailyMinorUnits[day] = (dailyMinorUnits[day] || 0) + minor;
        }
      }
      if (!data || !data.has_more || !data.data?.length) break;
      after = data.data[data.data.length - 1].id;
      if (pages >= 100) break; // defensive page cap (~10k charges)
    }
    return {
      ...base,
      available: true,
      configured: true,
      livemode: true,
      gross: Math.round(totalMinorUnits) / 100,
      since: STRIPE_REVENUE_CUTOFF_ISO,
      sinceLabel,
      currency: currency || "usd",
      dailyGross: Object.fromEntries(Object.entries(dailyMinorUnits).map(([day, minor]) => [day, Math.round(minor) / 100]))
    };
  } catch (error) {
    const aborted = error && (error.name === "AbortError" || error.aborted);
    return { ...base, available: false, configured: true, error: aborted ? "Stripe request timed out." : "Stripe is unavailable right now." };
  } finally {
    clearTimeout(timeout);
  }
}

// Live end-user signup counts, fetched server-side only. The signup endpoint lives
// on the new Next.js app (currently served on the partner domain — see the
// "signup endpoint URL at cutover" deferred decision). The API key is read here in
// Node scope and is NEVER serialized into any client payload — only the two
// integer counts and a status flag reach the browser.
//
// Returns { paid, registered } where:
//   paid       = real paying ($50) customers — the headline number.
//   registered = saved items at the top of the funnel. This counts SAVED ITEMS,
//                not distinct users — one person with several saved items is
//                counted more than once. Labelled "saved items" in the UI so the
//                number is never mistaken for distinct signups.
//
// On ANY failure — missing key, 401 auth rejection, 503/unreachable, timeout, or a
// malformed body — it returns available:false so the Users box renders a clear
// unavailable state. It never returns a cached, stale, estimated, or fabricated
// number. This is the connector's health check + safe failure; the box tone is its
// visible status.
const SIGNUPS_METRICS_URL = "https://expungement.ai/api/metrics/signups";

// 60-second server-side cache for the live Stripe + signups snapshots (Roger's call,
// 2026-07-09). Both /api/state and /api/today/summary attach them; before this, the
// summary endpoint attached NEITHER (it read stored state only, and nothing persists
// these snapshots), so the scoreboard showed "Not wired yet" for Revenue and Accounts
// created even with Stripe fully live, while the connector tiles (fed by /api/state's
// fresh fetch) correctly showed connected. The fetchers fail SOFT (available:false),
// so a cached failure clears the cache slot and the next request retries.
let liveMetricsCache = { at: 0, promise: null };
// Stale-while-revalidate layer (2026-07-12 latency fix). Stripe + signups sit on the two
// hottest GETs (/api/state, /api/today/summary) with 8s abort ceilings, and any soft failure
// used to clear the 60s cache — so one upstream wobble put an up-to-8s stall back on every
// request. Now: the last fully-available pair is kept and served immediately (marked
// stale:true once older than the 60s window) while a refresh runs in the background; only a
// caller with NO good pair from the last 5 minutes ever awaits a live fetch. Past the 5-minute
// grace, unavailability is served honestly, exactly as before — the layer never fabricates and
// never hides an ongoing outage, it only stops an outage from also being a latency cliff.
let liveMetricsLastGood = { at: 0, value: null };
const LIVE_METRICS_TTL_MS = 60000;
const LIVE_METRICS_STALE_GRACE_MS = 300000;

function startLiveMetricsRefresh(nowMs) {
  const promise = Promise.all([fetchStripeRevenueSnapshot(), fetchSignupsSnapshot()]).then(([stripeRevenue, signups]) => {
    const allGood = !(stripeRevenue && stripeRevenue.available === false) && !(signups && signups.available === false);
    if (allGood) {
      liveMetricsLastGood = { at: Date.now(), value: [stripeRevenue, signups] };
    } else if (liveMetricsCache.promise === promise) {
      // Do not pin an outage for a whole minute; the next request retries in the background.
      liveMetricsCache = { at: 0, promise: null };
    }
    return [stripeRevenue, signups];
  });
  liveMetricsCache = { at: nowMs, promise };
  // Belt for a future throw-path in either fetcher (both currently fail soft):
  // never pin a rejected promise in the cache for the 60s window.
  promise.catch(() => {
    if (liveMetricsCache.promise === promise) liveMetricsCache = { at: 0, promise: null };
  });
  return promise;
}

function fetchLiveMetricsSnapshots() {
  const nowMs = Date.now();
  const cacheFresh = liveMetricsCache.promise && nowMs - liveMetricsCache.at < LIVE_METRICS_TTL_MS;
  if (!cacheFresh) startLiveMetricsRefresh(nowMs);
  const lastGood = liveMetricsLastGood;
  if (lastGood.value && nowMs - lastGood.at < LIVE_METRICS_STALE_GRACE_MS) {
    if (nowMs - lastGood.at < LIVE_METRICS_TTL_MS) return Promise.resolve(lastGood.value);
    return Promise.resolve(lastGood.value.map((snapshot) => ({ ...snapshot, stale: true })));
  }
  return liveMetricsCache.promise;
}

async function fetchSignupsSnapshot() {
  const base = { source: "expungement_signups", fetchedAt: new Date().toISOString() };
  const key = process.env.COMMAND_CENTER_API_KEY || "";
  if (!key) {
    return { ...base, available: false, configured: false, error: "Signup metrics are not connected yet." };
  }
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), 8000);
  try {
    const res = await fetch(SIGNUPS_METRICS_URL, {
      headers: { authorization: "Bearer " + key },
      signal: controller.signal
    });
    const data = await res.json().catch(() => null);
    if (!res.ok) {
      const safe = res.status === 401
        ? "Signup endpoint rejected the API key."
        : res.status === 503
          ? "Signup endpoint is unavailable (503)."
          : "Signup request failed (status " + res.status + ").";
      return { ...base, available: false, configured: true, error: safe };
    }
    if (!data || !Number.isFinite(Number(data.paid)) || !Number.isFinite(Number(data.registered))) {
      return { ...base, available: false, configured: true, error: "Signup endpoint returned an unexpected response." };
    }
    return {
      ...base,
      available: true,
      configured: true,
      paid: Math.max(0, Math.round(Number(data.paid))),
      registered: Math.max(0, Math.round(Number(data.registered)))
    };
  } catch (error) {
    const aborted = error && (error.name === "AbortError" || error.aborted);
    return { ...base, available: false, configured: true, error: aborted ? "Signup request timed out." : "Signup endpoint is unavailable right now." };
  } finally {
    clearTimeout(timeout);
  }
}

const googleSyncTerms = [
  "LegalEase",
  "Expungement.ai",
  "RecordShield",
  "pilot",
  "proposal",
  "partnership",
  "investor",
  "raise",
  "diligence",
  "acquirer",
  "document request",
  "complaint",
  "refund",
  "legal advice",
  "campaign",
  "launch",
  "follow up",
  "data room",
  "We Must Vote",
  "TimeDone",
  "Clean Slate Initiative",
  "Fulton County",
  "Goodwill",
  "Hope Credit Union"
];

function googleAccessToken(connector = "") {
  if (connector === "gmail") return process.env.GMAIL_ACCESS_TOKEN || process.env.GOOGLE_GMAIL_ACCESS_TOKEN || process.env.GOOGLE_ACCESS_TOKEN || "";
  if (connector === "calendar") return process.env.GOOGLE_CALENDAR_ACCESS_TOKEN || process.env.CALENDAR_ACCESS_TOKEN || process.env.GOOGLE_ACCESS_TOKEN || "";
  return "";
}

function gmailHeader(message = {}, name = "") {
  return (message.payload?.headers || []).find((header) => String(header.name || "").toLowerCase() === name.toLowerCase())?.value || "";
}

function googleSenderDomain(value = "") {
  const raw = String(value || "");
  const match = raw.match(/[A-Z0-9._%+-]+@([A-Z0-9.-]+\.[A-Z]{2,})/i);
  return match ? match[1].toLowerCase().slice(0, 80) : "";
}

function googleSignalTag(text = "") {
  const source = String(text || "").toLowerCase();
  if (/proposal|pilot|partnership|partner|sponsor|revenue|investor|fund|acquirer/.test(source)) return "partner proposal follow up";
  if (/document|data room|diligence|request/.test(source)) return "document request";
  if (/complaint|refund|legal advice|guarantee|eligib|court|attorney|privacy|sensitive/.test(source)) return "compliance review";
  if (/follow up|next step|checking in|circling back|reply|question|\?/.test(source)) return "follow up";
  return "blind spot";
}

async function googleJson(url, token = "") {
  const result = await fetch(url, { headers: { authorization: `Bearer ${token}` } });
  const text = await result.text();
  let body = {};
  try {
    body = text ? JSON.parse(text) : {};
  } catch {
    body = { error: text.slice(0, 300) };
  }
  if (!result.ok) throw new Error(body.error?.message || body.error || `Google API returned ${result.status}`);
  return body;
}

// ---- I1 inbox intelligence: owner-only visibility + the ONE-mailbox full-read fetcher --------
// Owner decision 2026-07-12 (docs/decisions/2026-07-12-inbox-full-read-roger-legalease.md).
// Inbox-derived data is owner-visible ONLY: these collections are stripped from any state
// payload served to a non-owner actor. This is the codebase's first per-collection visibility
// gate; test-inbox-intelligence.mjs pins it.
// Le-E's conversation memory joins the inbox data behind the owner wall: Roger's chat history
// (and the leeMemory pointer into it) is stripped from any state payload served to a non-owner.
const OWNER_ONLY_COLLECTIONS = ["inboxSignals", "inboxConfig", "leeThreads", "leeMessages", "leeRuns", "leeMemory"];
function stripOwnerOnlyCollections(payload, actor) {
  if (!payload || typeof payload !== "object") return payload;
  if (String(actor?.role || "") === "owner") return payload;
  const stripped = { ...payload };
  for (const collection of OWNER_ONLY_COLLECTIONS) delete stripped[collection];
  return stripped;
}

function decodeGmailBodyData(data = "") {
  try {
    return Buffer.from(String(data || "").replace(/-/g, "+").replace(/_/g, "/"), "base64").toString("utf8");
  } catch {
    return "";
  }
}

// Prefer a text/plain part anywhere in the MIME tree; fall back to tag-stripped HTML. The
// decoded text is a TRANSIENT classification input — inbox-intelligence.mjs persists only
// classifications, summaries, and redacted evidence lines (never this).
function gmailPlainTextBody(payload) {
  if (!payload || typeof payload !== "object") return "";
  if (payload.mimeType === "text/plain" && payload.body?.data) return decodeGmailBodyData(payload.body.data);
  for (const part of payload.parts || []) {
    const text = gmailPlainTextBody(part);
    if (text) return text;
  }
  if (payload.mimeType === "text/html" && payload.body?.data) {
    return decodeGmailBodyData(payload.body.data).replace(/<[^>]+>/g, " ").replace(/&nbsp;/gi, " ").replace(/&amp;/gi, "&");
  }
  return "";
}

// Full-read fetch for EXACTLY the authorized mailbox. Identity wall lives here: if the bound
// Google account is any other address, this returns a refusal and reads nothing — the
// snippets-only rules keep governing every other account. Paginated (Gmail nextPageToken)
// with an explicit message cap; a capped scan reports truncated:true so the engine can
// resume the window next scan instead of silently dropping the tail.
async function fetchInboxThreadsForIntelligence({ windowDays = 14, messageCap = INBOX_SCAN_MESSAGE_CAP } = {}) {
  const currentState = await store.readState();
  const connector = (currentState.socialAccounts || []).find((account) => account.platform === "google_workspace");
  if (!connector) return { ok: false, reason: "google_not_connected" };
  const boundMailbox = String(connector.accountName || "").toLowerCase();
  if (boundMailbox !== INBOX_ALLOWED_MAILBOX) {
    return { ok: false, reason: "mailbox_not_authorized", mailbox: boundMailbox };
  }
  let token = "";
  try {
    token = await googleStoredOrEnvAccessToken(connector);
  } catch (error) {
    // Fail CLOSED but soft: a token/decryption problem is a "blocked" observation for the
    // engine, never an unhandled throw (the scan endpoint should report it plainly).
    return { ok: false, reason: "token_unavailable: " + String(error.message || error).slice(0, 120), mailbox: boundMailbox };
  }
  if (!token) return { ok: false, reason: "no_access_token", mailbox: boundMailbox };
  const query = encodeURIComponent("newer_than:" + Math.max(1, Math.round(Number(windowDays) || 14)) + "d -in:chats");
  const cap = Math.max(1, Math.min(Number(messageCap) || INBOX_SCAN_MESSAGE_CAP, INBOX_SCAN_MESSAGE_CAP));
  const refs = [];
  let pageToken = "";
  let truncated = false;
  for (let page = 0; page < 20; page += 1) {
    const listUrl = "https://gmail.googleapis.com/gmail/v1/users/me/messages?maxResults=100&q=" + query
      + (pageToken ? "&pageToken=" + encodeURIComponent(pageToken) : "");
    const data = await googleJson(listUrl, token);
    for (const ref of data?.messages || []) {
      if (refs.length >= cap) { truncated = true; break; }
      refs.push(ref);
    }
    pageToken = data?.nextPageToken || "";
    if (!pageToken || truncated) break;
  }
  if (pageToken && refs.length >= cap) truncated = true;
  const threads = new Map();
  for (const ref of refs) {
    let message;
    try {
      message = await googleJson("https://gmail.googleapis.com/gmail/v1/users/me/messages/" + encodeURIComponent(ref.id) + "?format=full", token);
    } catch {
      continue; // one unreadable message never kills the scan
    }
    const from = gmailHeader(message, "From") || "";
    const fromEmail = ((from.match(/<([^>]+)>/) || [])[1] || from).trim().toLowerCase();
    const fromName = from.replace(/<[^>]*>/, "").replace(/"/g, "").trim();
    const at = new Date(Number(message?.internalDate) || Date.parse(gmailHeader(message, "Date") || "") || Date.now()).toISOString();
    const isFromMe = (message?.labelIds || []).includes("SENT") || fromEmail === INBOX_ALLOWED_MAILBOX;
    const threadId = String(message?.threadId || ref.threadId || ref.id);
    if (!threads.has(threadId)) {
      threads.set(threadId, { threadId, subject: gmailHeader(message, "Subject") || "", messages: [] });
    }
    threads.get(threadId).messages.push({
      id: String(message?.id || ref.id),
      fromEmail,
      fromName,
      isFromMe,
      at,
      bodyText: gmailPlainTextBody(message?.payload).slice(0, 20000)
    });
  }
  return { ok: true, mailbox: boundMailbox, threads: [...threads.values()], scannedCount: refs.length, truncated };
}

async function fetchGmailReadOnlyEvents(token = "") {
  const query = `newer_than:14d {${googleSyncTerms.map((term) => term.includes(" ") || term.includes(".") ? `"${term}"` : term).join(" ")}}`;
  const listUrl = new URL("https://gmail.googleapis.com/gmail/v1/users/me/messages");
  listUrl.searchParams.set("maxResults", "25");
  listUrl.searchParams.set("q", query);
  const messageList = await googleJson(listUrl, token);
  const messages = [];
  for (const item of messageList.messages || []) {
    const url = new URL(`https://gmail.googleapis.com/gmail/v1/users/me/messages/${encodeURIComponent(item.id)}`);
    url.searchParams.set("format", "metadata");
    ["Subject", "From", "Date", "To"].forEach((header) => url.searchParams.append("metadataHeaders", header));
    messages.push(await googleJson(url, token));
  }
  return messages.map((message) => {
    const subject = gmailHeader(message, "Subject") || "Gmail message";
    const from = gmailHeader(message, "From");
    const date = gmailHeader(message, "Date");
    const dateTime = date ? new Date(date).getTime() : NaN;
    const snippet = String(message.snippet || "").slice(0, 500);
    const signalTag = googleSignalTag([subject, snippet].join(" "));
    const sourceRefHash = googleSourceRefHash(`gmail:${message.id || message.threadId || subject}:${date || ""}`);
    return {
      source:"gmail",
      sourceEventId:`gmail:${sourceRefHash}`,
      receivedAt: Number.isFinite(dateTime) ? new Date(dateTime).toISOString() : new Date().toISOString(),
      eventType:`email_received_${signalTag.replace(/[^a-z0-9]+/g, "_")}`,
      title: signalTag === "blind spot" ? "Gmail blind spot" : "Gmail follow-up opportunity",
      summary:`Read-only Gmail signal: ${signalTag}. Open Gmail directly for source context.`,
      rawPayload:{ sourceRefHash, sourceKind: message.threadId ? "thread" : "message", senderDomain: googleSenderDomain(from), date, signalTag },
      confidence:"medium"
    };
  });
}

async function fetchCalendarReadOnlyEvents(token = "") {
  const now = new Date();
  const timeMin = new Date(now);
  timeMin.setDate(timeMin.getDate() - 7);
  const timeMax = new Date(now);
  timeMax.setDate(timeMax.getDate() + 7);
  const calendarId = process.env.GOOGLE_CALENDAR_ID || "primary";
  const url = new URL(`https://www.googleapis.com/calendar/v3/calendars/${encodeURIComponent(calendarId)}/events`);
  url.searchParams.set("singleEvents", "true");
  url.searchParams.set("orderBy", "startTime");
  url.searchParams.set("maxResults", "50");
  url.searchParams.set("timeMin", timeMin.toISOString());
  url.searchParams.set("timeMax", timeMax.toISOString());
  const body = await googleJson(url, token);
  const terms = googleSyncTerms.map((term) => term.toLowerCase());
  return (body.items || []).filter((item) => {
    const text = [item.summary, item.description, item.location, (item.attendees || []).map((attendee) => attendee.email).join(" ")].join(" ").toLowerCase();
    return terms.some((term) => text.includes(term.toLowerCase()));
  }).map((item) => {
    const startTime = item.start?.dateTime || item.start?.date || "";
    const endTime = item.end?.dateTime || item.end?.date || "";
    const signalTag = googleSignalTag([item.summary, item.description, item.location].join(" ")) || "meeting";
    const sourceRefHash = googleSourceRefHash(`calendar:${item.id || item.iCalUID || item.htmlLink || item.summary}:${startTime}`);
    return {
      source:"calendar",
      sourceEventId:`calendar:${sourceRefHash}`,
      receivedAt:item.updated || new Date().toISOString(),
      eventType:`calendar_event_${signalTag.replace(/[^a-z0-9]+/g, "_")}`,
      title:"Google Calendar meeting",
      summary:`Read-only Google Calendar signal: ${signalTag}. Open Calendar directly for source context.`,
      rawPayload:{ sourceRefHash, sourceKind:"event", startTime, endTime, status:item.status || "", attendeeCount:(item.attendees || []).length, signalTag },
      confidence:"medium"
    };
  });
}

// Phase 18H — calendar events for meeting briefs (approved Google live-fetch decision).
// Unlike fetchCalendarReadOnlyEvents (keyword-filtered signals), briefs read the owner's OWN
// upcoming schedule with attendee emails so company-memory matching works. Read-only scope;
// returns null when Calendar is not connected so callers can report "not connected" honestly.
async function fetchCalendarEventsForBriefs() {
  const token = await googleStoredOrEnvAccessToken("calendar");
  if (!token) return null;
  const timeMin = new Date();
  const timeMax = new Date(timeMin.getTime() + 7 * 24 * 60 * 60 * 1000);
  const url = new URL("https://www.googleapis.com/calendar/v3/calendars/primary/events");
  url.searchParams.set("singleEvents", "true");
  url.searchParams.set("orderBy", "startTime");
  url.searchParams.set("maxResults", "20");
  url.searchParams.set("timeMin", timeMin.toISOString());
  url.searchParams.set("timeMax", timeMax.toISOString());
  const body = await googleJson(url, token);
  return (body.items || []).filter((item) => item.status !== "cancelled");
}

// Phase 18H — per-attendee Gmail thread snippets, ON DEMAND only (never on the heartbeat).
// Metadata format: subject/date headers plus Google's own short snippet. Never bodies.
async function fetchGmailSnippetsForAttendee(email = "") {
  const token = await googleStoredOrEnvAccessToken("gmail");
  if (!token) return null;
  const address = String(email || "").trim().toLowerCase();
  if (!address) return [];
  const listUrl = new URL("https://gmail.googleapis.com/gmail/v1/users/me/messages");
  listUrl.searchParams.set("maxResults", "3");
  listUrl.searchParams.set("q", `(from:${address} OR to:${address}) newer_than:30d`);
  const messageList = await googleJson(listUrl, token);
  const snippets = [];
  for (const item of (messageList.messages || []).slice(0, 3)) {
    const url = new URL(`https://gmail.googleapis.com/gmail/v1/users/me/messages/${encodeURIComponent(item.id)}`);
    url.searchParams.set("format", "metadata");
    url.searchParams.append("metadataHeaders", "Subject");
    url.searchParams.append("metadataHeaders", "Date");
    const message = await googleJson(url, token);
    const headers = message.payload?.headers || [];
    const header = (name) => headers.find((entry) => String(entry.name).toLowerCase() === name)?.value || "";
    snippets.push({ with: address, subject: header("subject"), snippet: message.snippet || "", at: header("date") });
  }
  return snippets;
}

function connectorStatusPatch(state = {}, connector = "", patch = {}) {
  const found = new Set();
  const items = defaultConnectorStatus(state).map((item) => {
    if (item.connector !== connector) return item;
    found.add(connector);
    return { ...item, ...patch };
  });
  if (!found.has(connector)) items.push({ connector, enabled:false, configured:false, recordsImported:0, recordsSuggested:0, ...patch });
  return items;
}

function automationText(event = {}) {
  return [event.title, event.summary, event.eventType, JSON.stringify(event.rawPayload || {})].filter(Boolean).join(" ").toLowerCase();
}

function findAutomationPartner(state = {}, text = "") {
  return (state.partners || []).find((partner) => {
    const name = String(partner.organizationName || "").toLowerCase();
    const domain = String(partner.website || partner.email || "").toLowerCase().replace(/^https?:\/\//, "").split(/[/?#@]/).pop();
    return (name && text.includes(name)) || (domain && domain.length > 4 && text.includes(domain));
  }) || null;
}

function findAutomationCampaign(state = {}, text = "") {
  return (state.campaigns || []).find((campaign) => {
    const name = String(campaign.campaignName || "").toLowerCase();
    const slug = String(campaign.trackingSlug || "").toLowerCase();
    return (name && text.includes(name)) || (slug && text.includes(slug));
  }) || null;
}

function normalizeAutomationEvent(input = {}, state = {}) {
  const now = new Date().toISOString();
  const source = automationSources.includes(input.source) ? input.source : "manual_import";
  const event = {
    id: input.id || `automation-event-${source}-${crypto.randomUUID().slice(0, 8)}`,
    source,
    sourceEventId: input.sourceEventId || `${source}-${crypto.randomUUID().slice(0, 8)}`,
    receivedAt: input.receivedAt || now,
    eventType: input.eventType || "manual_import",
    title: String(input.title || "Imported event").trim(),
    summary: String(input.summary || "").trim(),
    rawPayload: input.rawPayload || {},
    relatedEntityType: input.relatedEntityType || "unknown",
    relatedEntityId: input.relatedEntityId || "",
    status: input.status || "new",
    confidence: input.confidence || "medium",
    createdAt: input.createdAt || now,
    updatedAt: now
  };
  const text = automationText(event);
  const partner = findAutomationPartner(state, text);
  const campaign = findAutomationCampaign(state, text);
  if (!event.relatedEntityId && partner) {
    event.relatedEntityType = "partner";
    event.relatedEntityId = partner.id;
  } else if (!event.relatedEntityId && campaign) {
    event.relatedEntityType = "campaign";
    event.relatedEntityId = campaign.id;
  }
  return event;
}

function automationSuggestion(idPrefix, event = {}, patch = {}) {
  const now = new Date().toISOString();
  return {
    id: `${idPrefix}-${crypto.randomUUID().slice(0, 8)}`,
    eventId: event.id,
    suggestionType: "add_activity_event",
    title: event.title,
    explanation: "Detected an operational signal that should be reviewed.",
    relatedEntityType: event.relatedEntityType || "unknown",
    relatedEntityId: event.relatedEntityId || "",
    proposedChanges: {},
    status: "pending",
    confidence: event.confidence || "medium",
    createdAt: now,
    appliedAt: "",
    ...patch
  };
}

function classifyAutomationEvent(state = {}, event = {}) {
  const text = automationText(event);
  const suggestions = [];
  const partner = findAutomationPartner(state, text);
  const campaign = findAutomationCampaign(state, text);
  const confidence = partner || campaign ? "high" : event.confidence || "medium";
  const relatedEntityType = partner ? "partner" : campaign ? "campaign" : event.relatedEntityType || "unknown";
  const relatedEntityId = partner?.id || campaign?.id || event.relatedEntityId || "";
  const activityTitle = event.title || "Automation event captured";
  const base = { relatedEntityType, relatedEntityId, confidence };
  if (event.source === "gmail" && text.includes("proposal")) {
    suggestions.push(automationSuggestion("automation-suggestion-task", event, {
      ...base,
      suggestionType: "create_task",
      title: `Follow up on proposal: ${partner?.organizationName || event.title}`,
      explanation: "Proposal language in email usually needs a follow-up task and activity log.",
      proposedChanges: { title: `Follow up on proposal: ${partner?.organizationName || event.title}`, relatedObjectType: relatedEntityType, relatedObjectId: relatedEntityId, dueDate: appendDaysIso(3), owner: partner?.owner || "Owner TBD", priority: "High", status: "open", suggestedAction: "Confirm whether the proposal is approved, needs edits, or should be paused." }
    }));
  }
  if (event.source === "gmail" && text.includes("partnership") && !partner) {
    suggestions.push(automationSuggestion("automation-suggestion-partner", event, {
      suggestionType: "create_partner",
      title: `Create partner from email: ${event.title}`,
      explanation: "Partnership language was detected and no existing partner matched.",
      relatedEntityType: "partner",
      relatedEntityId: "",
      confidence: "medium",
      proposedChanges: { organizationName: event.rawPayload?.organizationName || event.title.replace(/^re:/i, "").slice(0, 80), partnerType: "other", status: "contact_found", owner: "Owner TBD", priority: "Normal", nextFollowUpDate: appendDaysIso(3), nextAction: "Review imported email and decide whether this is a real partner target.", notes: event.summary || "Created from Automation Inbox suggestion." }
    }));
  }
  if (event.source === "gmail" && text.includes("pilot")) {
    suggestions.push(automationSuggestion("automation-suggestion-pilot", event, {
      ...base,
      suggestionType: relatedEntityId ? "create_task" : "create_pilot",
      title: relatedEntityId ? `Create pilot follow-up: ${activityTitle}` : `Create pilot from signal: ${activityTitle}`,
      explanation: "Pilot language was detected and should become either a pilot record or follow-up task.",
      proposedChanges: relatedEntityId
        ? { title: `Pilot follow-up: ${activityTitle}`, relatedObjectType: relatedEntityType, relatedObjectId: relatedEntityId, dueDate: appendDaysIso(2), owner: partner?.owner || "Owner TBD", priority: "High", status: "open", suggestedAction: "Confirm pilot scope, owner, and next meeting." }
        : { pilotName: activityTitle, partnerId: "", objective: event.summary || "Pilot signal from Automation Inbox.", status: "proposed", startDate: appendDaysIso(14), endDate: appendDaysIso(90), targetUsers: 100, successMetrics: "RecordShield starts, partner reporting, and proof readiness.", internalOwner: "Owner TBD", nextAction: "Confirm partner, scope, and launch checklist.", publicProofStatus: "not_requested" }
    }));
  }
  if (event.source === "calendar") {
    const startTime = event.rawPayload?.startTime || event.rawPayload?.startsAt || "";
    const isFuture = startTime && new Date(startTime).getTime() > Date.now();
    suggestions.push(automationSuggestion("automation-suggestion-calendar-task", event, {
      ...base,
      suggestionType: "create_task",
      title: `${isFuture ? "Meeting prep" : "Meeting follow-up"}: ${activityTitle}`,
      explanation: "Calendar meetings should produce prep or follow-up tasks so next steps do not live in memory.",
      proposedChanges: { title: `${isFuture ? "Meeting prep" : "Meeting follow-up"}: ${activityTitle}`, relatedObjectType: relatedEntityType, relatedObjectId: relatedEntityId, dueDate: isFuture ? String(startTime).slice(0, 10) : appendDaysIso(1), owner: partner?.owner || "Owner TBD", priority: "High", status: "open", suggestedAction: isFuture ? "Prepare agenda, desired decision, and post-meeting follow-up owner." : "Add meeting notes, decision, and next follow-up date." }
    }));
  }
  if (event.source === "stripe" && text.includes("checkout.session.completed")) {
    suggestions.push(automationSuggestion("automation-suggestion-funnel", event, {
      ...base,
      suggestionType: "update_funnel_snapshot",
      title: "Update funnel revenue from Stripe checkout",
      explanation: "A completed checkout should update funnel conversion and revenue tracking.",
      relatedEntityType: campaign ? "campaign" : "funnel",
      relatedEntityId: campaign?.id || "",
      confidence: "high",
      proposedChanges: { campaignId: campaign?.id || "", partnerId: partner?.id || "", dateRange: new Date().toISOString().slice(0, 7), paymentCompleted: 1, revenue: Number(event.rawPayload?.amount_total || event.rawPayload?.amount || 0) / 100, source: "stripe", notes: event.summary || "Imported Stripe checkout completion." }
    }));
  }
  if (event.source === "supabase" && text.includes("recordshield_user_created")) {
    suggestions.push(automationSuggestion("automation-suggestion-rs-user", event, {
      ...base,
      suggestionType: "update_funnel_snapshot",
      title: "Update RecordShield starts",
      explanation: "A RecordShield user event should increase the funnel count.",
      relatedEntityType: campaign ? "campaign" : "funnel",
      relatedEntityId: campaign?.id || "",
      confidence: "high",
      proposedChanges: { campaignId: campaign?.id || "", partnerId: partner?.id || "", dateRange: new Date().toISOString().slice(0, 7), recordShieldStarts: 1, source: "supabase", notes: event.summary || "RecordShield user created." }
    }));
  }
  if (event.source === "drive" && text.includes("data room")) {
    suggestions.push(automationSuggestion("automation-suggestion-dataroom", event, {
      suggestionType: "add_data_room_item",
      title: `Add data room file: ${activityTitle}`,
      explanation: "A Drive file path mentions Data Room and should be tracked as a proof artifact.",
      relatedEntityType: "data_room",
      relatedEntityId: "",
      confidence: "high",
      proposedChanges: { title: activityTitle, section: event.rawPayload?.section || "Traction", status: "draft", filePath: event.rawPayload?.filePath || "", owner: "Owner TBD", lastUpdated: new Date().toISOString().slice(0, 10), notes: event.summary || "Imported from Drive event." }
    }));
  }
  if (event.source === "website" && (event.rawPayload?.campaign_slug || text.includes("campaign_slug"))) {
    suggestions.push(automationSuggestion("automation-suggestion-website-funnel", event, {
      ...base,
      suggestionType: "update_funnel_snapshot",
      title: `Update campaign funnel: ${campaign?.campaignName || event.rawPayload?.campaign_slug || "website event"}`,
      explanation: "Website campaign events should update referral and funnel snapshots.",
      relatedEntityType: campaign ? "campaign" : "funnel",
      relatedEntityId: campaign?.id || "",
      confidence: campaign ? "high" : "medium",
      proposedChanges: { campaignId: campaign?.id || "", partnerId: partner?.id || "", dateRange: new Date().toISOString().slice(0, 7), landingPageVisits: Number(event.rawPayload?.visits || 1), actualReferrals: Number(event.rawPayload?.referrals || 0), source: "website", notes: event.summary || "Website campaign signal." }
    }));
  }
  suggestions.push(automationSuggestion("automation-suggestion-activity", event, {
    ...base,
    suggestionType: "add_activity_event",
    title: `Log activity: ${activityTitle}`,
    explanation: "Keep an activity trail for raw signals even when no structured update is applied.",
    proposedChanges: { eventType: `Automation: ${event.eventType}`, title: activityTitle, relatedObjectType: relatedEntityType, relatedObjectId: relatedEntityId }
  }));
  return suggestions;
}

