  // B1 heartbeat: the cron-driven tick the other engines run on. Auth: dedicated cron
  // token (POST tick only) or owner/admin via the normal role path. plan() always runs;
  // act() runs only for engines whose autopilot toggle is on (default OFF).
  if (url.pathname === "/api/heartbeat/tick" && request.method === "POST") {
    try {
      const payload = request.headers["content-length"] === "0" ? {} : await readJson(request).catch(() => ({}));
      const registry = buildHeartbeatRegistry({
        runSourcesDaily: async () => {
          const r = await runSourceAutomation();
          return { state: r.state, results: r.posts || [] };
        },
        runPublishing: async () => {
          const r = await runPublishingWorker();
          const summary = publishingRunSummaryFromResults(r.results);
          const stateWithSummary = { ...r.state, dailyRunPublisherRuns: [summary, ...serverList(r.state.dailyRunPublisherRuns)].slice(0, 20) };
          return { state: stateWithSummary, results: r.results || [] };
        },
        // B2 outreach send — live SendGrid client is wired, but stays dry_run until
        // OUTREACH_LIVE_SEND is flipped AND a SendGrid key is present. The outreach engine's
        // act() also only runs when its autopilot toggle is ON (default OFF) — gated twice over,
        // plus fail-closed classification routing inside the executor.
        runOutreachSend,
        // MVP reactivation send (consumer B2C) — uses the same compliant SendGrid payload shape as
        // B2 but has its own gate (REACTIVATION_LIVE_SEND) and no RCAP classification routing.
        // The reactivation engine's act() only runs when its autopilot toggle is ON (default OFF)
        // and only for RELEASED waves.
        runReactivationSend,
        // Phase B PR 1 (incident 2026-07-08): durable atomic claim of (campaign, contact, step)
        // BEFORE each live reactivation send. The store's unique (collection, item_id) key makes
        // the insert the cross-process idempotency test; the engine fails closed without it.
        claimReactivationSends: (claims) => store.claimCollectionItems("reactivationSendClaims", claims),
        // B2 activation run (2026-07-09): the same claim-before-send boundary for cold outreach.
        // Every live outreach send atomically claims (campaign, contact, step) in
        // outreachSendClaims first; the engine fails closed without this path.
        claimOutreachSends: (claims) => store.claimCollectionItems("outreachSendClaims", claims),
        // Phase 18I alert email — owner-only digest and critical breakthroughs. Recipient is
        // env-locked (ALERTS_EMAIL_TO); gated by the in-app email toggle (default OFF) plus
        // ALERTS_LIVE_SEND plus the alerts engine's autopilot toggle (default OFF).
        runAlertEmailSend,
        // Phase 18H meeting briefs — read-only Calendar fetch of the owner's own schedule.
        // Gmail snippets are deliberately NOT injected: email context is on-demand only.
        fetchCalendarEventsForBriefs,
        // I1 inbox intelligence — full READ-ONLY fetch of exactly the one authorized mailbox
        // (owner decision 2026-07-12). The fetcher itself enforces the identity wall; the
        // engine additionally refuses to read at all until the inbox autopilot toggle is ON
        // (the flip that writes the activation audit event). plan()-only, no act(), no send.
        fetchInboxThreads: fetchInboxThreadsForIntelligence,
        inboxReadEnabled: (state) => autopilotEnabled(state, INBOX_ENGINE_ID, process.env),
        // B5 prospect discovery — inert (zero rows) until the live Tier-1 dataset clients are
        // wired and PROSPECT_LIVE_DISCOVERY is flipped. The prospect engine's act() only runs
        // when its autopilot toggle is ON (default OFF), so this is gated twice over.
        runProspectDiscovery,
        // B4 engagement & growth — READ-ONLY live read (GET only). Reuses the existing honest
        // fetchers; passes their {available,configured,error} shapes through untouched. B4 has no
        // act() and never posts/sends, so this fetcher is the ONLY external contact, and it reads.
        fetchEngagementMetrics: async () => {
          const [revenue, signups] = await Promise.all([fetchStripeRevenueSnapshot(), fetchSignupsSnapshot()]);
          return { revenue, signups };
        },
        // B7 operating-loop registry — the os-health loop reads live connection flags here (same
        // values the manual /api/os-health/refresh passes), so the scheduled snapshot matches the
        // on-demand one. Read-only; the loops never act. Absent this, os-health falls back to
        // in-state runtime flags.
        fetchConnectionHealth: async () => {
          const health = await getSupabaseHealth();
          return {
            endpointInventorySource,
            supabaseDbConnected: Boolean(health?.db?.ok),
            supabaseStorageConnected: Boolean(health?.storage?.ok),
            openAIConfigured: Boolean(process.env.OPENAI_API_KEY),
            ownerTokenAuthConfigured: authRequiredForEnv(),
            localFallbackAvailable: true
          };
        }
      });
      // Serialized against all other state mutations: runHeartbeat reads state at tick start
      // and writes a diff-scoped patch at tick end, so a scoped write to one of the SAME
      // collections landing mid-tick (an operator arming/disarming a campaign, a webhook
      // event) would still be reverted by the tick's closing write. Serializing closes that
      // window; mutations queue until the tick finishes.
      const result = await serializeStateMutation(() => runHeartbeat({
        store,
        registry,
        env: process.env,
        force: payload && payload.force === true,
        actor: accessDecision.actor?.role || "cron"
      }));
      sendJson(response, result);
    } catch (error) {
      sendJson(response, { error: error.message || "Heartbeat tick failed." }, 500);
    }
    return;
  }

  if (url.pathname === "/api/heartbeat/status" && request.method === "GET") {
    const currentState = await store.readState();
    const autopilot = HEARTBEAT_ENGINE_IDS.map((engineId) => ({
      engineId,
      enabled: autopilotEnabled(currentState, engineId, process.env)
    }));
    sendJson(response, {
      lease: currentState.heartbeatLease || null,
      autopilot,
      recentRuns: serverList(currentState.heartbeatRuns).slice(0, 50)
    });
    return;
  }

  if (url.pathname === "/api/heartbeat/autopilot" && request.method === "POST") {
    try {
      const input = await readJson(request);
      const engineId = String(input.engineId || "");
      if (!HEARTBEAT_ENGINE_IDS.includes(engineId)) {
        sendJson(response, { error: "Unknown engineId." }, 400);
        return;
      }
      const enabled = input.enabled === true;
      // Serialized + SCOPED: an autopilot flip touches ONE singleton. The old full-state
      // writeState here was the same prod-hostile pattern as the alerts toggle (PR #27) and
      // could clobber concurrent scoped writes (e.g. the reactivation live-mode record).
      await serializeStateMutation(async () => {
        const currentState = await store.readState();
        const settings = { ...(currentState.autopilotSettings || {}) };
        settings[engineId] = {
          enabled,
          updatedAt: new Date().toISOString(),
          updatedBy: accessDecision.actor?.label || accessDecision.actor?.role || "operator"
        };
        let nextState = { ...currentState, autopilotSettings: settings };
        const patch = { autopilotSettings: settings };
        // I1: the first ON-flip of the inbox toggle IS the capability activation the owner
        // decision record mandates an audit event for. Written once, ever.
        if (engineId === INBOX_ENGINE_ID && enabled && !inboxConfigOf(currentState).activationAuditAt) {
          nextState = recordInboxActivationAudit(nextState, {
            actor: accessDecision.actor?.label || accessDecision.actor?.role || "owner"
          });
          patch.auditHistory = nextState.auditHistory;
          patch.companyEvents = nextState.companyEvents;
          patch.inboxConfig = nextState.inboxConfig;
        }
        await store.writeCollections(patch);
        sendJson(response, { engineId, enabled, autopilotSettings: settings, state: withPublicChannelSetup(nextState) });
      });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not update autopilot toggle." }, 400);
    }
    return;
  }

  // ---- I1 inbox intelligence: on-demand scan --------------------------------------------
  // Owner/admin only, and refused while the inbox toggle is OFF: the toggle is the
  // capability gate the 2026-07-12 decision record hangs the audit event on, so nothing —
  // including a manual scan — reads the mailbox before the flip. Read-only; writes only the
  // inboxSignals/inboxConfig scoped patch.
  if (url.pathname === "/api/inbox/scan" && request.method === "POST") {
    if (!["owner", "admin"].includes(String(accessDecision.actor?.role || ""))) {
      sendJson(response, { error: "Only the owner can scan the inbox." }, 403);
      return;
    }
    try {
      const result = await serializeStateMutation(async () => {
        const currentState = await store.readState();
        if (!autopilotEnabled(currentState, INBOX_ENGINE_ID, process.env)) {
          return { blocked: true };
        }
        const planned = await planInboxIntelligence(currentState, {
          fetchInboxThreads: fetchInboxThreadsForIntelligence,
          inboxReadEnabled: () => true,
          now: new Date().toISOString()
        });
        const patch = {};
        if (planned.state.inboxSignals !== currentState.inboxSignals) patch.inboxSignals = planned.state.inboxSignals;
        if (planned.state.inboxConfig !== currentState.inboxConfig) patch.inboxConfig = planned.state.inboxConfig;
        if (planned.state.automationSuggestions !== currentState.automationSuggestions) patch.automationSuggestions = planned.state.automationSuggestions;
        if (Object.keys(patch).length) await store.writeCollections(patch);
        return { observations: planned.observations, config: inboxConfigOf(planned.state) };
      });
      if (result.blocked) {
        sendJson(response, { error: "Inbox reading is off. Flip the Inbox intelligence toggle first (that flip records the activation audit event)." }, 400);
        return;
      }
      sendJson(response, { ok: true, observations: result.observations, lastScan: { at: result.config.lastScanAt, status: result.config.lastScanStatus, count: result.config.lastScanCount, truncated: result.config.lastScanTruncated, backfillCompletedAt: result.config.backfillCompletedAt } });
    } catch (error) {
      sendJson(response, { error: error.message || "Inbox scan failed." }, 500);
    }
    return;
  }

  // ---- I3 inbox reply drafts: prepared, edited, approved — NEVER sent ---------------------
  // Skeleton by default (Roger's voice is Roger's); AI assist is a separate explicit call.
  // UPL-sensitive threads get NO draft and flag Lawrence. There is no send route: the only
  // exit is the clipboard on the signal page.
  if (url.pathname === "/api/inbox/signals/draft" && request.method === "POST") {
    if (!["owner", "admin"].includes(String(accessDecision.actor?.role || ""))) {
      sendJson(response, { error: "Only the owner can prepare inbox drafts." }, 403);
      return;
    }
    try {
      const body = (await readJson(request)) || {};
      const result = await serializeStateMutation(async () => {
        const currentState = await store.readState();
        const signals = Array.isArray(currentState.inboxSignals) ? currentState.inboxSignals : [];
        const signal = signals.find((s) => s.id === String(body.signalId || ""));
        if (!signal) return { error: "Signal not found.", statusCode: 404 };
        const now = new Date().toISOString();
        const prepared = prepareInboxDraftReply(signal, { now });
        if (!prepared.ok) {
          // UPL refusal: record the Lawrence flag on the signal so the card shows it.
          if (prepared.flagLawrence && !signal.lawrenceFlaggedAt) {
            const nextSignals = signals.map((s) => s.id === signal.id ? { ...s, lawrenceFlaggedAt: now, updatedAt: now } : s);
            await store.writeCollections({ inboxSignals: nextSignals });
          }
          return { error: prepared.error, flagLawrence: Boolean(prepared.flagLawrence), statusCode: 400 };
        }
        const existing = (currentState.emailDrafts || []).find((d) => d.signalId === signal.id && d.status !== "Dismissed");
        if (existing) return { draft: existing, message: "A draft for this thread already exists. Edit it below." };
        const emailDrafts = [prepared.draft, ...(currentState.emailDrafts || [])].slice(0, 100);
        const nextSignals = signals.map((s) => s.id === signal.id ? { ...s, draftId: prepared.draft.id, updatedAt: now } : s);
        await store.writeCollections({ emailDrafts, inboxSignals: nextSignals });
        return { draft: prepared.draft, message: "Draft ready. Edit it, then copy it into your reply. Nothing was sent." };
      });
      if (result.error) { sendJson(response, { error: result.error, flagLawrence: result.flagLawrence }, result.statusCode || 400); return; }
      sendJson(response, { ok: true, draft: result.draft, message: result.message, liveGatesCount: 0 });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not prepare the draft." }, 500);
    }
    return;
  }

  if (url.pathname === "/api/inbox/drafts/update" && request.method === "POST") {
    if (!["owner", "admin"].includes(String(accessDecision.actor?.role || ""))) {
      sendJson(response, { error: "Only the owner can edit inbox drafts." }, 403);
      return;
    }
    try {
      const input = (await readJson(request)) || {};
      const allowedStatuses = ["Needs review", "Approved to send manually", "Sent manually", "Dismissed"];
      const result = await serializeStateMutation(async () => {
        const currentState = await store.readState();
        const drafts = Array.isArray(currentState.emailDrafts) ? currentState.emailDrafts : [];
        const draft = drafts.find((d) => d.id === String(input.id || ""));
        if (!draft) return { error: "Draft not found.", statusCode: 404 };
        const patch = { updatedAt: new Date().toISOString() };
        if (typeof input.body === "string") patch.body = input.body.slice(0, 4000);
        if (input.status !== undefined) {
          if (!allowedStatuses.includes(String(input.status))) return { error: "Unknown draft status.", statusCode: 400 };
          patch.status = String(input.status);
        }
        const emailDrafts = drafts.map((d) => d.id === draft.id ? { ...d, ...patch } : d);
        await store.writeCollections({ emailDrafts });
        return { draft: { ...draft, ...patch } };
      });
      if (result.error) { sendJson(response, { error: result.error }, result.statusCode || 400); return; }
      sendJson(response, { ok: true, draft: result.draft, message: "Draft updated. Nothing was sent.", liveGatesCount: 0 });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not update the draft." }, 500);
    }
    return;
  }

  // AI assist — EXPLICIT, per-draft, never automatic (Roger: outbound voice is his; assist
  // stays one click away). Context sent to the model is the skeleton + the signal's plain
  // sentence + already-REDACTED evidence lines — never raw email content.
  if (url.pathname === "/api/inbox/drafts/assist" && request.method === "POST") {
    if (!["owner", "admin"].includes(String(accessDecision.actor?.role || ""))) {
      sendJson(response, { error: "Only the owner can use draft assist." }, 403);
      return;
    }
    if (!process.env.OPENAI_API_KEY) {
      sendJson(response, { error: "OPENAI_API_KEY is not configured; the skeleton draft still works." }, 400);
      return;
    }
    try {
      const input = (await readJson(request)) || {};
      const currentState = await store.readState();
      const draft = (currentState.emailDrafts || []).find((d) => d.id === String(input.id || ""));
      if (!draft) { sendJson(response, { error: "Draft not found." }, 404); return; }
      const signal = (currentState.inboxSignals || []).find((s) => s.id === draft.signalId) || {};
      const env = openAIDraftEnvStatus();
      const prompt = "Rewrite this reply draft in a warm, direct, plain-spoken founder voice. Keep it under 120 words, keep every bracketed [slot] exactly as-is for the human to fill, never promise legal outcomes, never give legal advice.\n\nContext (redacted): " + String(signal.summary || "") + "\n" + (signal.evidence || []).join("\n") + "\n\nDraft:\n" + String(draft.body || "");
      const aiResponse = await fetch("https://api.openai.com/v1/responses", {
        method: "POST",
        headers: { authorization: `Bearer ${process.env.OPENAI_API_KEY}`, "content-type": "application/json" },
        body: JSON.stringify({ model: env.openaiDraftModel, input: prompt, max_output_tokens: 500 })
      });
      const data = await aiResponse.json().catch(() => null);
      if (!aiResponse.ok) { sendJson(response, { error: "Assist failed (status " + aiResponse.status + "). The skeleton draft is untouched." }, 502); return; }
      const text = String(data?.output_text || data?.output?.map?.((o) => o?.content?.map?.((c) => c?.text || "").join("") || "").join("") || "").trim();
      if (!text) { sendJson(response, { error: "Assist returned nothing usable. The skeleton draft is untouched." }, 502); return; }
      const result = await serializeStateMutation(async () => {
        const freshState = await store.readState();
        const emailDrafts = (freshState.emailDrafts || []).map((d) => d.id === draft.id ? { ...d, body: text.slice(0, 4000), aiAssisted: true, updatedAt: new Date().toISOString() } : d);
        await store.writeCollections({ emailDrafts });
        return emailDrafts.find((d) => d.id === draft.id);
      });
      sendJson(response, { ok: true, draft: result, message: "Assist applied. Review it - your voice, your call. Nothing was sent.", liveGatesCount: 0 });
    } catch (error) {
      sendJson(response, { error: error.message || "Assist failed." }, 500);
    }
    return;
  }

  // ---- B2 outreach OS (Phase 0) -------------------------------------------
  // One-click unsubscribe — PUBLIC, signed token, idempotent. Honored immediately
  // (CAN-SPAM requires within 10 days). Handles both the browser GET and the Gmail/Yahoo
  // List-Unsubscribe-Post one-click POST.
  if (url.pathname === "/api/outreach/unsubscribe" && (request.method === "GET" || request.method === "POST")) {
    const token = url.searchParams.get("token") || "";
    const verified = verifyUnsubscribeToken(token, process.env);
    if (!verified.ok) {
      response.writeHead(400, { "content-type": "text/html; charset=utf-8", "cache-control": "no-store" });
      response.end("<!doctype html><meta charset=utf-8><p>This unsubscribe link is invalid or expired.</p>");
      return;
    }
    try {
      // Serialized + SCOPED write of exactly the collections this handler changes. This endpoint
      // is PUBLIC (token-signed, but reachable by any mail client that expands the link), so the
      // previous full-state writeState here was the same internet-facing clobber surface PR #30
      // removed from the denial-audit and product-event paths: one unsubscribe carrying a stale
      // 90-collection snapshot could silently revert unrelated writes landing in its window.
      await serializeStateMutation(async () => {
        const currentState = await store.readState();
        const email = verified.payload.email || "";
        const contactId = verified.payload.contact_id || "";
        const suppressed = recordSuppression(currentState, { contactId, email, reason: "unsubscribed", source: "one_click" });
        await store.writeCollections({
          outreachSuppressions: serverList(suppressed.outreachSuppressions),
          outreachContacts: serverList(suppressed.outreachContacts),
          outreachUnsubscribes: [
            { id: `outreach-unsub-${Date.now().toString(16)}`, contact_id: contactId, email, campaign_id: verified.payload.campaign_id || "", created_at: new Date().toISOString() },
            ...serverList(currentState.outreachUnsubscribes)
          ]
        });
      });
    } catch (error) {
      // Suppression is best-effort idempotent; never surface an error that makes the user
      // think they're still subscribed.
    }
    response.writeHead(200, { "content-type": "text/html; charset=utf-8", "cache-control": "no-store" });
    response.end("<!doctype html><meta charset=utf-8><title>Unsubscribed</title><p>You've been unsubscribed and will receive no further messages.</p>");
    return;
  }

  // SendGrid event webhook — PUBLIC. A configured SENDGRID_WEBHOOK_PUBLIC_KEY and a valid,
  // fresh signature are required; missing verification rejects the batch before processing.
  // Records bounces/unsubscribes into the suppression ledger and reactivation events into the
  // campaign ledger, then writes back ONLY the touched
  // collections (scoped write) — a webhook batch can never rewrite, or be broken by, unrelated
  // state. Health telemetry persists to sendgridWebhookHealth and is surfaced (with warnings) on
  // /api/reactivation/status. MUST be the -prod host URL at SendGrid.
  if (url.pathname === "/api/outreach/webhooks/sendgrid" && request.method === "POST") {
    if (!webhookRouteEnabled(process.env)) {
      sendJson(response, { error:"Not found." }, 404);
      return;
    }
    // Best-effort health stamp — never lets a telemetry failure mask the primary outcome.
    const recordWebhookHealth = async (outcome) => {
      try {
        const s = await store.readState();
        await store.writeCollections({
          [SENDGRID_WEBHOOK_HEALTH_COLLECTION]: updateSendGridWebhookHealth(s[SENDGRID_WEBHOOK_HEALTH_COLLECTION], outcome)
        });
      } catch {}
    };
    try {
      const rate = await consumeRateLimit({
        store,
        scope: "sendgrid_webhook",
        subject: request.socket?.remoteAddress || "unknown",
        limit: 120,
        windowMs: 60_000,
        secret: process.env.COMMAND_CENTER_SESSION_SECRET
      });
      if (!rate.allowed) {
        response.setHeader("retry-after", String(rate.retryAfterSeconds));
        sendJson(response, { error: "Webhook rejected." }, 429);
        return;
      }
      const { payload, rawBody } = await readJsonWithRawBody(request);
      const signedTimestamp = request.headers[SENDGRID_TIMESTAMP_HEADER] || "";
      const verification = verifySendGridSignature({
        env: process.env,
        rawBody,
        signature: request.headers[SENDGRID_SIGNATURE_HEADER] || "",
        timestamp: signedTimestamp
      });
      if (verification.rejected) {
        await incrementSecurityMetric(store, "webhook_rejections").catch(() => {});
        await recordWebhookHealth({ rejected: true, reason: verification.reason });
        sendJson(response, { error: "Webhook rejected." }, 401);
        return;
      }
      if (!Array.isArray(payload)) {
        sendJson(response, { error: "Webhook rejected." }, 400);
        return;
      }
      const batchId = `sendgrid-batch-${sendgridBatchDigest(rawBody, signedTimestamp)}`;
      const batchClaim = await store.claimCollectionItems("webhookReplayClaims", [{ id: batchId, kind: "sendgrid_batch", status: "claimed", createdAt: new Date().toISOString(), expiresAt: new Date(Date.now() + 10 * 60 * 1000).toISOString() }]);
      if (!batchClaim.inserted?.length) {
        await incrementSecurityMetric(store, "webhook_replays").catch(() => {});
        sendJson(response, { ok: true, duplicate: true, processed: 0 });
        return;
      }
      const eventClaims = payload.map((event) => ({ id: `sendgrid-event-${sendgridEventDigest(event)}`, kind: "sendgrid_event", createdAt: new Date().toISOString(), expiresAt: new Date(Date.now() + 10 * 60 * 1000).toISOString() }));
      const claimedEvents = await store.claimCollectionItems("webhookReplayClaims", eventClaims);
      const wonIds = new Set((claimedEvents.inserted || []).map((claim) => claim.id));
      const events = payload.filter((event, index) => wonIds.has(eventClaims[index].id));
      const currentState = await store.readState();
      const scoped = {};
      for (const collection of SENDGRID_WEBHOOK_COLLECTIONS) scoped[collection] = serverList(currentState[collection]);
      const { state: reduced, counters } = reduceSendGridEvents(scoped, events);
      const writePatch = {};
      for (const collection of SENDGRID_WEBHOOK_COLLECTIONS) writePatch[collection] = reduced[collection];
      writePatch[SENDGRID_WEBHOOK_HEALTH_COLLECTION] = updateSendGridWebhookHealth(
        currentState[SENDGRID_WEBHOOK_HEALTH_COLLECTION],
        { ok: true, counters, verified: verification.verified }
      );
      await store.writeCollections(writePatch);
      await store.mutateCollectionItem("webhookReplayClaims", batchId, (claim) => ({ ...claim, status: "processed", processedAt: new Date().toISOString() }), { maxRetries: 1 });
      sendJson(response, { ok: true, processed: events.length, recorded: counters.recorded, verified: verification.verified });
    } catch (error) {
      await recordWebhookHealth({ error: "webhook_processing_failed" });
      sendJson(response, { error: "Webhook rejected." }, error instanceof RequestLimitError ? 413 : 400);
    }
    return;
  }

  // Approve a queued outreach message (does NOT send — act() sends only when autopilot is on).
  if (url.pathname === "/api/outreach/approve" && request.method === "POST") {
    try {
      const input = await readJson(request);
      const ids = new Set((Array.isArray(input.ids) ? input.ids : [input.id]).filter(Boolean).map(String));
      const approvedCount = await serializeStateMutation(async () => {
        const currentState = await store.readState();
        const queue = serverList(currentState.approvalQueue).map((q) =>
          (q.type === OUTREACH_QUEUE_TYPE && ids.has(q.id) && String(q.status).toLowerCase() === "queued_for_approval")
            ? { ...q, status: "approved", approved_at: new Date().toISOString(), approved_by: accessDecision.actor?.label || accessDecision.actor?.role || "operator" }
            : q
        );
        await store.writeCollections({ approvalQueue: queue });
        return queue.filter((q) => ids.has(q.id) && q.status === "approved").length;
      });
      sendJson(response, { ok: true, approved: approvedCount });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not approve outreach messages." }, 400);
    }
    return;
  }

  // Outreach status — queue counts, autopilot state, dry-run/live posture (read).
  if (url.pathname === "/api/outreach/status" && request.method === "GET") {
    const currentState = await store.readState();
    const queue = serverList(currentState.approvalQueue).filter((q) => q.type === OUTREACH_QUEUE_TYPE);
    const cfg = outreachConfigOf(currentState);
    const liveEnabled = outreachLiveSendEnabled(process.env);
    sendJson(response, {
      autopilotEnabled: autopilotEnabled(currentState, OUTREACH_ENGINE_ID, process.env),
      liveSendWired: true,
      liveSendFlag: liveEnabled,
      sendgridKeyPresent: Boolean(process.env.SENDGRID_API_KEY),
      postalAddressSet: Boolean(cfg.postalAddress),
      fromEmailSet: Boolean(cfg.fromEmail),
      caps: cfg.caps,
      queued: queue.filter((q) => String(q.status).toLowerCase() === "queued_for_approval").length,
      approved: queue.filter((q) => String(q.status).toLowerCase() === "approved").length,
      sent: serverList(currentState.outreachAttempts).filter((a) => a.status === "sent").length,
      dryRun: serverList(currentState.outreachAttempts).filter((a) => a.status === "dry_run").length,
      suppressions: serverList(currentState.outreachSuppressions).length,
      unsubscribes: serverList(currentState.outreachUnsubscribes).length,
      bounces: serverList(currentState.outreachBounces).length,
      // Claim-before-send safety ledger (mirrors reactivation sendClaims).
      sendClaims: serverList(currentState.outreachSendClaims).reduce((m, c) => {
        const s = String(c.status || "").toLowerCase();
        m.total += 1;
        if (m[s] !== undefined) m[s] += 1;
        return m;
      }, { total: 0, claimed: 0, sent: 0, dry_run: 0, failed: 0 })
    });
    return;
  }

  // Set outreach config (postal address, From identity, caps) — admin.
  if (url.pathname === "/api/outreach/config" && request.method === "POST") {
    try {
      const input = await readJson(request);
      const merged = await serializeStateMutation(async () => {
        const currentState = await store.readState();
        const next = {
          ...(currentState.outreachConfig || {}),
          ...(input.postalAddress !== undefined ? { postalAddress: String(input.postalAddress) } : {}),
          ...(input.fromEmail !== undefined ? { fromEmail: String(input.fromEmail) } : {}),
          ...(input.fromName !== undefined ? { fromName: String(input.fromName) } : {}),
          ...(input.replyTo !== undefined ? { replyTo: String(input.replyTo) } : {}),
          ...(input.sendingDomain !== undefined ? { sendingDomain: String(input.sendingDomain) } : {}),
          ...(input.caps && typeof input.caps === "object" ? { caps: { ...(currentState.outreachConfig?.caps || {}), ...input.caps } } : {})
        };
        await store.writeCollections({ outreachConfig: next });
        return next;
      });
      sendJson(response, { ok: true, outreachConfig: merged });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not update outreach config." }, 400);
    }
    return;
  }

  // B2 domain authentication — admin drives SendGrid domain auth for the dedicated outreach
  // subdomain from the server, the only place SENDGRID_API_KEY exists (never handled by hand).
  // Scoped to the v3/whitelabel/domains API via sendgrid-domain-auth.mjs; cannot send mail and
  // never exposes the key. Admin-gated by the /api/outreach/ POST rule in access-control.
  // create and a passing validate are audited to companyEvents; status is read-only.
  if (url.pathname === "/api/outreach/domain-auth" && request.method === "POST") {
    try {
      const input = await readJson(request);
      const result = await runDomainAuthAction({
        action: input.action,
        domain: input.domain || DEFAULT_OUTREACH_AUTH_DOMAIN,
        env: process.env
      });
      const audited = (result.action === "create" && result.created === true)
        || (result.action === "validate" && result.valid === true);
      if (audited) {
        await serializeStateMutation(async () => {
          const currentState = await store.readState();
          const nextState = emitCompanyEvent(currentState, {
            source: OUTREACH_ENGINE_ID,
            type: "outreach_domain_auth",
            risk: "watch",
            summary: result.action === "create"
              ? `SendGrid domain authentication created for ${result.domainAuth?.domain} by ${accessDecision.actor?.label || accessDecision.actor?.role || "operator"}; DNS records issued, not yet validated.`
              : `SendGrid domain authentication VALIDATED for ${result.domainAuth?.domain} by ${accessDecision.actor?.label || accessDecision.actor?.role || "operator"}.`
          });
          await store.writeCollections({ companyEvents: nextState.companyEvents });
        });
      }
      sendJson(response, { ok: true, ...result });
    } catch (error) {
      sendJson(response, { error: error.message || "Domain auth action failed." }, 400);
    }
    return;
  }

  // ---- Universal list intake — dead-simple "Upload a list" front door ----------------------
  // ONE entry point for every list type. Preview is PURE (detects type, inspects headers, warns
  // about sensitive columns, never writes). Confirm routes to the EXISTING importers (consumer
  // reactivation, Expungement.ai sync) or the Company Memory identity layer, records the audit
  // trail (Event + Agent Run + Approval), and creates Queue items for anything needing review.
  // Neither endpoint sends, calls a provider, releases a wave, enrolls a contact, or changes a
  // live-send/autopilot gate.
  if (url.pathname === "/api/intake/preview" && request.method === "POST") {
    // POST is gated as "write" by access-control (owner/auth-protected). Preview writes NO state.
    try {
      const payload = await readJson(request);
      const currentState = await store.readState();
      const preview = previewIntake(currentState, payload?.csv ?? payload?.csvText ?? "", {
        intakeType: payload?.intakeType || payload?.listType,
        afterAction: payload?.afterAction,
        sourceNote: payload?.sourceNote,
        fileName: payload?.fileName
      });
      sendJson(response, preview);
    } catch (error) {
      sendJson(response, { error: error.message || "Could not preview this list." }, 400);
    }
    return;
  }

  if (url.pathname === "/api/intake/confirm" && request.method === "POST") {
    // Explicit owner/admin guard for the state-writing step (mirrors /api/upload/consumer/confirm).
    const actorRole = String(accessDecision.actor?.role || "").toLowerCase();
    if (!["owner", "admin"].includes(actorRole)) {
      sendJson(response, { error: "Owner or admin access required.", requiredPermission: "owner/admin", actor: publicActor(accessDecision.actor) }, 403);
      return;
    }
    try {
      const payload = await readJson(request);
      const result = await serializeStateMutation(async () => {
        const currentState = await store.readState();
        const confirmed = confirmIntake(currentState, payload?.csv ?? payload?.csvText ?? "", {
          intakeType: payload?.intakeType || payload?.listType,
          afterAction: payload?.afterAction,
          sourceNote: payload?.sourceNote,
          fileName: payload?.fileName,
          actor: accessDecision.actor?.id || accessDecision.actor?.role || "owner",
          now: new Date().toISOString()
        });
        await writeChangedCollections(currentState, confirmed.state);
        return confirmed;
      });
      sendJson(response, {
        ok: true,
        intakeType: result.intakeType,
        typeLabel: result.typeLabel,
        afterAction: result.afterAction,
        actionLabel: result.actionLabel,
        sourceNote: result.sourceNote,
        fileName: result.fileName,
        headline: result.headline,
        lines: result.lines,
        counts: result.counts,
        verified: result.verified,
        approvalRequested: result.approvalRequested,
        warning: result.warning,
        state: withPublicChannelSetup(result.state)
      });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not import this list." }, 400);
    }
    return;
  }

  // ---- Campaign command — Milestone 2: campaigns controllable without a terminal -----------
  // View + previews are read-only. Propose writes ONLY a requested Approval + Queue item +
  // Event. Execute performs the release/resume ONLY with an approved Approval, re-checking
  // safety, and persists via SCOPED collection writes. Nothing here sends an email or changes
  // a live-send/autopilot gate.
  if (url.pathname === "/api/campaign/command" && request.method === "GET") {
    try {
      const currentState = await store.readState();
      sendJson(response, buildCampaignCommandView(currentState, { env: process.env }));
    } catch (error) {
      sendJson(response, { error: error.message || "Could not build the campaign view." }, 400);
    }
    return;
  }

  // ---- Campaign brain (Phase 18E) ------------------------------------------------------------
  // Read-only lanes + deliverability, and ONE gated write: releasing approved-for-later held
  // contacts into the next UNRELEASED wave. Never enrolls, never releases a wave, never sends.
  if (url.pathname === "/api/campaign/brain" && request.method === "GET") {
    try {
      const currentState = await store.readState();
      sendJson(response, {
        ok: true,
        outreach: buildOutreachLaneView(currentState, { env: process.env }),
        held: previewHeldRelease(currentState),
        deliverability: buildDeliverabilityWarnings(currentState, { env: process.env })
      });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not build the campaign brain view." }, 400);
    }
    return;
  }

  // ---- RCAP partner ops (Phase 18F) ----------------------------------------------------------
  // Display only: observed partner usage windows, onboarding progress derived from lifecycle
  // stages, and packet counts from inbound event metrics. There is no cap enforcement in this
  // system and this endpoint cannot create any — it has no write path.
  if (url.pathname === "/api/rcap/partner-ops" && request.method === "GET") {
    try {
      const currentState = await store.readState();
      sendJson(response, {
        ok: true,
        usage: buildPartnerUsageView(currentState),
        onboarding: buildOnboardingChecklist(currentState),
        packets: buildPacketCounts(currentState)
      });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not build the RCAP partner ops view." }, 400);
    }
    return;
  }

  // ---- Meeting briefs (Phase 18H) ------------------------------------------------------------
  // Calendar is read live (read-only) when preparing; Gmail snippets are pulled only when the
  // owner asks for email context on one brief. Never bodies, never in the background.
  if (url.pathname === "/api/meeting-briefs" && request.method === "GET") {
    const currentState = await store.readState();
    sendJson(response, { ok: true, ...buildMeetingBriefsView(currentState) });
    return;
  }

  if (url.pathname === "/api/meeting-briefs/prepare" && request.method === "POST") {
    const actorRole = String(accessDecision.actor?.role || "").toLowerCase();
    if (!["owner", "admin"].includes(actorRole)) {
      sendJson(response, { error: "Owner or admin access required.", requiredPermission: "owner/admin", actor: publicActor(accessDecision.actor) }, 403);
      return;
    }
    try {
      const events = await fetchCalendarEventsForBriefs();
      if (events === null) {
        sendJson(response, { ok: true, status: "not_connected", message: "Calendar is not connected yet. Connect Google read-only in Settings first." });
        return;
      }
      await serializeStateMutation(async () => {
        const currentState = await store.readState();
        const now = new Date();
        const fresh = events.map((event) => buildMeetingBrief(currentState, event, { now })).filter(Boolean);
        const rec = reconcileMeetingBriefs(currentState.meetingBriefs, fresh, { now });
        let nextState = { ...currentState, meetingBriefs: rec.briefs };
        if (rec.created > 0) {
          nextState = emitCompanyEvent(nextState, { source: MEETING_BRIEFS_ENGINE_ID, type: "meeting_briefs_prepared", risk: "info", summary: `${rec.created} new meeting brief(s) prepared from read-only Calendar. No email was read.` });
          await store.writeCollections({ meetingBriefs: rec.briefs, companyEvents: nextState.companyEvents });
        } else {
          await store.writeCollections({ meetingBriefs: rec.briefs });
        }
        sendJson(response, { ok: true, status: "prepared", created: rec.created, ...buildMeetingBriefsView(nextState) });
      });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not prepare meeting briefs." }, 400);
    }
    return;
  }

  if (url.pathname === "/api/meeting-briefs/email-context" && request.method === "POST") {
    const actorRole = String(accessDecision.actor?.role || "").toLowerCase();
    if (!["owner", "admin"].includes(actorRole)) {
      sendJson(response, { error: "Owner or admin access required.", requiredPermission: "owner/admin", actor: publicActor(accessDecision.actor) }, 403);
      return;
    }
    try {
      const body = await readJson(request);
      const briefId = String(body.briefId || "").trim();
      const currentState = await store.readState();
      const brief = (currentState.meetingBriefs || []).find((item) => item.id === briefId);
      if (!brief) {
        sendJson(response, { error: "Brief not found. Prepare briefs first." }, 400);
        return;
      }
      const attendees = (brief.attendees || []).filter((attendee) => !attendee.self).slice(0, 5);
      const snippetsByAttendee = {};
      let gmailConnected = true;
      for (const attendee of attendees) {
        const snippets = await fetchGmailSnippetsForAttendee(attendee.email);
        if (snippets === null) { gmailConnected = false; break; }
        snippetsByAttendee[attendee.email] = snippets;
      }
      if (!gmailConnected) {
        sendJson(response, { ok: true, status: "not_connected", message: "Gmail is not connected yet. Connect Google read-only in Settings first." });
        return;
      }
      await serializeStateMutation(async () => {
        const latest = await store.readState();
        const enriched = attachEmailContext((latest.meetingBriefs || []).find((item) => item.id === briefId) || brief, snippetsByAttendee, { now: new Date() });
        const nextBriefs = (latest.meetingBriefs || []).map((item) => (item.id === briefId ? enriched : item));
        let nextState = emitCompanyEvent({ ...latest, meetingBriefs: nextBriefs }, { source: MEETING_BRIEFS_ENGINE_ID, type: "meeting_brief_email_context", risk: "info", summary: `Email snippets pulled on demand for one meeting brief (${enriched.email_context.length} snippet(s), read-only, no bodies stored).` });
        await store.writeCollections({ meetingBriefs: nextBriefs, companyEvents: nextState.companyEvents });
        sendJson(response, { ok: true, status: "enriched", snippets: enriched.email_context.length, ...buildMeetingBriefsView(nextState) });
      });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not pull email context." }, 400);
    }
    return;
  }

  // ---- Alert system (Phase 18I) --------------------------------------------------------------
  // Internal alerts from four source groups; email goes ONLY to the env-locked owner address
  // behind stacked off-by-default gates. Config never accepts a recipient.
  if (url.pathname === "/api/alerts" && request.method === "GET") {
    const currentState = await store.readState();
    sendJson(response, { ok: true, ...buildAlertsView(currentState, { env: process.env }) });
    return;
  }

  if (url.pathname === "/api/alerts/refresh" && request.method === "POST") {
    const actorRole = String(accessDecision.actor?.role || "").toLowerCase();
    if (!["owner", "admin"].includes(actorRole)) {
      sendJson(response, { error: "Owner or admin access required.", requiredPermission: "owner/admin", actor: publicActor(accessDecision.actor) }, 403);
      return;
    }
    try {
      await serializeStateMutation(async () => {
        const currentState = await store.readState();
        // Refresh raises/resolves internal alert records only. It never emails: the digest and
        // critical breakthroughs run on the heartbeat under the autopilot + email gates.
        const stripeRevenue = await fetchStripeRevenueSnapshot().catch(() => null);
        const candidates = buildAlertCandidates(currentState, { env: process.env, now: new Date(), stripeRevenue });
        const rec = reconcileAlerts(currentState.alerts || [], candidates, { now: new Date() });
        await store.writeCollections({ alerts: rec.alerts });
        sendJson(response, { ok: true, created: rec.created, escalated: rec.escalated, resolved: rec.resolved, ...buildAlertsView({ ...currentState, alerts: rec.alerts }, { env: process.env }) });
      });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not refresh alerts." }, 400);
    }
    return;
  }

  if (url.pathname === "/api/alerts/status" && request.method === "POST") {
    const actorRole = String(accessDecision.actor?.role || "").toLowerCase();
    if (!["owner", "admin"].includes(actorRole)) {
      sendJson(response, { error: "Owner or admin access required.", requiredPermission: "owner/admin", actor: publicActor(accessDecision.actor) }, 403);
      return;
    }
    try {
      const body = await readJson(request);
      await serializeStateMutation(async () => {
        const currentState = await store.readState();
        const result = setAlertStatus(currentState, { id: String(body.id || ""), status: String(body.status || "") });
        if (!result.ok) {
          sendJson(response, { error: result.reason === "not_found" ? "Alert not found." : "Status must be read, dismissed, or active." }, 400);
          return;
        }
        await store.writeCollections({ alerts: result.state.alerts });
        sendJson(response, { ok: true, ...buildAlertsView(result.state, { env: process.env }) });
      });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not update the alert." }, 400);
    }
    return;
  }

  if (url.pathname === "/api/alerts/config" && request.method === "POST") {
    const actorRole = String(accessDecision.actor?.role || "").toLowerCase();
    if (!["owner", "admin"].includes(actorRole)) {
      sendJson(response, { error: "Owner or admin access required.", requiredPermission: "owner/admin", actor: publicActor(accessDecision.actor) }, 403);
      return;
    }
    try {
      const body = await readJson(request);
      await serializeStateMutation(async () => {
        const currentState = await store.readState();
        const prior = alertsConfigOf(currentState);
        // The recipient address is env-locked on purpose and is NOT accepted here.
        const nextConfig = {
          ...(currentState.settings?.alerts || {}),
          emailEnabled: body.emailEnabled === undefined ? prior.emailEnabled : body.emailEnabled === true,
          digestHourEt: body.digestHourEt === undefined ? prior.digestHourEt : Math.min(23, Math.max(0, Number(body.digestHourEt) || 0))
        };
        // SCOPED write only. updateSettings would rewrite the ENTIRE state to Supabase (every
        // collection serialized + orphan-reconciled in one request) — the historically fragile
        // full-state prod write path, and the reason this toggle appeared dead in production.
        const nextSettings = { ...(currentState.settings || {}), alerts: nextConfig };
        let nextState = { ...currentState, settings: nextSettings };
        if (nextConfig.emailEnabled !== prior.emailEnabled) {
          // Gate flips are audited like every other decision in the system.
          nextState = emitCompanyEvent(nextState, {
            source: ALERTS_ENGINE_ID,
            type: "alert_email_gate",
            risk: "watch",
            summary: `Alert email to owner turned ${nextConfig.emailEnabled ? "ON" : "OFF"} by ${accessDecision.actor?.label || actorRole}.`
          });
          await store.writeCollections({ settings: nextSettings, companyEvents: nextState.companyEvents });
        } else {
          await store.writeCollections({ settings: nextSettings });
        }
        sendJson(response, { ok: true, ...buildAlertsView(nextState, { env: process.env }) });
      });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not update alert settings." }, 400);
    }
    return;
  }

  if (url.pathname === "/api/alerts/digest-preview" && request.method === "POST") {
    const actorRole = String(accessDecision.actor?.role || "").toLowerCase();
    if (!["owner", "admin"].includes(actorRole)) {
      sendJson(response, { error: "Owner or admin access required.", requiredPermission: "owner/admin", actor: publicActor(accessDecision.actor) }, 403);
      return;
    }
    const currentState = await store.readState();
    const decision = resolveAlertEmailDecision(currentState, { env: process.env });
    const digest = buildDailyDigest(currentState, currentState.alerts || [], { env: process.env, recipient: decision.recipient || "", now: new Date() });
    sendJson(response, { ok: true, decision: decision.status, decisionReason: decision.reason || "", subject: digest.subject, text: digest.text, counts: digest.counts });
    return;
  }

  if (url.pathname === "/api/alerts/email-test" && request.method === "POST") {
    const actorRole = String(accessDecision.actor?.role || "").toLowerCase();
    if (!["owner", "admin"].includes(actorRole)) {
      sendJson(response, { error: "Owner or admin access required.", requiredPermission: "owner/admin", actor: publicActor(accessDecision.actor) }, 403);
      return;
    }
    try {
      const currentState = await store.readState();
      const decision = resolveAlertEmailDecision(currentState, { env: process.env });
      if (decision.status !== "live") {
        sendJson(response, { ok: true, status: decision.status, reason: decision.reason || "", note: "No email was sent. The gate chain is not fully armed." });
        return;
      }
      const result = await runAlertEmailSend({
        to: decision.recipient,
        from: String(process.env.ALERTS_EMAIL_FROM || "roger@example.com").trim(),
        subject: "Alert email test from the LegalEase Command Center",
        text: "This is a test of owner alert email. It goes only to you. Nothing was sent to contacts, customers, or partners."
      }, { env: process.env });
      await serializeStateMutation(async () => {
        const latest = await store.readState();
        const withEvent = emitCompanyEvent(latest, { source: ALERTS_ENGINE_ID, type: "alert_email_test", risk: "info", summary: `Alert email test: ${result.status}.` });
        await store.writeCollections({ companyEvents: withEvent.companyEvents });
      });
      sendJson(response, { ok: true, status: result.status, reason: result.reason || "" });
    } catch (error) {
      sendJson(response, { error: error.message || "Alert email test failed." }, 400);
    }
    return;
  }

  if (url.pathname === "/api/campaign/held-release/confirm" && request.method === "POST") {
    const actorRole = String(accessDecision.actor?.role || "").toLowerCase();
    if (!["owner", "admin"].includes(actorRole)) {
      sendJson(response, { error: "Owner or admin access required.", requiredPermission: "owner/admin", actor: publicActor(accessDecision.actor) }, 403);
      return;
    }
    try {
      const payload = await readJson(request);
      const actor = accessDecision.actor?.label || accessDecision.actor?.role || "owner";
      const result = await serializeStateMutation(async () => {
        const currentState = await store.readState();
        const confirmed = confirmHeldRelease(currentState, {
          contactIds: payload?.contactIds || payload?.contact_ids,
          actor,
          now: new Date().toISOString()
        });
        if (!confirmed.ok) return confirmed;
        let nextState = emitCompanyEvent(confirmed.state, {
          source: "campaign-command",
          type: "held_contacts_released",
          risk: "watch",
          summary: `${actor} released ${confirmed.released} held contact${confirmed.released === 1 ? "" : "s"} into wave ${confirmed.wave}. Nobody is enrolled and nothing was sent.`
        });
        nextState = recordAgentRun(nextState, {
          agent: "campaign-command",
          trigger: "operator",
          purpose: `Release ${confirmed.released} approved-for-later held contact${confirmed.released === 1 ? "" : "s"} into wave ${confirmed.wave}`,
          output_summary: "Hold cleared and wave assigned. Nobody enrolled, nothing sent.",
          risk: "caution",
          approval_required: false,
          recommended_next_step: `Preview the wave ${confirmed.wave} release when you are ready; enrolling still needs your approval.`
        });
        await store.writeCollections({
          reactivationContacts: nextState.reactivationContacts,
          companyEvents: nextState.companyEvents,
          agentRuns: nextState.agentRuns
        });
        return { ok: true, released: confirmed.released, wave: confirmed.wave, noSend: true, plain: confirmed.plain };
      });
      if (!result.ok) { sendJson(response, { error: result.error, rejected: result.rejected || [] }, 400); return; }
      sendJson(response, result);
    } catch (error) {
      sendJson(response, { error: error.message || "Could not release the selected contacts.", rejected: [] }, 400);
    }
    return;
  }

  if (url.pathname === "/api/campaign/wave-release/preview" && request.method === "POST") {
    try {
      const payload = await readJson(request);
      const currentState = await store.readState();
      sendJson(response, previewWaveRelease(currentState, payload?.wave, { env: process.env }));
    } catch (error) {
      sendJson(response, { error: error.message || "Could not preview this wave release." }, 400);
    }
    return;
  }

  if (url.pathname === "/api/campaign/wave-release/propose" && request.method === "POST") {
    const actorRole = String(accessDecision.actor?.role || "").toLowerCase();
    if (!["owner", "admin"].includes(actorRole)) {
      sendJson(response, { error: "Owner or admin access required.", requiredPermission: "owner/admin", actor: publicActor(accessDecision.actor) }, 403);
      return;
    }
    try {
      const payload = await readJson(request);
      const currentState = await store.readState();
      const result = proposeWaveRelease(currentState, payload?.wave, {
        scheduledFor: payload?.scheduledFor,
        actor: accessDecision.actor?.id || accessDecision.actor?.role || "owner",
        env: process.env,
        now: new Date().toISOString()
      });
      if (!result.ok) { sendJson(response, { error: result.error }, 400); return; }
      await store.writeCollections({
        queueItems: result.state.queueItems,
        approvals: result.state.approvals,
        companyEvents: result.state.companyEvents,
        agentRuns: result.state.agentRuns
      });
      sendJson(response, { ok: true, approvalId: result.approvalId, queueItemId: result.queueItemId, preview: result.preview });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not propose this wave release." }, 400);
    }
    return;
  }

  if (url.pathname === "/api/campaign/wave-release/execute" && request.method === "POST") {
    const actorRole = String(accessDecision.actor?.role || "").toLowerCase();
    if (!["owner", "admin"].includes(actorRole)) {
      sendJson(response, { error: "Owner or admin access required.", requiredPermission: "owner/admin", actor: publicActor(accessDecision.actor) }, 403);
      return;
    }
    try {
      const payload = await readJson(request);
      const currentState = await store.readState();
      const result = executeApprovedWaveRelease(currentState, {
        approvalId: payload?.approvalId,
        actor: accessDecision.actor?.id || accessDecision.actor?.role || "owner",
        env: process.env,
        now: new Date().toISOString()
      });
      if (!result.ok) {
        // Persist the blocked-attempt event, then refuse.
        await store.writeCollections({ companyEvents: result.state.companyEvents });
        sendJson(response, { error: result.error }, 400);
        return;
      }
      await store.writeCollections({
        reactivationContacts: result.state.reactivationContacts,
        reactivationCampaign: result.state.reactivationCampaign,
        queueItems: result.state.queueItems,
        approvals: result.state.approvals,
        companyEvents: result.state.companyEvents,
        agentRuns: result.state.agentRuns
      });
      sendJson(response, { ok: true, wave: result.wave, enrolled: result.enrolled, headline: result.headline, verified: result.verified, warning: result.warning });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not run this wave release." }, 400);
    }
    return;
  }

  if (url.pathname === "/api/campaign/pause" && request.method === "POST") {
    const actorRole = String(accessDecision.actor?.role || "").toLowerCase();
    if (!["owner", "admin"].includes(actorRole)) {
      sendJson(response, { error: "Owner or admin access required.", requiredPermission: "owner/admin", actor: publicActor(accessDecision.actor) }, 403);
      return;
    }
    try {
      const payload = await readJson(request);
      const currentState = await store.readState();
      const result = pauseCampaign(currentState, {
        reason: payload?.reason,
        actor: accessDecision.actor?.id || accessDecision.actor?.role || "owner",
        now: new Date().toISOString()
      });
      if (!result.ok) { sendJson(response, { error: result.error }, 400); return; }
      await store.writeCollections({
        reactivationCampaign: result.state.reactivationCampaign,
        approvals: result.state.approvals,
        companyEvents: result.state.companyEvents,
        agentRuns: result.state.agentRuns
      });
      sendJson(response, { ok: true, headline: result.headline, warning: result.warning });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not pause the campaign." }, 400);
    }
    return;
  }

  if (url.pathname === "/api/campaign/resume/propose" && request.method === "POST") {
    const actorRole = String(accessDecision.actor?.role || "").toLowerCase();
    if (!["owner", "admin"].includes(actorRole)) {
      sendJson(response, { error: "Owner or admin access required.", requiredPermission: "owner/admin", actor: publicActor(accessDecision.actor) }, 403);
      return;
    }
    try {
      const currentState = await store.readState();
      const result = proposeCampaignResume(currentState, {
        actor: accessDecision.actor?.id || accessDecision.actor?.role || "owner",
        env: process.env,
        now: new Date().toISOString()
      });
      if (!result.ok) { sendJson(response, { error: result.error }, 400); return; }
      await store.writeCollections({
        queueItems: result.state.queueItems,
        approvals: result.state.approvals,
        companyEvents: result.state.companyEvents,
        agentRuns: result.state.agentRuns
      });
      sendJson(response, { ok: true, approvalId: result.approvalId, queueItemId: result.queueItemId });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not propose the resume." }, 400);
    }
    return;
  }

  if (url.pathname === "/api/campaign/resume/execute" && request.method === "POST") {
    const actorRole = String(accessDecision.actor?.role || "").toLowerCase();
    if (!["owner", "admin"].includes(actorRole)) {
      sendJson(response, { error: "Owner or admin access required.", requiredPermission: "owner/admin", actor: publicActor(accessDecision.actor) }, 403);
      return;
    }
    try {
      const payload = await readJson(request);
      const currentState = await store.readState();
      const result = executeApprovedResume(currentState, {
        approvalId: payload?.approvalId,
        actor: accessDecision.actor?.id || accessDecision.actor?.role || "owner",
        env: process.env,
        now: new Date().toISOString()
      });
      if (!result.ok) {
        await store.writeCollections({ companyEvents: result.state.companyEvents });
        sendJson(response, { error: result.error }, 400);
        return;
      }
      await store.writeCollections({
        reactivationCampaign: result.state.reactivationCampaign,
        queueItems: result.state.queueItems,
        approvals: result.state.approvals,
        agentRuns: result.state.agentRuns,
        companyEvents: result.state.companyEvents
      });
      sendJson(response, { ok: true, headline: result.headline, warning: result.warning });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not resume the campaign." }, 400);
    }
    return;
  }

  // ---- Consumer / Expungement.ai list import ("Upload a list" front door) -----------------
  // IMPORT ONLY. Preview never writes state; confirm routes rows through the EXISTING reactivation
  // import path (importReactivationContacts + safe wave-number assignment). Neither endpoint sends,
  // calls a provider, releases a wave, enrolls a contact, or changes a live-send/autopilot gate.
  if (url.pathname === "/api/upload/consumer/preview" && request.method === "POST") {
    // POST is gated as "write" by access-control, so this is already owner/auth-protected. Preview
    // performs NO state write — it is a faithful dry-run only.
    try {
      const payload = await readJson(request);
      const currentState = await store.readState();
      const preview = previewConsumerImport(currentState, payload?.csv ?? payload?.csvText ?? "", {
        sourceNote: payload?.sourceNote,
        listType: payload?.listType || CONSUMER_LIST_TYPE
      });
      sendJson(response, preview);
    } catch (error) {
      sendJson(response, { error: error.message || "Could not preview the consumer list." }, 400);
    }
    return;
  }

  if (url.pathname === "/api/upload/consumer/confirm" && request.method === "POST") {
    // Explicit owner/admin guard for the state-writing step (mirrors /api/rcap-revenue/import).
    const actorRole = String(accessDecision.actor?.role || "").toLowerCase();
    if (!["owner", "admin"].includes(actorRole)) {
      sendJson(response, { error: "Owner or admin access required.", requiredPermission: "owner/admin", actor: publicActor(accessDecision.actor) }, 403);
      return;
    }
    try {
      const payload = await readJson(request);
      const result = await serializeStateMutation(async () => {
        const currentState = await store.readState();
        const confirmed = confirmConsumerImport(currentState, payload?.csv ?? payload?.csvText ?? "", {
          sourceNote: payload?.sourceNote,
          listType: payload?.listType || CONSUMER_LIST_TYPE,
          now: new Date().toISOString()
        });
        await writeChangedCollections(currentState, confirmed.state);
        return confirmed;
      });
      sendJson(response, {
        ok: true,
        listType: result.listType,
        sourceNote: result.sourceNote,
        summary: result.summary,
        held: result.held,
        waveSizes: result.waveSizes,
        totalContacts: result.totalContacts,
        warning: result.warning,
        heldMessage: result.heldMessage,
        state: withPublicChannelSetup(result.state)
      });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not import the consumer list." }, 400);
    }
    return;
  }

  // ---- Expungement.ai lifecycle sync (ingest-only; no live source pull) --------------------
  // Preview never writes; confirm upserts lifecycle contacts/events and stages campaign-eligible
  // contacts into reactivationContacts ALWAYS held. Neither endpoint sends, calls a provider,
  // releases a wave, enrolls a contact, or changes a live-send/autopilot gate.
  if (url.pathname === "/api/sync/expungement-ai/preview" && request.method === "POST") {
    // POST is gated as "write" by access-control (owner/auth-protected). Preview writes NO state.
    try {
      const payload = await readJson(request);
      const records = resolveSyncRecords({ records: payload?.records, csvText: payload?.csvText });
      const preview = previewExpungementSync(await store.readState(), records, {
        sourceNote: payload?.sourceNote
      });
      sendJson(response, preview);
    } catch (error) {
      sendJson(response, { error: error.message || "Could not preview the Expungement.ai sync." }, 400);
    }
    return;
  }

  if (url.pathname === "/api/sync/expungement-ai/confirm" && request.method === "POST") {
    // Explicit owner/admin guard for the state-writing step (mirrors the consumer import confirm).
    const actorRole = String(accessDecision.actor?.role || "").toLowerCase();
    if (!["owner", "admin"].includes(actorRole)) {
      sendJson(response, { error: "Owner or admin access required.", requiredPermission: "owner/admin", actor: publicActor(accessDecision.actor) }, 403);
      return;
    }
    try {
      const payload = await readJson(request);
      const records = resolveSyncRecords({ records: payload?.records, csvText: payload?.csvText });
      const result = await serializeStateMutation(async () => {
        const currentState = await store.readState();
        const confirmed = confirmExpungementSync(currentState, records, {
          sourceNote: payload?.sourceNote,
          now: new Date().toISOString()
        });
        await writeChangedCollections(currentState, confirmed.state);
        return confirmed;
      });
      sendJson(response, {
        ok: true,
        sourceNote: result.sourceNote,
        lifecycleUpserted: result.lifecycleUpserted,
        lifecycleEventsRecorded: result.lifecycleEventsRecorded,
        reactivationStaged: result.reactivationStaged,
        held: result.held,
        excludedUnsubscribed: result.excludedUnsubscribed,
        excludedDeleted: result.excludedDeleted,
        warning: result.warning,
        heldMessage: result.heldMessage,
        noSend: true,
        state: withPublicChannelSetup(result.state)
      });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not run the Expungement.ai sync." }, 400);
    }
    return;
  }

  // ---- Held contacts review (read-only operator surface) -----------------------------------
  // Safe counts + masked rows for held reactivation contacts and Expungement.ai lifecycle contacts.
  // GET => "read" permission (auth required). Writes NO state; returns only safe, masked fields.
  if (url.pathname === "/api/contacts/held-review" && request.method === "GET") {
    sendJson(response, buildHeldContactsReview(await store.readState()));
    return;
  }

  // Disposition — owner/admin records what should happen to a held contact LATER. Never releases,
  // enrolls, sends, or wave-assigns. campaign_hold stays true; "suppress" adds sticky suppression.
  if (url.pathname === "/api/contacts/held-review/disposition" && request.method === "POST") {
    const actorRole = String(accessDecision.actor?.role || "").toLowerCase();
    if (!["owner", "admin"].includes(actorRole)) {
      sendJson(response, { error: "Owner or admin access required.", requiredPermission: "owner/admin", actor: publicActor(accessDecision.actor) }, 403);
      return;
    }
    try {
      const payload = await readJson(request);
      // Hard guard: this slice can never clear the hold, assign a wave, or enroll a contact.
      if ((payload && payload.campaign_hold !== undefined && payload.campaign_hold !== true && String(payload.campaign_hold).toLowerCase() !== "true")
        || "wave" in (payload || {}) || "enrolled_at" in (payload || {})
        || (payload?.sequence_status && /enrolled/i.test(String(payload.sequence_status)))) {
        sendJson(response, { error: "This action cannot clear the hold, assign a wave, or enroll a contact." }, 400);
        return;
      }
      const result = await serializeStateMutation(async () => {
        const currentState = await store.readState();
        const applied = applyHeldDisposition(currentState, {
          contactId: payload?.contactId,
          contact_id: payload?.contact_id,
          contactIds: payload?.contactIds,
          contact_ids: payload?.contact_ids,
          review_status: payload?.review_status,
          review_note: payload?.review_note,
          reviewed_by: accessDecision.actor?.label || accessDecision.actor?.role || "owner",
          now: new Date().toISOString()
        });
        await writeChangedCollections(currentState, applied.state);
        return applied;
      });
      sendJson(response, {
        ok: true,
        review_status: result.review_status,
        updatedCount: result.updatedCount,
        rejected: result.rejected,
        updated: result.updated,
        noSend: true
      });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not record the disposition.", rejected: error.rejected || [] }, 400);
    }
    return;
  }

  // ---- MVP reactivation (consumer B2C) ----------
  // Status — contact/wave counts, send posture, per-wave metrics, threshold state (read-only).
  if (url.pathname === "/api/reactivation/status" && request.method === "GET") {
    const currentState = await store.readState();
    const config = reactivationCampaignOf(currentState);
    const contacts = serverList(currentState.reactivationContacts);
    const byWave = {};
    let enrolled = 0, suppressed = 0, staged = 0, held = 0;
    for (const c of contacts) {
      const w = c.wave || "unassigned";
      byWave[w] = (byWave[w] || 0) + 1;
      if (c.enrolled_at) enrolled++;
      if (c.suppressed_at_import) suppressed++;
      if (c.campaign_hold === true) held++;
      if (c.import_status === "staged") staged++;
    }
    const thr = evaluateThresholds(currentState, config);
    const rates = campaignRates(currentState);
    sendJson(response, {
      autopilotEnabled: autopilotEnabled(currentState, REACTIVATION_ENGINE_ID, process.env),
      liveSendWired: true,
      liveSendFlag: reactivationLiveSendEnabled(process.env),
      sendgridKeyPresent: Boolean(process.env.SENDGRID_API_KEY),
      campaignStatus: config.status,
      pausedReason: config.pausedReason || "",
      releasedWaves: config.releasedWaves,
      autoAdvanceWaves: config.autoAdvanceWaves,
      waves: config.waves,
      caps: config.caps,
      thresholds: config.thresholds,
      totalContacts: contacts.length,
      enrolled,
      staged,
      held,
      suppressedAtImport: suppressed,
      contactsByWave: byWave,
      rates,
      thresholdTripped: thr.tripped,
      thresholdReasons: thr.reasons,
      belowSample: thr.belowSample,
      metricsByWave: waveMetrics(currentState),
      // Webhook health posture (Phase 0 trust fix): whether delivery telemetry — and therefore
      // the auto-pause threshold monitor — can be trusted. Carries a plain-English warning when
      // sends exist but no events were ever recorded.
      webhook: sendgridWebhookHealthSummary(currentState[SENDGRID_WEBHOOK_HEALTH_COLLECTION], { env: process.env, sent: rates.sent }),
      writeHealth: typeof store.writeHealth === "function" ? store.writeHealth() : null,
      // Owner live-mode truth view: liveMode record, combined send authority, window, armed
      // state, lastHeartbeatAt/lastSendAttemptAt, and the plain-English statusCopy. Note the
      // top-level liveSendFlag above stays the raw env flag; live.reactivationLiveSendEnabled
      // is the FULL authority (live mode OR env flag, minus kill switch).
      live: buildReactivationLiveStatus(currentState, { env: process.env })
    });
    return;
  }

  // Owner Run/Stop switch for reactivation sending. Arms/disarms the reactivation engine ONLY
  // (live-mode record + reactivation autopilot together, scoped writes, audited). It never sends:
  // the hourly heartbeat remains the only send path and still enforces the ET window, caps,
  // suppression, wave release, and stop-thresholds. B2 outreach, social, and every other engine
  // are untouched.
  if (url.pathname === "/api/reactivation/live-mode" && request.method === "POST") {
    const actorRole = String(accessDecision.actor?.role || "").toLowerCase();
    if (!["owner", "admin"].includes(actorRole)) {
      sendJson(response, { error: "Owner or admin access required.", requiredPermission: "owner/admin", actor: publicActor(accessDecision.actor) }, 403);
      return;
    }
    try {
      const body = await readJson(request);
      if (typeof body.enabled !== "boolean") {
        sendJson(response, { error: "Body must include enabled: true or false." }, 400);
        return;
      }
      await serializeStateMutation(async () => {
        const result = await applyReactivationLiveMode(store, {
          enabled: body.enabled,
          actorLabel: accessDecision.actor?.label || actorRole,
          env: process.env
        });
        sendJson(response, result);
      });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not update reactivation live mode." }, 400);
    }
    return;
  }

  // ---- B5 prospect discovery (Tier-1 datasets only, NO send path) ----------
  // Status — staged-candidate counts by review_state, config, and discovery posture (read).
  if (url.pathname === "/api/prospects/status" && request.method === "GET") {
    const currentState = await store.readState();
    const candidates = serverList(currentState.prospectCandidates);
    const byState = {};
    for (const c of candidates) {
      const s = String(c.review_state || "").toLowerCase() || "unknown";
      byState[s] = (byState[s] || 0) + 1;
    }
    const cfg = prospectConfigOf(currentState);
    const liveEnabled = prospectLiveDiscoveryEnabled(process.env);
    sendJson(response, {
      autopilotEnabled: autopilotEnabled(currentState, PROSPECT_ENGINE_ID, process.env),
      liveDiscoveryWired: true,                  // dataset loaders are wired (IRS BMF + LSC; NLADA not built)
      liveDiscoveryFlag: liveEnabled,            // the actual on/off gate (PROSPECT_LIVE_DISCOVERY)
      nteeFilter: RCAP_NTEE_FILTER,              // the full selectable NTEE catalog (default flag per code)
      nteeActive: [...activeNteeSet(cfg)],       // the prefixes actually filtering this run (default subset unless overridden)
      scope: cfg.scope,
      classifications: cfg.classifications,
      enabledSources: cfg.enabledSources,
      sources: PROSPECT_SOURCES,
      total: candidates.length,
      byReviewState: byState,
      pending: byState[PROSPECT_REVIEW.PENDING] || 0,
      approved: byState[PROSPECT_REVIEW.APPROVED] || 0,
      promoted: byState[PROSPECT_REVIEW.PROMOTED] || 0,
      duplicates: candidates.filter((c) => c.is_duplicate).length,
      recentRuns: serverList(currentState.prospectDiscoveryRuns).slice(0, 30)
    });
    return;
  }

  // Set prospect discovery config (national scope, classifications, source toggles) — admin.
  if (url.pathname === "/api/prospects/config" && request.method === "POST") {
    try {
      const input = await readJson(request);
      const merged = await serializeStateMutation(async () => {
        const currentState = await store.readState();
        const sourceIds = new Set(PROSPECT_SOURCES.map((s) => s.id));
        const next = {
          ...(currentState.prospectConfig || {}),
          ...(input.scope !== undefined ? { scope: String(input.scope) } : {}),
          ...(Array.isArray(input.states) ? { states: input.states.map(String) } : {}),
          ...(Array.isArray(input.classifications)
            ? { classifications: input.classifications.map(normalizeClassification).filter(Boolean) } : {}),
          ...(Array.isArray(input.enabledSources)
            ? { enabledSources: input.enabledSources.map(String).filter((id) => sourceIds.has(id)) } : {}),
          ...(Array.isArray(input.nteePrefixes)
            ? { nteePrefixes: (() => {
                const known = new Set(RCAP_NTEE_FILTER.map((e) => e.prefix));
                return input.nteePrefixes.map((p) => String(p).toUpperCase().replace(/[^A-Z0-9]/g, "").slice(0, 3)).filter((p) => known.has(p));
              })() } : {}),
          ...(input.maxStagedPerRun !== undefined ? { maxStagedPerRun: Math.max(1, Number(input.maxStagedPerRun) || 0) } : {})
        };
        await store.writeCollections({ prospectConfig: next });
        return next;
      });
      sendJson(response, { ok: true, prospectConfig: prospectConfigOf({ prospectConfig: merged }) });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not update prospect config." }, 400);
    }
    return;
  }

  // ---- B3 codebase-health monitor (detect-and-report only; NO act path) -----
  // Status — latest read-only structural audit report (findings, severity counts, deltas).
  // Read-only surface; the engine itself never modifies source files and has no act() method.
  if (url.pathname === "/api/codebase-health/status" && request.method === "GET") {
    const currentState = await store.readState();
    const snapshots = serverList(currentState.codebaseHealthSnapshots);
    const latest = snapshots[0] || null;
    sendJson(response, {
      autopilotEnabled: autopilotEnabled(currentState, CODEBASE_HEALTH_ENGINE_ID, process.env),
      hasActPath: false,                 // structural: B3 cannot modify, delete, refactor, or merge
      latest,
      status: latest?.status || "never_run",
      counts: latest?.counts || { would_break_prod: 0, accumulating_risk: 0, cosmetic: 0, total: 0 },
      deltas: latest?.deltas || null,
      history: snapshots.slice(0, 30).map((s) => ({ id: s.id, generated_at: s.generated_at, status: s.status, counts: s.counts }))
    });
    return;
  }

  // ---- B4 engagement & growth monitor (READ-ONLY observe-and-report) --------
  // Status — latest growth report (live metrics, trends/deltas, honest blocked-source ladder).
  // Read-only surface; the engine never posts/sends and has no act() method.
  if (url.pathname === "/api/engagement-growth/status" && request.method === "GET") {
    const currentState = await store.readState();
    const snapshots = serverList(currentState.engagementGrowthSnapshots);
    const latest = snapshots[0] || null;
    sendJson(response, {
      autopilotEnabled: autopilotEnabled(currentState, ENGAGEMENT_GROWTH_ENGINE_ID, process.env),
      hasActPath: false,                 // structural: B4 never posts, sends, or writes outward
      latest,
      status: latest?.status || "never_run",
      liveSourcesConnected: latest?.live_sources_connected ?? 0,
      blockedSources: latest?.blocked_sources || [],
      whatsWorking: latest?.deltas?.whats_working || [],
      history: snapshots.slice(0, 30).map((s) => ({ id: s.id, generated_at: s.generated_at, status: s.status, live_sources_connected: s.live_sources_connected }))
    });
    return;
  }

  // ---- B7 operating-loop registry (READ-ONLY monitors on the heartbeat) ------
  // Status — latest pulse per loop (cash-runway, capacity, aging, partner-health, outreach-health,
  // os-health). Read-only surface; every loop is a pure monitor with no act() path.
  if (url.pathname === "/api/operating-pulse/status" && request.method === "GET") {
    const currentState = await store.readState();
    const snaps = serverList(currentState.operatingPulseSnapshots);
    const latestByLoop = {};
    for (const s of snaps) if (!latestByLoop[s.loop]) latestByLoop[s.loop] = s; // snaps newest-first
    const loops = LOOP_REGISTRY.map((d) => {
      const s = latestByLoop[d.key] || null;
      return {
        loop: d.key,
        label: d.label,
        cadence: d.cadence,
        engineId: d.engineId,
        autopilotEnabled: autopilotEnabled(currentState, d.engineId, process.env),
        hasActPath: false,                 // structural: B7 loops are pure monitors
        status: s?.status || "never_run",
        data_connected: s?.data_connected ?? null,
        headline: s?.headline || "",
        metrics: s?.metrics || null,
        delta: s?.delta ?? null,
        generated_at: s?.generated_at || null
      };
    });
    sendJson(response, { loops, generatedAny: loops.some((l) => l.generated_at) });
    return;
  }

  // Approve staged candidates — THE ONLY place review_state becomes "approved". Promotion into
  // the B2 collections happens later in the engine's act() (under autopilot). An optional
  // classification override is validated against the shared B2 vocab.
  if (url.pathname === "/api/prospects/approve" && request.method === "POST") {
    try {
      const input = await readJson(request);
      const ids = new Set((Array.isArray(input.ids) ? input.ids : [input.id]).filter(Boolean).map(String));
      const overrideClass = input.classification !== undefined ? normalizeClassification(input.classification) : "";
      const approvedCount = await serializeStateMutation(async () => {
        const currentState = await store.readState();
        let approved = 0;
        const candidates = serverList(currentState.prospectCandidates).map((c) => {
          if (!ids.has(c.id) || String(c.review_state || "").toLowerCase() !== PROSPECT_REVIEW.PENDING) return c;
          approved += 1;
          return {
            ...c,
            ...(overrideClass ? { classification: overrideClass } : {}),
            review_state: PROSPECT_REVIEW.APPROVED,
            approved_at: new Date().toISOString(),
            approved_by: accessDecision.actor?.label || accessDecision.actor?.role || "operator"
          };
        });
        await store.writeCollections({ prospectCandidates: candidates });
        return approved;
      });
      sendJson(response, { ok: true, approved: approvedCount });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not approve prospects." }, 400);
    }
    return;
  }

  // Reject staged candidates (human only) — moves pending_review -> rejected.
  if (url.pathname === "/api/prospects/reject" && request.method === "POST") {
    try {
      const input = await readJson(request);
      const ids = new Set((Array.isArray(input.ids) ? input.ids : [input.id]).filter(Boolean).map(String));
      const rejectedCount = await serializeStateMutation(async () => {
        const currentState = await store.readState();
        let rejected = 0;
        const candidates = serverList(currentState.prospectCandidates).map((c) => {
          if (!ids.has(c.id) || String(c.review_state || "").toLowerCase() !== PROSPECT_REVIEW.PENDING) return c;
          rejected += 1;
          return {
            ...c,
            review_state: PROSPECT_REVIEW.REJECTED,
            rejected_at: new Date().toISOString(),
            rejected_by: accessDecision.actor?.label || accessDecision.actor?.role || "operator"
          };
        });
        await store.writeCollections({ prospectCandidates: candidates });
        return rejected;
      });
      sendJson(response, { ok: true, rejected: rejectedCount });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not reject prospects." }, 400);
    }
    return;
  }

  const autonomyAction = url.pathname.match(/^\/api\/autonomy\/actions\/([^/]+)\/(approve|ignore|block)$/);
  if (autonomyAction && request.method === "POST") {
    try {
      const patch = request.headers["content-length"] === "0" ? {} : await readJson(request);
      const result = await updateAutonomyAction(decodeURIComponent(autonomyAction[1]), autonomyAction[2], patch || {});
      sendJson(response, { ...result, state: withPublicChannelSetup(result.state) });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not update autonomy action." }, 400);
    }
    return;
  }

  if (url.pathname === "/api/priority/rebuild" && request.method === "POST") {
    try {
      const result = await rebuildPriorityState();
      sendJson(response, { ...result, state: withPublicChannelSetup(result.state) });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not rebuild priorities." }, 400);
    }
    return;
  }

  if (url.pathname === "/api/tasks/rebuild" && request.method === "POST") {
    try {
      const result = await rebuildTasksState();
      sendJson(response, { ...result, state: withPublicChannelSetup(result.state) });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not rebuild tasks." }, 400);
    }
    return;
  }

  const taskAction = url.pathname.match(/^\/api\/tasks\/([^/]+)\/(in_progress|waiting|blocked|done|reopen|archive|add_note|update_priority|update_due_date|snooze|assign|dismiss|block|convert-report-note|convert-content-idea)$/);
  if (taskAction && request.method === "POST") {
    try {
      const payload = request.headers["content-length"] === "0" ? {} : await readJson(request);
      const result = await updateTaskRecord(decodeURIComponent(taskAction[1]), taskAction[2], payload || {});
      sendJson(response, { ...result, state: withPublicChannelSetup(result.state) });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not update task." }, 400);
    }
    return;
  }

  // ---- Support desk (Phase 18D) --------------------------------------------------------------
  // Triage + internal drafts only. There is NO send path: a reply leaves the app only when
  // the operator copies it out. UPL-sensitive messages never get a machine draft.
  if (url.pathname === "/api/support/intake" && request.method === "POST") {
    try {
      const payload = (await readJson(request)) || {};
      const result = await serializeStateMutation(async () => {
        const currentState = await store.readState();
        const issue = normalizeSupportIssue({
          title: payload.title,
          summary: payload.text || payload.summary,
          contact_email: payload.email,
          source: "manual"
        });
        const supportIssues = upsertSupportIssues(currentState.supportIssues, [issue]);
        const withEvent = emitCompanyEvent({ ...currentState, supportIssues }, {
          source: "support-inbox",
          type: "support_issue_logged",
          risk: issue.upl_sensitive ? "needs_roger" : "info",
          summary: `Support request logged: "${issue.title}".${issue.upl_sensitive ? " It may ask for legal advice; read it personally." : ""}`,
          sourceRef: { collection: "supportIssues", itemId: issue.id }
        });
        await store.writeCollections({ supportIssues: withEvent.supportIssues, companyEvents: withEvent.companyEvents });
        return { state: { ...currentState, supportIssues: withEvent.supportIssues, companyEvents: withEvent.companyEvents }, issue };
      });
      sendJson(response, { ...result, state: withPublicChannelSetup(result.state), message: result.issue.upl_sensitive ? "Logged. This one may ask for legal advice, so it is flagged for you personally." : "Support request logged." });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not log the support request." }, 400);
    }
    return;
  }

  const supportAction = url.pathname.match(/^\/api\/support\/([^/]+)\/(draft|transition)$/);
  if (supportAction && request.method === "POST") {
    try {
      const id = decodeURIComponent(supportAction[1]);
      const action = supportAction[2];
      const payload = (await readJson(request)) || {};
      const actor = accessDecision.actor?.label || accessDecision.actor?.role || "owner";
      const result = await serializeStateMutation(async () => {
        const currentState = await store.readState();
        const issues = Array.isArray(currentState.supportIssues) ? currentState.supportIssues : [];
        if (action === "draft") {
          const issue = issues.find((i) => i.id === id);
          if (!issue) return { error: "Support issue not found." };
          const prepared = prepareSupportDraftReply(issue);
          if (!prepared.ok) return { error: prepared.error };
          const supportIssues = issues.map((i) => (i.id === id ? prepared.issue : i));
          let nextState = emitCompanyEvent({ ...currentState, supportIssues }, {
            source: "support-inbox",
            type: "support_draft_prepared",
            risk: "info",
            summary: `Draft reply prepared for "${prepared.issue.title}". Nothing was sent.`,
            sourceRef: { collection: "supportIssues", itemId: id }
          });
          nextState = recordAgentRun(nextState, {
            agent: "support-inbox",
            trigger: "operator",
            purpose: `Prepare a draft reply for "${prepared.issue.title}"`,
            output_summary: "Internal draft prepared for review. Nothing was sent.",
            risk: "safe",
            approval_required: true,
            recommended_next_step: "Review the draft on the Support page, edit it, and copy it into your reply."
          });
          await store.writeCollections({ supportIssues: nextState.supportIssues, companyEvents: nextState.companyEvents, agentRuns: nextState.agentRuns });
          return { state: { ...currentState, supportIssues: nextState.supportIssues, companyEvents: nextState.companyEvents, agentRuns: nextState.agentRuns }, message: "Draft ready. Review and edit it before you use it. Nothing was sent." };
        }
        const moved = transitionSupportIssue(issues, { id, status: String(payload.status || ""), actor, note: String(payload.note || "") });
        if (!moved.ok) return { error: moved.error };
        const nextState = emitCompanyEvent({ ...currentState, supportIssues: moved.issues }, {
          source: "support-inbox",
          type: "support_status_changed",
          risk: "info",
          summary: `${actor} marked "${moved.issue.title}" as ${moved.issue.status}.`,
          sourceRef: { collection: "supportIssues", itemId: id }
        });
        await store.writeCollections({ supportIssues: nextState.supportIssues, companyEvents: nextState.companyEvents });
        return { state: { ...currentState, supportIssues: nextState.supportIssues, companyEvents: nextState.companyEvents }, message: `Marked as ${moved.issue.status}.` };
      });
      if (result.error) { sendJson(response, { error: result.error }, 400); return; }
      sendJson(response, { ...result, state: withPublicChannelSetup(result.state) });
    } catch (error) {
      sendJson(response, { error: error.message || "Could not update the support issue." }, 400);
    }
    return;
  }

